#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum TuiMode {
    Ask,
    Act,
    Serve,
    Logs,
    Automations,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HomeDashboardAction {
    Setup,
    Doctor,
    Serve,
    Chat,
    ComfyUi,
    Services,
    Engine,
    Permissions,
    Help,
    Quit,
}

fn tui_mode_for_command(head: &str, has_args: bool) -> TuiMode {
    match head {
        "automations" | "reviews" | "proposals" | "approve" | "reject" | "edit" => {
            TuiMode::Automations
        }
        "logs" => TuiMode::Logs,
        "serve" => TuiMode::Serve,
        "model" if has_args => TuiMode::Serve,
        "config" | "daemon" | "engine" | "install" | "permissions" | "runtimes" | "setup"
        | "uninstall" | "update" => TuiMode::Act,
        _ => TuiMode::Ask,
    }
}

fn is_doctor_command_input(command: &str) -> bool {
    let Some(rest) = command.strip_prefix("doctor") else {
        return false;
    };
    rest.is_empty() || rest.chars().next().is_some_and(char::is_whitespace)
}

fn tui_mode_for_cli_args(args: &[String]) -> TuiMode {
    args.first()
        .map(|head| tui_mode_for_command(head, args.len() > 1))
        .unwrap_or(TuiMode::Ask)
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct TranscriptLine {
    kind: TranscriptLineKind,
    text: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum TranscriptLineKind {
    #[allow(dead_code)]
    UserInput,
    BlockHeader {
        title: String,
    },
    BlockBody {
        title: String,
    },
    Stream {
        stream: CommandOutputStream,
    },
    Assistant,
    Blank,
}

impl TranscriptLine {
    #[allow(dead_code)]
    fn user_input(input: &str) -> Self {
        Self {
            kind: TranscriptLineKind::UserInput,
            text: format!("> {input}"),
        }
    }

    fn block_header(title: &str) -> Self {
        Self {
            kind: TranscriptLineKind::BlockHeader {
                title: title.to_owned(),
            },
            text: format!("[{title}]"),
        }
    }

    fn block_body(title: &str, line: &str) -> Self {
        Self {
            kind: TranscriptLineKind::BlockBody {
                title: title.to_owned(),
            },
            text: line.to_owned(),
        }
    }

    fn stream(stream: CommandOutputStream, line: &str) -> Self {
        Self {
            kind: TranscriptLineKind::Stream { stream },
            text: format!("[{}] {line}", stream.label()),
        }
    }

    fn assistant(line: &str) -> Self {
        Self {
            kind: TranscriptLineKind::Assistant,
            text: line.to_owned(),
        }
    }

    fn blank() -> Self {
        Self {
            kind: TranscriptLineKind::Blank,
            text: String::new(),
        }
    }
}

impl std::ops::Deref for TranscriptLine {
    type Target = str;

    fn deref(&self) -> &Self::Target {
        &self.text
    }
}

impl Borrow<str> for TranscriptLine {
    fn borrow(&self) -> &str {
        &self.text
    }
}

impl PartialEq<&str> for TranscriptLine {
    fn eq(&self, other: &&str) -> bool {
        self.text == *other
    }
}

impl PartialEq<str> for TranscriptLine {
    fn eq(&self, other: &str) -> bool {
        self.text == other
    }
}

