#[derive(Debug, Clone, PartialEq, Eq)]
struct CompletionMenu {
    title: String,
    items: Vec<String>,
    replacements: Vec<Option<String>>,
    selected: usize,
}

impl CompletionMenu {
    fn selectable_indices(&self) -> Vec<usize> {
        self.replacements
            .iter()
            .enumerate()
            .filter_map(|(index, replacement)| replacement.as_ref().map(|_| index))
            .collect()
    }

    fn selected_replacement(&self) -> Option<&str> {
        self.replacements
            .get(self.selected)
            .and_then(Option::as_deref)
    }
}

fn completion_visible_range(menu: &CompletionMenu) -> (usize, usize) {
    let visible_len = menu.items.len().min(MAX_COMPLETION_MENU_ITEMS);
    if visible_len == 0 {
        return (0, 0);
    }
    let selected = menu.selected.min(menu.items.len().saturating_sub(1));
    let max_start = menu.items.len().saturating_sub(visible_len);
    let start = selected.saturating_sub(visible_len / 2).min(max_start);
    let end = start.saturating_add(visible_len).min(menu.items.len());
    (start, end)
}

