struct ServeCommandPlan {
    model: Option<String>,
    engine: Option<String>,
    device: Option<String>,
    runtime_id: Option<String>,
    env_id: Option<String>,
    host: Option<String>,
    port: Option<u16>,
    foreground: bool,
    managed: bool,
    allow_public_bind: bool,
}

impl ServeCommandPlan {
    fn selected_engine<'a>(&'a self, config: &'a RocmCliConfig) -> &'a str {
        self.engine
            .as_deref()
            .or(config.default_engine.as_deref())
            .unwrap_or(default_engine_for_platform())
    }

    fn engine_manages_own_runtime(&self, config: &RocmCliConfig) -> bool {
        self.selected_engine(config)
            .eq_ignore_ascii_case("lemonade")
    }

    fn cli_args(&self) -> Vec<String> {
        let mut args = vec!["serve".to_owned()];
        if let Some(model) = self.model.as_ref() {
            args.push(model.clone());
        }
        push_optional_cli_arg(&mut args, "--engine", self.engine.as_deref());
        push_optional_cli_arg(&mut args, "--device", self.device.as_deref());
        push_optional_cli_arg(&mut args, "--runtime-id", self.runtime_id.as_deref());
        push_optional_cli_arg(&mut args, "--env-id", self.env_id.as_deref());
        push_optional_cli_arg(&mut args, "--host", self.host.as_deref());
        if let Some(port) = self.port {
            args.push("--port".to_owned());
            args.push(port.to_string());
        }
        if self.foreground {
            args.push("--foreground".to_owned());
        }
        if self.managed {
            args.push("--managed".to_owned());
        }
        if self.allow_public_bind {
            args.push("--allow-public-bind".to_owned());
        }
        args
    }
}

