    fn toggle_runtime_import_replace(&mut self) {
        if let Some(state) = self.runtime_manager.as_mut()
            && let RuntimeManagerScreen::ImportManifest { replace, .. } = &mut state.screen
        {
            *replace = !*replace;
            self.status = if *replace {
                "Matching saved ROCm installs will be replaced.".to_owned()
            } else {
                "Matching saved ROCm installs will be left alone.".to_owned()
            };
        }
    }

    fn toggle_runtime_adopt_replace(&mut self) {
        if let Some(state) = self.runtime_manager.as_mut()
            && let RuntimeManagerScreen::AdoptExisting { replace, .. } = &mut state.screen
        {
            *replace = !*replace;
            self.status = if *replace {
                "Matching saved ROCm installs will be replaced.".to_owned()
            } else {
                "Matching saved ROCm installs will be left alone.".to_owned()
            };
        }
    }

    fn toggle_runtime_adopt_channel(&mut self) {
        if let Some(state) = self.runtime_manager.as_mut()
            && let RuntimeManagerScreen::AdoptExisting { channel, .. } = &mut state.screen
        {
            *channel = channel.toggle();
            self.status = format!("Channel set to {}.", channel.as_str());
        }
    }

    fn request_runtime_import_from_form(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(state) = self.runtime_manager.as_mut() else {
            return;
        };
        let RuntimeManagerScreen::ImportManifest {
            manifest_path,
            replace,
            ..
        } = &mut state.screen
        else {
            return;
        };
        let manifest = match validate_runtime_manifest_path(manifest_path) {
            Ok(path) => path,
            Err(error) => {
                state.message = Some(error.to_string());
                self.status = "Choose a saved ROCm install file first.".to_owned();
                return;
            }
        };
        let mut args = vec![
            "runtimes".to_owned(),
            "import".to_owned(),
            manifest.display().to_string(),
        ];
        if *replace {
            args.push("--replace".to_owned());
        }
        self.request_screen_cli_approval("Import existing ROCm install", "Runtimes", args, None);
    }

    fn request_runtime_adopt_from_form(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(state) = self.runtime_manager.as_mut() else {
            return;
        };
        let RuntimeManagerScreen::AdoptExisting {
            python_path,
            channel,
            replace,
            ..
        } = &mut state.screen
        else {
            return;
        };
        let python = match validate_runtime_python_path(python_path) {
            Ok(path) => path,
            Err(error) => {
                state.message = Some(error.to_string());
                self.status = "Choose a Python folder first.".to_owned();
                return;
            }
        };
        let mut args = vec![
            "runtimes".to_owned(),
            "adopt".to_owned(),
            "--python".to_owned(),
            python.display().to_string(),
            "--channel".to_owned(),
            channel.as_str().to_owned(),
        ];
        if *replace {
            args.push("--replace".to_owned());
        }
        self.request_screen_cli_approval(
            "Add existing Python ROCm install",
            "Runtimes",
            args,
            None,
        );
    }

    fn perform_runtime_manager_selected_action(&mut self) {
        let Some(state) = self.runtime_manager.as_ref() else {
            return;
        };
        match &state.screen {
            RuntimeManagerScreen::List => {
                if self.selected_runtime_manager_item().is_some() {
                    self.request_runtime_manager_activation();
                    return;
                }
                match self.selected_runtime_manager_action() {
                    Some(RuntimeManagerAction::Install) => self.request_runtime_manager_install(),
                    Some(RuntimeManagerAction::RemoveSelected) => {
                        self.request_runtime_manager_uninstall()
                    }
                    Some(RuntimeManagerAction::AdvancedOptions) => {
                        self.open_runtime_advanced_options()
                    }
                    None => self.request_runtime_manager_install(),
                }
            }
            RuntimeManagerScreen::Advanced { selected } => {
                match runtime_advanced_choices().get(*selected).copied() {
                    Some(RuntimeAdvancedChoice::AdoptExisting) => self.open_runtime_adopt_form(),
                    Some(RuntimeAdvancedChoice::ImportManifest) => self.open_runtime_import_form(),
                    Some(RuntimeAdvancedChoice::Back) | None => self.close_runtime_subscreen(),
                }
            }
            RuntimeManagerScreen::ImportManifest { selected, .. } => {
                match runtime_import_choices().get(*selected).copied() {
                    Some(RuntimeImportChoice::ManifestPath) => {
                        self.start_runtime_import_path_edit()
                    }
                    Some(RuntimeImportChoice::Replace) => self.toggle_runtime_import_replace(),
                    Some(RuntimeImportChoice::Import) => self.request_runtime_import_from_form(),
                    Some(RuntimeImportChoice::Back) | None => self.close_runtime_subscreen(),
                }
            }
            RuntimeManagerScreen::AdoptExisting { selected, .. } => {
                match runtime_adopt_choices().get(*selected).copied() {
                    Some(RuntimeAdoptChoice::PythonPath) => self.start_runtime_adopt_python_edit(),
                    Some(RuntimeAdoptChoice::Channel) => self.toggle_runtime_adopt_channel(),
                    Some(RuntimeAdoptChoice::Replace) => self.toggle_runtime_adopt_replace(),
                    Some(RuntimeAdoptChoice::Adopt) => self.request_runtime_adopt_from_form(),
                    Some(RuntimeAdoptChoice::Back) | None => self.close_runtime_subscreen(),
                }
            }
        }
    }

    fn request_runtime_manager_activation(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(item) = self.selected_runtime_manager_item() else {
            self.request_runtime_manager_install();
            return;
        };
        if item.active {
            self.status = "That ROCm install is already active.".to_owned();
            return;
        }
        if item.status != "ready" {
            self.status = "That ROCm install needs repair before it can be used.".to_owned();
            return;
        }
        self.request_screen_cli_approval(
            "Use this ROCm install",
            "Runtimes",
            vec![
                "runtimes".to_owned(),
                "activate".to_owned(),
                item.runtime_key.clone(),
            ],
            Some(format!("/runtimes activate {}", item.runtime_key)),
        );
    }

    fn request_runtime_manager_uninstall(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(item) = self.selected_runtime_manager_target_item() else {
            self.status = "No ROCm install is selected.".to_owned();
            return;
        };
        let title = if item.read_only || item.imported_from.is_some() {
            "Remove ROCm install from ROCm CLI"
        } else {
            "Uninstall this ROCm install"
        };
        self.request_screen_cli_approval(
            title,
            "Runtimes",
            vec![
                "runtimes".to_owned(),
                "uninstall".to_owned(),
                item.runtime_key.clone(),
            ],
            Some(format!("/runtimes uninstall {}", item.runtime_key)),
        );
    }

    fn request_runtime_manager_install(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        self.open_install_manager();
        if let Some(state) = self.install_manager.as_mut() {
            state.return_to_runtime_manager_on_back = true;
        }
        self.open_install_sdk_form(None);
        self.status = "Choose where to install ROCm, then press Enter on Install ROCm.".to_owned();
    }

    fn open_install_manager(&mut self) {
        self.doctor_manager = None;
        self.runtime_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.logs_view = None;
        self.install_manager = Some(InstallManagerState {
            selected: 0,
            detail_scroll: 0,
            message: None,
            screen: InstallManagerScreen::Main,
            return_to_runtime_manager_on_back: false,
        });
        self.mode = TuiMode::Act;
        self.status = "Install opened. Use arrow keys, then Enter.".to_owned();
    }

    fn close_install_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.install_manager = None;
        self.return_to_home_after_surface_close("Install closed.");
    }

    fn move_install_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.install_manager.as_mut() else {
            return;
        };
        match &mut state.screen {
            InstallManagerScreen::Main => {
                state.selected =
                    cycle_index(state.selected, install_menu_choices().len(), direction);
            }
            InstallManagerScreen::Sdk { selected, .. } => {
                *selected = cycle_index(*selected, install_sdk_choices().len(), direction);
            }
        }
        state.detail_scroll = 0;
        self.status = "Install option selected. Press Enter to continue.".to_owned();
    }

    fn selected_install_menu_choice(&self) -> InstallMenuChoice {
        let selected = self
            .install_manager
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        install_menu_choices()
            .get(selected)
            .copied()
            .unwrap_or(InstallMenuChoice::Runtime)
    }

    fn open_install_sdk_form(&mut self, message: Option<String>) {
        let folder = setup_install_root(&self.paths, &self.config)
            .display()
            .to_string();
        self.open_install_sdk_form_with(
            InstallSdkChannel::Release,
            InstallSdkFormat::Wheel,
            folder,
            message,
        );
    }

    fn open_install_sdk_form_with(
        &mut self,
        channel: InstallSdkChannel,
        format: InstallSdkFormat,
        folder: String,
        message: Option<String>,
    ) {
        if let Some(state) = self.install_manager.as_mut() {
            state.screen = InstallManagerScreen::Sdk {
                selected: install_sdk_default_selection(),
                channel,
                format,
                folder,
                editing_folder: false,
            };
            state.detail_scroll = 0;
            state.message = message;
        }
        self.clear_input();
        self.status = "ROCm install options opened. Use arrows, then Enter.".to_owned();
    }

    fn open_install_sdk_form_from_args(&mut self, args: &[&str]) {
        match parse_install_sdk_form_args(args) {
            Ok(options) => self.open_install_sdk_form_with(
                options.channel,
                options.format,
                options
                    .folder
                    .unwrap_or_else(|| setup_install_root(&self.paths, &self.config))
                    .display()
                    .to_string(),
                None,
            ),
            Err(error) => {
                self.open_install_sdk_form(Some(plain_install_sdk_args_error(&error.to_string())));
            }
        }
    }

    fn install_manager_editing_text(&self) -> bool {
        self.install_manager.as_ref().is_some_and(|state| {
            matches!(
                state.screen,
                InstallManagerScreen::Sdk {
                    editing_folder: true,
                    ..
                }
            )
        })
    }

    fn selected_install_sdk_choice(&self) -> InstallSdkChoice {
        let selected = self
            .install_manager
            .as_ref()
            .and_then(|state| match &state.screen {
                InstallManagerScreen::Sdk { selected, .. } => Some(*selected),
                InstallManagerScreen::Main => None,
            })
            .unwrap_or(0);
        install_sdk_choices()
            .get(selected)
            .copied()
            .unwrap_or(InstallSdkChoice::Install)
    }

    fn cycle_install_sdk_folder_preset(&mut self, direction: CompletionDirection) {
        let Some(current) = self.install_manager.as_ref().and_then(|state| {
            if let InstallManagerScreen::Sdk { folder, .. } = &state.screen {
                Some(PathBuf::from(folder))
            } else {
                None
            }
        }) else {
            return;
        };
        let presets = install_folder_presets(&self.paths, &self.config, &current);
        if presets.len() <= 1 {
            self.status = "Press Enter to choose another install folder.".to_owned();
            return;
        }
        let current_key = onboarding_folder_preset_key(&current);
        let current_index = presets
            .iter()
            .position(|path| onboarding_folder_preset_key(path) == current_key)
            .unwrap_or(0);
        let next_index = cycle_index(current_index, presets.len(), direction);
        if let Some(state) = self.install_manager.as_mut()
            && let InstallManagerScreen::Sdk {
                selected,
                folder,
                editing_folder,
                ..
            } = &mut state.screen
        {
            *selected = install_sdk_choice_index(InstallSdkChoice::Folder);
            *folder = presets[next_index].display().to_string();
            *editing_folder = false;
            state.message = None;
            state.detail_scroll = 0;
        }
        self.clear_input();
        self.status =
            "Install folder changed. Press Enter to browse, or Left/Right for another.".to_owned();
    }

    fn open_install_sdk_form_folder_browser(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        self.open_folder_browser(
            "Choose ROCm Folder",
            "Pick where ROCm/TheRock should be installed.",
            FolderBrowserContext::InstallSdkForm,
        );
    }

    fn start_install_sdk_folder_edit(&mut self) {
        let folder = self
            .install_manager
            .as_ref()
            .and_then(|state| match &state.screen {
                InstallManagerScreen::Sdk { folder, .. } => Some(folder.clone()),
                InstallManagerScreen::Main => None,
            })
            .unwrap_or_else(|| {
                setup_install_root(&self.paths, &self.config)
                    .display()
                    .to_string()
            });
        if let Some(state) = self.install_manager.as_mut()
            && let InstallManagerScreen::Sdk { editing_folder, .. } = &mut state.screen
        {
            *editing_folder = true;
            state.message = None;
        }
        self.set_input(folder);
        self.status = "Type or paste a folder for ROCm, then press Enter.".to_owned();
    }

    fn commit_install_sdk_folder_edit(&mut self) {
        let value = self.input.trim();
        let path = match validate_onboarding_install_folder(value) {
            Ok(path) => path,
            Err(error) => {
                if let Some(state) = self.install_manager.as_mut() {
                    state.message = Some(error.to_string());
                }
                self.status = "Choose a folder you own.".to_owned();
                return;
            }
        };
        if let Some(state) = self.install_manager.as_mut()
            && let InstallManagerScreen::Sdk {
                folder,
                editing_folder,
                ..
            } = &mut state.screen
        {
            *folder = path.display().to_string();
            *editing_folder = false;
            state.message = None;
        }
        self.clear_input();
        self.status = "ROCm folder saved. Press Enter on Install ROCm.".to_owned();
    }

    fn cancel_install_sdk_folder_edit(&mut self) {
        if let Some(state) = self.install_manager.as_mut()
            && let InstallManagerScreen::Sdk { editing_folder, .. } = &mut state.screen
        {
            *editing_folder = false;
        }
        self.clear_input();
        self.status = "ROCm folder unchanged.".to_owned();
    }

    fn close_install_sdk_form(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        if self
            .install_manager
            .as_ref()
            .is_some_and(|state| state.return_to_runtime_manager_on_back)
        {
            self.install_manager = None;
            self.open_runtime_manager();
            self.status = "Back to ROCm installs.".to_owned();
            return;
        }
        if let Some(state) = self.install_manager.as_mut() {
            state.screen = InstallManagerScreen::Main;
            state.selected = 0;
            state.detail_scroll = 0;
            state.message = None;
        }
        self.clear_input();
        self.status = "Back to install options.".to_owned();
    }

    fn request_install_sdk_from_form(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(state) = self.install_manager.as_ref() else {
            return;
        };
        let InstallManagerScreen::Sdk {
            channel,
            format,
            folder,
            ..
        } = &state.screen
        else {
            return;
        };
        let folder = match validate_onboarding_install_folder(folder) {
            Ok(folder) => folder,
            Err(error) => {
                if let Some(state) = self.install_manager.as_mut() {
                    state.message = Some(error.to_string());
                }
                self.status = "Choose a folder you own before installing.".to_owned();
                return;
            }
        };
        let args = vec![
            "install".to_owned(),
            "sdk".to_owned(),
            "--channel".to_owned(),
            channel.as_str().to_owned(),
            "--format".to_owned(),
            format.as_str().to_owned(),
            "--prefix".to_owned(),
            folder.display().to_string(),
        ];
        let display = format!(
            "/install sdk --channel {} --format {} --prefix {}",
            channel.as_str(),
            format.as_str(),
            quote_tui_arg(&folder.display().to_string())
        );
        self.request_screen_cli_approval("Install ROCm", "Install", args, Some(display));
    }

    fn perform_install_manager_selected_action(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(state) = self.install_manager.as_ref() else {
            return;
        };
        match &state.screen {
            InstallManagerScreen::Main => match self.selected_install_menu_choice() {
                InstallMenuChoice::Runtime => self.open_install_sdk_form(None),
                InstallMenuChoice::DriverPreview => {
                    self.start_cli_command_with_display(
                        "Install Preview",
                        vec![
                            "install".to_owned(),
                            "driver".to_owned(),
                            "--dry-run".to_owned(),
                        ],
                        "/install driver --preview".to_owned(),
                    );
                }
                InstallMenuChoice::Back => self.close_install_manager(),
            },
            InstallManagerScreen::Sdk { selected, .. } => {
                match install_sdk_choices().get(*selected).copied() {
                    Some(InstallSdkChoice::Folder) => self.open_install_sdk_form_folder_browser(),
                    Some(InstallSdkChoice::Install) => self.request_install_sdk_from_form(),
                    Some(InstallSdkChoice::Back) | None => self.close_install_sdk_form(),
                }
            }
        }
    }

    fn open_engine_manager(&mut self) {
        self.refresh_config();
        self.doctor_manager = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.logs_view = None;
        self.engine_manager = Some(EngineManagerState {
            items: engine_manager_items(&self.paths, &self.config),
            selected: 0,
            last_item_selected: 0,
            detail_scroll: 0,
            message: None,
        });
        self.mode = TuiMode::Act;
        self.status = "Engines opened. Use arrow keys, then Enter.".to_owned();
    }

    fn close_engine_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.engine_manager = None;
        self.return_to_home_after_surface_close("Engines closed.");
    }

    fn refresh_engine_manager(&mut self) {
        let selected_name = self
            .engine_manager
            .as_ref()
            .and_then(|state| {
                state
                    .items
                    .get(state.selected)
                    .or_else(|| state.items.get(state.last_item_selected))
            })
            .map(|item| item.name.clone());
        self.refresh_config();
        let items = engine_manager_items(&self.paths, &self.config);
        let selected = selected_name
            .and_then(|name| items.iter().position(|item| item.name == name))
            .unwrap_or(0)
            .min(items.len().saturating_sub(1));
        self.engine_manager = Some(EngineManagerState {
            items,
            selected,
            last_item_selected: selected,
            detail_scroll: 0,
            message: None,
        });
    }

    fn move_engine_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.engine_manager.as_mut() else {
            return;
        };
        let rows = engine_manager_rows(state);
        let count = rows.len();
        if count == 0 {
            self.status = "No engines are available.".to_owned();
            return;
        }
        let selected = cycle_index(state.selected, count, direction);
        match rows
            .get(selected)
            .copied()
            .unwrap_or(EngineManagerRow::Item(0))
        {
            EngineManagerRow::Item(index) => {
                state.last_item_selected = index;
                state.selected = index;
            }
            EngineManagerRow::Action(_) => {
                state.selected = selected;
            }
        }
        state.detail_scroll = 0;
        self.status = "Engine option selected. Press Enter to continue.".to_owned();
    }

    fn selected_engine_manager_item(&self) -> Option<EngineManagerItem> {
        let state = self.engine_manager.as_ref()?;
        match engine_manager_selected_row(state)? {
            EngineManagerRow::Item(index) => state.items.get(index).cloned(),
            EngineManagerRow::Action(_) => None,
        }
    }

    fn selected_engine_manager_target_item(&self) -> Option<EngineManagerItem> {
        let state = self.engine_manager.as_ref()?;
        state
            .items
            .get(state.last_item_selected)
            .or_else(|| state.items.first())
            .cloned()
    }

    fn selected_engine_manager_action(&self) -> Option<EngineManagerAction> {
        let state = self.engine_manager.as_ref()?;
        match engine_manager_selected_row(state)? {
            EngineManagerRow::Action(action) => Some(action),
            EngineManagerRow::Item(_) => None,
        }
    }

    fn select_engine_manager_item(&mut self, engine: &str) -> bool {
        let Some(state) = self.engine_manager.as_mut() else {
            return false;
        };
        let Some(index) = state
            .items
            .iter()
            .position(|item| item.name.eq_ignore_ascii_case(engine))
        else {
            state.message = Some(format!(
                "I could not find engine `{engine}`.\n\nUse the arrow keys to choose one from this list."
            ));
            state.detail_scroll = 0;
            self.status = "Choose an engine from the list.".to_owned();
            return false;
        };
        state.selected = index;
        state.last_item_selected = index;
        state.message = None;
        state.detail_scroll = 0;
        self.status = "Engine selected. Press Enter to continue.".to_owned();
        true
    }

    fn perform_engine_manager_selected_action(&mut self) {
        if self.selected_engine_manager_item().is_some() {
            self.perform_selected_engine_item_action();
            return;
        }
        match self.selected_engine_manager_action() {
            Some(EngineManagerAction::UseSelected) => self.request_selected_engine_default(),
            Some(EngineManagerAction::InstallSelected) => {
                self.request_selected_engine_install(false)
            }
            Some(EngineManagerAction::ReinstallSelected) => {
                self.request_selected_engine_install(true)
            }
            Some(EngineManagerAction::InstallRocm) => self.open_install_manager(),
            Some(EngineManagerAction::Back) => self.close_engine_manager(),
            None => self.perform_selected_engine_item_action(),
        }
    }

    fn perform_selected_engine_item_action(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(item) = self.selected_engine_manager_item() else {
            self.status = "No engine is selected.".to_owned();
            return;
        };
        if item.installed_env_id.is_some() {
            self.request_engine_default(&item.name);
        } else if !item.runtime_ready {
            self.open_install_manager();
        } else {
            self.request_engine_install(&item.name, false);
        }
    }

    fn request_selected_engine_default(&mut self) {
        let Some(item) = self.selected_engine_manager_target_item() else {
            self.status = "No engine is selected.".to_owned();
            return;
        };
        if item.installed_env_id.is_none() {
            self.status = "Install this engine before making it the default.".to_owned();
            return;
        }
        self.request_engine_default(&item.name);
    }

    fn request_engine_default(&mut self, engine: &str) {
        self.request_screen_cli_approval(
            "Use this engine",
            "Engine",
            vec![
                "config".to_owned(),
                "set-default-engine".to_owned(),
                engine.to_owned(),
            ],
            Some(format!("/config set-default-engine {engine}")),
        );
    }

    fn request_selected_engine_install(&mut self, reinstall: bool) {
        let Some(item) = self.selected_engine_manager_target_item() else {
            self.status = "No engine is selected.".to_owned();
            return;
        };
        if !item.runtime_ready {
            self.open_install_manager();
            return;
        }
        self.request_engine_install(&item.name, reinstall);
    }

    fn request_engine_install(&mut self, engine: &str, reinstall: bool) {
        if self.running_job_blocks_action() {
            return;
        }
        let mut args = vec![
            "engines".to_owned(),
            "install".to_owned(),
            engine.to_owned(),
        ];
        let mut display = format!("/engine install {engine}");
        if reinstall {
            args.push("--reinstall".to_owned());
            display.push_str(" --reinstall");
        }
        self.request_screen_cli_approval("Install engine", "Engine", args, Some(display));
    }

    fn open_model_picker(&mut self) {
        self.refresh_config();
        self.doctor_manager = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.logs_view = None;
        match load_model_recipe_registry() {
            Ok(registry) => {
                let recipes = tui_gpu_model_recipes(registry.recipes);
                self.model_picker = Some(ModelPickerState {
                    items: recipes,
                    selected: 0,
                    detail_scroll: 0,
                    message: None,
                });
                self.status = "Models opened. Use arrow keys, then Enter.".to_owned();
            }
            Err(error) => {
                self.model_picker = Some(ModelPickerState {
                    items: Vec::new(),
                    selected: 0,
                    detail_scroll: 0,
                    message: Some(format!("Model recipes could not load.\n\n{error}")),
                });
                self.status = "Model recipes could not load.".to_owned();
            }
        }
        self.mode = TuiMode::Serve;
    }

    fn focus_model_picker_recipe(&mut self, model_ref: &str) {
        let query = model_ref.trim();
        if query.is_empty() {
            return;
        }
        let Some(state) = self.model_picker.as_mut() else {
            return;
        };
        match state
            .items
            .iter()
            .position(|recipe| recipe.matches_ref(query))
        {
            Some(index) => {
                state.selected = index;
                state.detail_scroll = 0;
                state.message = None;
                self.status = "Model selected. Press Enter to start setup.".to_owned();
            }
            None => {
                state.message = Some(format!(
                    "I could not find `{query}` in the built-in model list.\n\nUse the arrow keys to choose a model, then press Enter."
                ));
                self.status = "Choose a model from the list.".to_owned();
            }
        }
    }

    fn close_model_picker(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.model_picker = None;
        self.status = "Models closed.".to_owned();
    }

    fn move_model_picker_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.model_picker.as_mut() else {
            return;
        };
        if state.items.is_empty() {
            self.status = "No model recipes found.".to_owned();
            return;
        }
        state.message = None;
        state.selected = match direction {
            CompletionDirection::Next => (state.selected + 1) % state.items.len(),
            CompletionDirection::Previous => {
                if state.selected == 0 {
                    state.items.len().saturating_sub(1)
                } else {
                    state.selected - 1
                }
            }
        };
        state.detail_scroll = 0;
        self.status = "Model selected. Press Enter to start setup.".to_owned();
    }

    fn selected_model_recipe(&self) -> Option<ModelRecipeRecord> {
        self.model_picker
            .as_ref()
            .and_then(|state| state.items.get(state.selected))
            .cloned()
    }

    fn plan_selected_model_recipe(&mut self) {
        let Some(recipe) = self.selected_model_recipe() else {
            if let Some(state) = self.model_picker.as_mut() {
                state.message = Some("No model recipes found.".to_owned());
            }
            self.status = "No model recipe is selected.".to_owned();
            return;
        };
        let plan = ServeCommandPlan {
            model: Some(recipe.canonical_model_id),
            engine: None,
            device: None,
            runtime_id: None,
            env_id: None,
            host: None,
            port: None,
            foreground: false,
            managed: true,
            allow_public_bind: false,
        };
        self.open_serve_wizard_from_plan(plan);
    }

    fn open_serve_wizard(&mut self) {
        self.refresh_config();
        self.doctor_manager = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.logs_view = None;

        let engines = serve_wizard_engine_names();
        let default_engine = self
            .config
            .default_engine
            .as_deref()
            .unwrap_or(default_engine_for_platform());
        let default_engine_index = engines
            .iter()
            .position(|engine| engine == default_engine)
            .unwrap_or(0);
        match load_model_recipe_registry() {
            Ok(registry) => {
                let recipes = tui_recommended_assistant_recipes(registry.recipes);
                let engine_index =
                    serve_wizard_preferred_engine_index(&recipes).unwrap_or(default_engine_index);
                let message = recipes.is_empty().then(|| {
                    format!(
                        "The recommended assistant model was not found.\n\nExpected: {VALIDATED_LOCAL_ASSISTANT_MODEL}\n\nNo unverified model will be used automatically."
                    )
                });
                self.serve_wizard = Some(ServeWizardState {
                    recipes,
                    selected: 0,
                    detail_scroll: 0,
                    model_source: ServeModelSource::BuiltInRecipe,
                    model_index: 0,
                    local_model_path: String::new(),
                    engine_index,
                    device_index: 0,
                    host: DEFAULT_LOCAL_HOST.to_owned(),
                    port: DEFAULT_LOCAL_PORT.to_string(),
                    managed: true,
                    runtime_id: None,
                    env_id: None,
                    allow_public_bind: false,
                    editing_field: None,
                    message,
                });
                self.status = if self
                    .serve_wizard
                    .as_ref()
                    .is_some_and(|state| state.recipes.is_empty())
                {
                    "Recommended assistant model was not found.".to_owned()
                } else {
                    "Local AI opened with the recommended assistant model. Press Start.".to_owned()
                };
            }
            Err(error) => {
                self.serve_wizard = Some(ServeWizardState {
                    recipes: Vec::new(),
                    selected: 0,
                    detail_scroll: 0,
                    model_source: ServeModelSource::LocalPath,
                    model_index: 0,
                    local_model_path: String::new(),
                    engine_index: default_engine_index,
                    device_index: 0,
                    host: DEFAULT_LOCAL_HOST.to_owned(),
                    port: DEFAULT_LOCAL_PORT.to_string(),
                    managed: true,
                    runtime_id: None,
                    env_id: None,
                    allow_public_bind: false,
                    editing_field: None,
                    message: Some(format!("Model recipes could not load.\n\n{error}")),
                });
                self.status = "Local AI could not load model choices.".to_owned();
            }
        }
        self.mode = TuiMode::Serve;
    }

    fn open_serve_wizard_from_plan(&mut self, plan: ServeCommandPlan) {
        let typed_model = plan.model.clone();
        let typed_engine = plan.engine.clone();
        let runtime_id = plan.runtime_id.clone();
        let env_id = plan.env_id.clone();
        let allow_public_bind = plan.allow_public_bind;
        self.open_serve_wizard();
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };

        let review_index = serve_wizard_choice_index(ServeWizardChoice::Review);
        state.selected = review_index;
        state.managed = !plan.foreground;
        state.host = plan.host.unwrap_or_else(|| DEFAULT_LOCAL_HOST.to_owned());
        state.port = plan
            .port
            .map(|port| port.to_string())
            .unwrap_or_else(|| DEFAULT_LOCAL_PORT.to_string());
        state.runtime_id = runtime_id;
        state.env_id = env_id;
        state.allow_public_bind = allow_public_bind;

        let mut messages = vec!["Loaded your serve request. Use arrows to adjust it.".to_owned()];
        if let Some(model) = typed_model {
            if let Some(index) = state.recipes.iter().position(|recipe| {
                recipe.canonical_model_id.eq_ignore_ascii_case(&model)
                    || recipe
                        .aliases
                        .iter()
                        .any(|alias| alias.eq_ignore_ascii_case(&model))
            }) {
                state.model_source = ServeModelSource::BuiltInRecipe;
                state.model_index = index;
            } else {
                state.model_source = ServeModelSource::LocalPath;
                state.local_model_path = model.clone();
                if Path::new(&model)
                    .extension()
                    .and_then(|extension| extension.to_str())
                    .is_some_and(|extension| extension.eq_ignore_ascii_case("gguf"))
                    && typed_engine.is_none()
                    && let Some(index) = serve_wizard_engine_names()
                        .iter()
                        .position(|engine| engine == "llama.cpp")
                {
                    state.engine_index = index;
                }
            }
        }

        if let Some(engine) = typed_engine {
            if let Some(index) = serve_wizard_engine_names()
                .iter()
                .position(|candidate| candidate == &engine)
            {
                state.engine_index = index;
            } else {
                messages.push(format!(
                    "Engine `{engine}` is not in the list. Choose one from the Engine row."
                ));
                if let Some(index) = serve_wizard_choices()
                    .iter()
                    .position(|choice| *choice == ServeWizardChoice::Engine)
                {
                    state.selected = index;
                }
            }
        }

        state.message = Some(messages.join("\n\n"));
        self.status = "Local AI options loaded. Press Enter on Start to review.".to_owned();
    }

    fn close_serve_wizard(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.serve_wizard = None;
        self.status = "Local AI screen closed.".to_owned();
    }

    fn move_serve_wizard_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        state.message = None;
        state.selected = next_enabled_serve_wizard_index(state, direction);
        state.detail_scroll = 0;
        self.status = "Local AI option selected.".to_owned();
    }

    fn selected_serve_wizard_choice(&self) -> ServeWizardChoice {
        let selected = self
            .serve_wizard
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        serve_wizard_choices()
            .get(selected)
            .copied()
            .unwrap_or(ServeWizardChoice::Model)
    }

    fn serve_wizard_editing_text(&self) -> bool {
        self.serve_wizard
            .as_ref()
            .is_some_and(|state| state.editing_field.is_some())
    }

    fn serve_wizard_editing_title(&self) -> &'static str {
        match self
            .serve_wizard
            .as_ref()
            .and_then(|state| state.editing_field)
        {
            Some(ServeWizardEditField::LocalPath) => "Model Path",
            Some(ServeWizardEditField::Host) => "Host",
            Some(ServeWizardEditField::Port) => "Port",
            None => "Prompt",
        }
    }

    fn cycle_serve_wizard_value(&mut self, direction: CompletionDirection) {
        let Some(choice) = self
            .serve_wizard
            .as_ref()
            .map(|_| self.selected_serve_wizard_choice())
        else {
            return;
        };
        match choice {
            ServeWizardChoice::Source => self.toggle_serve_wizard_model_source(),
            ServeWizardChoice::Model => self.cycle_serve_wizard_model(direction),
            ServeWizardChoice::LocalPath => {
                self.status = if self
                    .serve_wizard
                    .as_ref()
                    .is_some_and(|state| state.model_source == ServeModelSource::BuiltInRecipe)
                {
                    "Change Model type before choosing a custom path.".to_owned()
                } else {
                    "Press Enter to choose a local model file or folder.".to_owned()
                };
            }
            ServeWizardChoice::Engine => self.cycle_serve_wizard_engine(direction),
            ServeWizardChoice::Device => self.cycle_serve_wizard_device(direction),
            ServeWizardChoice::Host => self.cycle_serve_wizard_host(),
            ServeWizardChoice::Port => self.cycle_serve_wizard_port(direction),
            ServeWizardChoice::Mode => self.toggle_serve_wizard_mode(),
            ServeWizardChoice::Review | ServeWizardChoice::Back => {
                self.status = "Use Enter to select this row.".to_owned();
            }
        }
    }

    fn toggle_serve_wizard_model_source(&mut self) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        state.message = None;
        state.model_source = match state.model_source {
            ServeModelSource::BuiltInRecipe => ServeModelSource::LocalPath,
            ServeModelSource::LocalPath => ServeModelSource::BuiltInRecipe,
        };
        self.status = match state.model_source {
            ServeModelSource::BuiltInRecipe => {
                format!("Recommended assistant model selected: {VALIDATED_LOCAL_ASSISTANT_MODEL}.")
            }
            ServeModelSource::LocalPath => {
                "Local model selected. Press Enter on Local path to choose a file or folder."
                    .to_owned()
            }
        };
    }

    fn cycle_serve_wizard_model(&mut self, _direction: CompletionDirection) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        if state.model_source == ServeModelSource::BuiltInRecipe {
            state.message = Some(format!(
                "Recommended model is fixed.\n\nROCm CLI uses {VALIDATED_LOCAL_ASSISTANT_MODEL} because it is the validated low-VRAM Lemonade assistant path."
            ));
            self.status =
                "Recommended model is fixed. Use Model type for a custom file.".to_owned();
            return;
        }
        state.message = Some(
            "Model row is not used for a custom file.\n\nUse the Path row to choose your model file or folder."
                .to_owned(),
        );
        self.status = "Use Path to choose a custom model.".to_owned();
    }

    fn cycle_serve_wizard_engine(&mut self, direction: CompletionDirection) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        let engines = serve_wizard_engine_names();
        state.message = None;
        state.engine_index = cycle_index(state.engine_index, engines.len(), direction);
        self.status = "Engine selected.".to_owned();
    }

    fn cycle_serve_wizard_device(&mut self, direction: CompletionDirection) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        let devices = serve_wizard_device_options();
        state.message = None;
        state.device_index = cycle_index(state.device_index, devices.len(), direction);
        self.status = "Device choice selected.".to_owned();
    }

    fn cycle_serve_wizard_host(&mut self) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        state.message = None;
        state.host = if state.host.eq_ignore_ascii_case("localhost") {
            DEFAULT_LOCAL_HOST.to_owned()
        } else {
            "localhost".to_owned()
        };
        self.status = format!("Host set to {}.", state.host);
    }

    fn cycle_serve_wizard_port(&mut self, direction: CompletionDirection) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        state.message = None;
        let port = state.port.parse::<u16>().unwrap_or(DEFAULT_LOCAL_PORT);
        let next = match direction {
            CompletionDirection::Next => port.saturating_add(1).max(1),
            CompletionDirection::Previous => port.saturating_sub(1).max(1),
        };
        state.port = next.to_string();
        self.status = format!("Port set to {}.", state.port);
    }

    fn toggle_serve_wizard_mode(&mut self) {
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        state.message = None;
        state.managed = !state.managed;
        self.status = if state.managed {
            "Local AI will stay running in ROCm CLI after approval.".to_owned()
        } else {
            "Command-only mode will show the command without launching here.".to_owned()
        };
    }

    fn perform_serve_wizard_selected_action(&mut self) {
        match self.selected_serve_wizard_choice() {
            ServeWizardChoice::Source => self.toggle_serve_wizard_model_source(),
            ServeWizardChoice::Model => self.cycle_serve_wizard_model(CompletionDirection::Next),
            ServeWizardChoice::Engine | ServeWizardChoice::Device | ServeWizardChoice::Mode => {
                self.cycle_serve_wizard_value(CompletionDirection::Next)
            }
            ServeWizardChoice::LocalPath => {
                if self
                    .serve_wizard
                    .as_ref()
                    .is_some_and(|state| state.model_source == ServeModelSource::BuiltInRecipe)
                {
                    self.status =
                        "Change Model type to my own model file before editing Path.".to_owned();
                } else {
                    self.start_serve_wizard_field_edit(ServeWizardEditField::LocalPath)
                }
            }
            ServeWizardChoice::Host => {
                self.start_serve_wizard_field_edit(ServeWizardEditField::Host)
            }
            ServeWizardChoice::Port => {
                self.start_serve_wizard_field_edit(ServeWizardEditField::Port)
            }
            ServeWizardChoice::Review => self.review_serve_wizard_plan(),
            ServeWizardChoice::Back => self.close_serve_wizard(),
        }
    }

    fn start_serve_wizard_field_edit(&mut self, field: ServeWizardEditField) {
        let value = self
            .serve_wizard
            .as_ref()
            .map(|state| match field {
                ServeWizardEditField::LocalPath => state.local_model_path.clone(),
                ServeWizardEditField::Host => state.host.clone(),
                ServeWizardEditField::Port => state.port.clone(),
            })
            .unwrap_or_default();
        if let Some(state) = self.serve_wizard.as_mut() {
            if field == ServeWizardEditField::LocalPath {
                state.model_source = ServeModelSource::LocalPath;
            }
            state.editing_field = Some(field);
            state.message = Some(match field {
                ServeWizardEditField::LocalPath => {
                    "Choose a model file or folder below.\n\nPress Enter to save or Esc to cancel."
                        .to_owned()
                }
                ServeWizardEditField::Host => {
                    "Choose where the server listens.\n\nUse 127.0.0.1 or localhost for this computer."
                        .to_owned()
                }
                ServeWizardEditField::Port => {
                    "Choose the local server port.\n\nUse a number from 1 to 65535.".to_owned()
                }
            });
        }
        self.set_input(value);
        self.status = match field {
            ServeWizardEditField::LocalPath => {
                "Type or paste a local model file or folder, then press Enter.".to_owned()
            }
            ServeWizardEditField::Host => "Type a local host, then press Enter.".to_owned(),
            ServeWizardEditField::Port => "Type a port number, then press Enter.".to_owned(),
        };
    }

    fn commit_serve_wizard_field_edit(&mut self) {
        let field = self
            .serve_wizard
            .as_ref()
            .and_then(|state| state.editing_field);
        let Some(field) = field else {
            return;
        };
        let value = normalize_runtime_path_input(&self.input);
        let result = match field {
            ServeWizardEditField::LocalPath => {
                validate_serve_local_model_path(&value).map(|path| path.display().to_string())
            }
            ServeWizardEditField::Host => validate_serve_wizard_host(&value),
            ServeWizardEditField::Port => {
                validate_serve_wizard_port(&value).map(|port| port.to_string())
            }
        };
        let Some(state) = self.serve_wizard.as_mut() else {
            return;
        };
        match result {
            Ok(value) => {
                match field {
                    ServeWizardEditField::LocalPath => {
                        if Path::new(&value)
                            .extension()
                            .and_then(|extension| extension.to_str())
                            .is_some_and(|extension| extension.eq_ignore_ascii_case("gguf"))
                            && let Some(index) = serve_wizard_engine_names()
                                .iter()
                                .position(|engine| engine == "llama.cpp")
                        {
                            state.engine_index = index;
                        }
                        state.local_model_path = value;
                        state.model_source = ServeModelSource::LocalPath;
                        self.status = "Local model selected. Press Start when ready.".to_owned();
                    }
                    ServeWizardEditField::Host => {
                        state.host = value;
                        self.status = "Host saved.".to_owned();
                    }
                    ServeWizardEditField::Port => {
                        state.port = value;
                        self.status = "Port saved.".to_owned();
                    }
                }
                state.editing_field = None;
                state.message = None;
                self.clear_input();
            }
            Err(error) => {
                state.message = Some(error.to_string());
                self.status = match field {
                    ServeWizardEditField::LocalPath => {
                        "Choose a model file or folder that exists.".to_owned()
                    }
                    ServeWizardEditField::Host => "Use a local-only host.".to_owned(),
                    ServeWizardEditField::Port => "Use a port number from 1 to 65535.".to_owned(),
                };
            }
        }
    }

    fn cancel_serve_wizard_field_edit(&mut self) {
        if let Some(state) = self.serve_wizard.as_mut() {
            state.editing_field = None;
            state.message = None;
        }
        self.clear_input();
        self.status = "Serve option unchanged.".to_owned();
    }

    fn selected_serve_wizard_plan(&self) -> Result<ServeCommandPlan> {
        let state = self
            .serve_wizard
            .as_ref()
            .context("serve wizard is not open")?;
        let engines = serve_wizard_engine_names();
        let devices = serve_wizard_device_options();
        let model = match state.model_source {
            ServeModelSource::BuiltInRecipe => selected_serve_wizard_recipe(state)
                .map(|recipe| recipe.canonical_model_id.clone())
                .with_context(|| {
                    format!(
                        "The recommended assistant model is not available: {VALIDATED_LOCAL_ASSISTANT_MODEL}"
                    )
                })?,
            ServeModelSource::LocalPath => {
                validate_serve_local_model_path(&state.local_model_path)?
                    .display()
                    .to_string()
            }
        };
        let host = validate_serve_wizard_host(&state.host)?;
        let port = validate_serve_wizard_port(&state.port)?;
        Ok(ServeCommandPlan {
            model: Some(model),
            engine: engines.get(state.engine_index).cloned(),
            device: devices
                .get(state.device_index)
                .map(|device| (*device).to_owned()),
            runtime_id: state.runtime_id.clone(),
            env_id: state.env_id.clone(),
            host: (host != DEFAULT_LOCAL_HOST).then_some(host),
            port: (port != DEFAULT_LOCAL_PORT).then_some(port),
            foreground: !state.managed,
            managed: state.managed,
            allow_public_bind: state.allow_public_bind,
        })
    }

    fn review_serve_wizard_plan(&mut self) {
        let mut plan = match self.selected_serve_wizard_plan() {
            Ok(plan) => plan,
            Err(error) => {
                if let Some(state) = self.serve_wizard.as_mut() {
                    state.message = Some(error.to_string());
                }
                self.status = "Local AI options need a fix.".to_owned();
                return;
            }
        };
        if plan.managed && !self.prepare_serve_wizard_runtime(&mut plan) {
            return;
        }
        let rendered = render_serve_wizard_review(&plan, &self.config);
        if let Some(state) = self.serve_wizard.as_mut() {
            state.message = Some(rendered);
        }
        if plan.managed {
            self.request_screen_cli_approval("Serve", "Serve", plan.cli_args(), None);
        } else {
            self.status = "Plan shown. Change Mode to keep it running in ROCm CLI.".to_owned();
        }
    }

    fn prepare_serve_wizard_runtime(&mut self, plan: &mut ServeCommandPlan) -> bool {
        if plan.engine_manages_own_runtime(&self.config) {
            plan.runtime_id = None;
            if let Some(state) = self.serve_wizard.as_mut() {
                state.runtime_id = None;
                state.message = Some(
                    "Lemonade uses its own ROCm runner. No TheRock install has to be chosen here."
                        .to_owned(),
                );
            }
            return true;
        }
        if plan.runtime_id.is_some() || plan.env_id.is_some() {
            return true;
        }
        match serve_runtime_preflight(&self.paths, &self.config) {
            Ok(ServeRuntimePreflight::UseRuntime(runtime_key)) => {
                plan.runtime_id = Some(runtime_key.clone());
                if let Some(state) = self.serve_wizard.as_mut() {
                    state.runtime_id = Some(runtime_key.clone());
                    state.message = Some(format!(
                        "Using ROCm install `{runtime_key}` for this local model server."
                    ));
                }
                true
            }
            Ok(ServeRuntimePreflight::NeedsInstall) => {
                self.open_install_manager();
                self.open_install_sdk_form(Some(
                    "Set up ROCm first.\n\nLocal AI needs a usable ROCm install before it can start. Choose an install folder, then press Enter on Install ROCm."
                        .to_owned(),
                ));
                self.status = "Set up ROCm before starting Local AI.".to_owned();
                false
            }
            Ok(ServeRuntimePreflight::NeedsChoice) => {
                self.open_runtime_manager();
                if let Some(state) = self.runtime_manager.as_mut() {
                    state.message = Some(
                        "Choose a ROCm install for Local AI.\n\nSelect a ready install and press Enter to review making it the default, then start Local AI again."
                            .to_owned(),
                    );
                }
                self.status = "Choose a ROCm install before starting Local AI.".to_owned();
                false
            }
            Err(error) => {
                if let Some(state) = self.serve_wizard.as_mut() {
                    state.message = Some(format!("Could not check ROCm installs.\n\n{error}"));
                }
                self.status = "ROCm install check failed.".to_owned();
                false
            }
        }
    }

    fn open_update_manager(&mut self) {
        self.doctor_manager = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.logs_view = None;
        self.update_manager = Some(UpdateManagerState {
            selected: 0,
            detail_scroll: 0,
            report: render_update_manager_report(&self.paths),
            message: None,
        });
        self.mode = TuiMode::Act;
        self.status = "Updates opened. Use arrow keys, then Enter.".to_owned();
    }

    fn close_update_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.update_manager = None;
        self.return_to_home_after_surface_close("Updates closed.");
    }

    fn refresh_update_manager(&mut self) {
        let message = self
            .update_manager
            .as_ref()
            .and_then(|state| state.message.clone());
        if let Some(state) = self.update_manager.as_mut() {
            state.report = render_update_manager_report(&self.paths);
            state.message = message;
            self.status = "Update status refreshed.".to_owned();
        }
    }

    fn move_update_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.update_manager.as_mut() else {
            return;
        };
        let choices = update_menu_choices();
        state.selected = match direction {
            CompletionDirection::Next => (state.selected + 1) % choices.len(),
            CompletionDirection::Previous => {
                if state.selected == 0 {
                    choices.len().saturating_sub(1)
                } else {
                    state.selected - 1
                }
            }
        };
        state.detail_scroll = 0;
        self.status = "Update option selected. Press Enter to continue.".to_owned();
    }

    fn selected_update_menu_choice(&self) -> UpdateMenuChoice {
        let selected = self
            .update_manager
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        update_menu_choices()
            .get(selected)
            .copied()
            .unwrap_or(UpdateMenuChoice::Refresh)
    }

    fn perform_update_manager_selected_action(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        match self.selected_update_menu_choice() {
            UpdateMenuChoice::Refresh => self.refresh_update_manager(),
            UpdateMenuChoice::Preview => self.start_cli_command_with_display(
                "Update",
                vec![
                    "update".to_owned(),
                    "--apply".to_owned(),
                    "--dry-run".to_owned(),
                ],
                "/update --apply --preview".to_owned(),
            ),
            UpdateMenuChoice::Apply => self.request_screen_cli_approval(
                "Apply ROCm update",
                "Update",
                vec!["update".to_owned(), "--apply".to_owned()],
                Some("/update --apply".to_owned()),
            ),
            UpdateMenuChoice::ApplyAndUse => self.request_screen_cli_approval(
                "Apply ROCm update and use it",
                "Update",
                vec![
                    "update".to_owned(),
                    "--apply".to_owned(),
                    "--activate".to_owned(),
                ],
                Some("/update --apply --activate".to_owned()),
            ),
            UpdateMenuChoice::Back => self.close_update_manager(),
        }
    }

    fn normalize_update_runtime_args(&mut self, mut cli_args: Vec<String>) -> Option<Vec<String>> {
        let Some(runtime_index) = cli_args.iter().position(|arg| arg == "--runtime") else {
            return Some(cli_args);
        };
        let Some(selector) = cli_args.get(runtime_index + 1).cloned() else {
            self.set_active_screen_message("Choose a ROCm install before applying this update.");
            self.status = "Choose a ROCm install before updating.".to_owned();
            return None;
        };
        let items = match runtime_manager_items(&self.paths, &self.config) {
            Ok(items) => items,
            Err(error) => {
                self.set_active_screen_message(format!(
                    "ROCm installs could not be loaded.\n\n{error}"
                ));
                self.status = "ROCm installs could not be loaded.".to_owned();
                return None;
            }
        };
        if let Some(item) = items
            .iter()
            .find(|item| item.runtime_key.eq_ignore_ascii_case(&selector))
        {
            cli_args[runtime_index + 1] = item.runtime_key.clone();
            return Some(cli_args);
        }

        let runtime_id_matches = items
            .iter()
            .filter(|item| item.runtime_id.eq_ignore_ascii_case(&selector))
            .collect::<Vec<_>>();
        match runtime_id_matches.as_slice() {
            [item] => {
                cli_args[runtime_index + 1] = item.runtime_key.clone();
                Some(cli_args)
            }
            [] => {
                self.set_active_screen_message(format!(
                    "I could not find ROCm install `{selector}`.\n\nOpen ROCm installs and choose one from the list."
                ));
                self.status = "Choose a ROCm install before updating.".to_owned();
                None
            }
            _ => {
                self.set_active_screen_message(format!(
                    "More than one ROCm install matches `{selector}`.\n\nOpen ROCm installs and choose the exact install."
                ));
                self.status = "Choose the exact ROCm install before updating.".to_owned();
                None
            }
        }
    }

    fn open_automations_manager(&mut self) {
        self.refresh_config();
        self.doctor_manager = None;
        self.logs_view = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        let previous_key = self
            .automations_manager
            .as_ref()
            .and_then(selected_automation_manager_row_key);
        let items = load_recent_automation_proposals(&self.paths, 32)
            .unwrap_or_default()
            .into_iter()
            .map(|proposal| AutomationReviewItem { proposal })
            .collect::<Vec<_>>();
        let watchers = automation_watcher_items(&self.config);
        let rows = automation_manager_rows(&items, &watchers);
        let selected = previous_key
            .as_ref()
            .and_then(|key| automation_manager_row_index(&items, &watchers, &rows, key))
            .or_else(|| {
                items
                    .iter()
                    .position(|item| item.proposal.status == "pending")
                    .and_then(|index| {
                        rows.iter()
                            .position(|row| *row == AutomationManagerRow::Review(index))
                    })
            })
            .unwrap_or(0);
        self.automations_manager = Some(AutomationsManagerState {
            selected: selected.min(rows.len().saturating_sub(1)),
            detail_scroll: 0,
            items,
            watchers,
            rows,
            overview: render_automations_text(&self.paths, &self.config)
                .unwrap_or_else(|error| format!("Automation check failed.\n\n{error}")),
            editing_prefetch_max_bytes: None,
            message: None,
        });
        self.mode = TuiMode::Automations;
        self.status = "Automations opened. Use arrow keys, then Enter.".to_owned();
    }

    fn close_automations_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.automations_manager = None;
        self.pending_approval = None;
        self.return_to_home_after_surface_close("Automations closed.");
    }

    fn refresh_automations_manager(&mut self) {
        let message = self
            .automations_manager
            .as_ref()
            .and_then(|state| state.message.clone());
        let selected_key = self
            .automations_manager
            .as_ref()
            .and_then(selected_automation_manager_row_key);
        self.open_automations_manager();
        if let Some(state) = self.automations_manager.as_mut() {
            if let Some(selected_key) = selected_key.as_ref()
                && let Some(index) = automation_manager_row_index(
                    &state.items,
                    &state.watchers,
                    &state.rows,
                    selected_key,
                )
            {
                state.selected = index;
            }
            state.message = message;
        }
        self.status = "Automations refreshed.".to_owned();
    }

    fn move_automations_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.automations_manager.as_mut() else {
            return;
        };
        if state.rows.is_empty() {
            self.status = "No automation checks found.".to_owned();
            return;
        }
        state.message = None;
        state.selected = match direction {
            CompletionDirection::Next => (state.selected + 1) % state.rows.len(),
            CompletionDirection::Previous => {
                if state.selected == 0 {
                    state.rows.len().saturating_sub(1)
                } else {
                    state.selected - 1
                }
            }
        };
        state.detail_scroll = 0;
        self.status = match selected_automation_manager_row(state) {
            Some(AutomationManagerSelectedRow::Review(_)) => {
                "Review request selected. Press Enter to review.".to_owned()
            }
            Some(AutomationManagerSelectedRow::PrefetchField(_, field)) => {
                automation_prefetch_field_status(field).to_owned()
            }
            Some(AutomationManagerSelectedRow::Watcher(watcher)) => format!(
                "{} selected. Press Enter to {} it.",
                watcher.name,
                if watcher.enabled {
                    "turn off"
                } else {
                    "turn on"
                }
            ),
            None => "Automation item selected.".to_owned(),
        };
    }

    fn selected_automation_proposal(&self) -> Option<AutomationProposalRecord> {
        let state = self.automations_manager.as_ref()?;
        match selected_automation_manager_row(state)? {
            AutomationManagerSelectedRow::Review(proposal) => Some(proposal),
            AutomationManagerSelectedRow::PrefetchField(_, _) => None,
            AutomationManagerSelectedRow::Watcher(_) => None,
        }
    }

    fn selected_automation_prefetch_field(
        &self,
    ) -> Option<(AutomationProposalRecord, AutomationPrefetchField)> {
        let state = self.automations_manager.as_ref()?;
        match selected_automation_manager_row(state)? {
            AutomationManagerSelectedRow::PrefetchField(proposal, field) => Some((proposal, field)),
            _ => None,
        }
    }

    fn automations_manager_editing_text(&self) -> bool {
        self.automations_manager
            .as_ref()
            .is_some_and(|state| state.editing_prefetch_max_bytes.is_some())
    }

    fn automations_manager_editing_title(&self) -> &'static str {
        if self.automations_manager_editing_text() {
            "Max Download"
        } else {
            "Prompt"
        }
    }

    fn selected_automation_watcher(&self) -> Option<AutomationWatcherItem> {
        let state = self.automations_manager.as_ref()?;
        match selected_automation_manager_row(state)? {
            AutomationManagerSelectedRow::Review(_) => None,
            AutomationManagerSelectedRow::PrefetchField(_, _) => None,
            AutomationManagerSelectedRow::Watcher(watcher) => Some(watcher),
        }
    }

    fn perform_automations_manager_selected_action(&mut self) {
        if self.selected_automation_watcher().is_some() {
            self.request_selected_automation_watcher_toggle();
        } else if let Some((proposal, field)) = self.selected_automation_prefetch_field() {
            self.perform_prefetch_field_action(proposal, field);
        } else {
            self.focus_selected_automation_proposal();
        }
    }

    fn perform_prefetch_field_action(
        &mut self,
        proposal: AutomationProposalRecord,
        field: AutomationPrefetchField,
    ) {
        match field {
            AutomationPrefetchField::AllowDownload => {
                let current = proposal_bool_argument(&proposal, "allow_artifact_download");
                self.update_prefetch_bool_field(proposal, field, !current);
            }
            AutomationPrefetchField::AllowHuggingFace => {
                let current = proposal_bool_argument(&proposal, "allow_huggingface_download");
                self.update_prefetch_bool_field(proposal, field, !current);
            }
            AutomationPrefetchField::MaxBytes => {
                self.start_prefetch_max_bytes_edit(&proposal);
            }
        }
    }

    fn update_prefetch_bool_field(
        &mut self,
        mut proposal: AutomationProposalRecord,
        field: AutomationPrefetchField,
        value: bool,
    ) {
        if field == AutomationPrefetchField::AllowHuggingFace
            && value
            && !proposal_bool_argument(&proposal, "allow_artifact_download")
        {
            if let Some(state) = self.automations_manager.as_mut() {
                state.message = Some(
                    "Turn on Download first.\n\nHugging Face token permission is only used when this review may download the file."
                        .to_owned(),
                );
            }
            self.status = "Turn on Download first.".to_owned();
            return;
        }
        let key = match field {
            AutomationPrefetchField::AllowDownload => "allow_artifact_download",
            AutomationPrefetchField::AllowHuggingFace => "allow_huggingface_download",
            AutomationPrefetchField::MaxBytes => {
                self.status = "Use Enter to edit max download.".to_owned();
                return;
            }
        };
        set_proposal_bool_argument(&mut proposal, key, value);
        self.save_prefetch_proposal_edit(
            proposal,
            field,
            automation_prefetch_field_saved_message(field),
        );
    }

    fn cycle_prefetch_max_bytes(
        &mut self,
        mut proposal: AutomationProposalRecord,
        direction: CompletionDirection,
    ) {
        let next = cycle_prefetch_max_bytes_value(
            proposal_u64_argument(&proposal, "artifact_max_bytes"),
            direction,
        );
        set_proposal_u64_argument(&mut proposal, "artifact_max_bytes", next);
        self.save_prefetch_proposal_edit(
            proposal,
            AutomationPrefetchField::MaxBytes,
            "Max download updated.",
        );
    }

    fn save_prefetch_proposal_edit(
        &mut self,
        proposal: AutomationProposalRecord,
        field: AutomationPrefetchField,
        status: &str,
    ) {
        match self.save_prefetch_proposal_edit_result(proposal, field) {
            Ok(()) => self.status = status.to_owned(),
            Err(error) => {
                if let Some(state) = self.automations_manager.as_mut() {
                    state.message = Some(format!("Review edit failed.\n\n{error}"));
                }
                self.status = "Review edit failed.".to_owned();
            }
        }
    }

    fn save_prefetch_proposal_edit_result(
        &mut self,
        proposal: AutomationProposalRecord,
        field: AutomationPrefetchField,
    ) -> Result<()> {
        ensure_prefetch_proposal(&proposal)?;
        if proposal.status != "pending" {
            bail!(
                "review request `{}` is already {}",
                proposal.proposal_id,
                proposal_status_for_user(&proposal.status)
            );
        }
        let updated = replace_automation_proposal(&self.paths, &proposal)?;
        record_proposal_audit(
            &self.paths,
            &updated,
            "proposal_edited",
            "info",
            &format!("edited proposal {}", updated.proposal_id),
        )?;
        if let Some(state) = self.automations_manager.as_mut() {
            if let Some(item) = state
                .items
                .iter_mut()
                .find(|item| item.proposal.proposal_id == updated.proposal_id)
            {
                item.proposal = updated.clone();
            }
            select_automation_manager_row_by_key(
                state,
                &AutomationManagerRowKey::PrefetchField(updated.proposal_id.clone(), field),
            );
            state.message = Some(render_prefetch_field_detail(&updated, field));
        }
        Ok(())
    }

    fn start_prefetch_max_bytes_edit(&mut self, proposal: &AutomationProposalRecord) {
        if let Some(state) = self.automations_manager.as_mut() {
            state.editing_prefetch_max_bytes = Some(proposal.proposal_id.clone());
            state.message = Some(
                "Set the largest download this review may approve.\n\nType bytes, then press Enter. Esc cancels."
                    .to_owned(),
            );
        }
        let value = proposal_u64_argument(proposal, "artifact_max_bytes")
            .map(|bytes| bytes.to_string())
            .unwrap_or_default();
        self.set_input(value);
        self.status = "Type max download bytes, then press Enter.".to_owned();
    }

    fn commit_prefetch_max_bytes_edit(&mut self) {
        let proposal_id = self
            .automations_manager
            .as_ref()
            .and_then(|state| state.editing_prefetch_max_bytes.clone());
        let Some(proposal_id) = proposal_id else {
            return;
        };
        let value = self.input.trim().to_owned();
        let bytes = match value.parse::<u64>() {
            Ok(bytes) if bytes > 0 => bytes,
            _ => {
                if let Some(state) = self.automations_manager.as_mut() {
                    state.message = Some(
                        "Max download was not saved.\n\nUse a number greater than zero.".to_owned(),
                    );
                }
                self.status = "Use a number greater than zero.".to_owned();
                return;
            }
        };
        let mut proposal = match find_automation_proposal(&self.paths, &proposal_id) {
            Ok(proposal) => proposal,
            Err(error) => {
                if let Some(state) = self.automations_manager.as_mut() {
                    state.message = Some(format!("Review edit failed.\n\n{error}"));
                    state.editing_prefetch_max_bytes = None;
                }
                self.clear_input();
                self.status = "Review edit failed.".to_owned();
                return;
            }
        };
        set_proposal_u64_argument(&mut proposal, "artifact_max_bytes", bytes);
        if let Some(state) = self.automations_manager.as_mut() {
            state.editing_prefetch_max_bytes = None;
        }
        self.clear_input();
        self.save_prefetch_proposal_edit(
            proposal,
            AutomationPrefetchField::MaxBytes,
            "Max download updated.",
        );
    }

    fn cancel_prefetch_max_bytes_edit(&mut self) {
        if let Some(state) = self.automations_manager.as_mut() {
            state.editing_prefetch_max_bytes = None;
            state.message = None;
        }
        self.clear_input();
        self.status = "Max download unchanged.".to_owned();
    }

    fn focus_selected_automation_proposal(&mut self) {
        let Some(proposal) = self.selected_automation_proposal() else {
            self.show_no_automation_review_selected_message();
            return;
        };
        if proposal.status != "pending" {
            if let Some(state) = self.automations_manager.as_mut() {
                state.message = Some(format!(
                    "{} is already {}.",
                    proposal.proposal_id,
                    proposal_status_for_user(&proposal.status)
                ));
            }
            self.status = "Review request is not pending.".to_owned();
            return;
        }
        match self.focus_proposal(proposal) {
            Ok(()) => {}
            Err(error) => {
                if let Some(state) = self.automations_manager.as_mut() {
                    state.message = Some(format!("Review request failed.\n\n{error}"));
                }
                self.status = "Review request failed.".to_owned();
            }
        }
    }

    fn show_no_automation_review_selected_message(&mut self) {
        if let Some(state) = self.automations_manager.as_mut() {
            state.message = Some(
                "No review request is selected.\n\nUse Up and Down to choose a review request, then press Enter to review it. Automation checks can be turned on or off from their own rows."
                    .to_owned(),
            );
        }
        self.status = "Choose a review request from the list.".to_owned();
    }

    fn request_selected_automation_watcher_toggle(&mut self) {
        let Some(watcher) = self.selected_automation_watcher() else {
            self.status = "No automation check is selected.".to_owned();
            return;
        };
        self.request_automation_watcher_enabled(&watcher, !watcher.enabled);
    }

    fn request_automation_watcher_enabled(
        &mut self,
        watcher: &AutomationWatcherItem,
        enabled: bool,
    ) {
        if self.running_job_blocks_action() {
            return;
        }
        let mut args = vec!["automations".to_owned()];
        let display;
        let title;
        if enabled {
            args.push("enable".to_owned());
            args.push(watcher.id.clone());
            args.push("--mode".to_owned());
            args.push(watcher.mode.as_str().to_owned());
            display = format!(
                "/automations enable {} --mode {}",
                watcher.id,
                watcher.mode.as_str()
            );
            title = format!("Turn on {}", watcher.name);
        } else {
            args.push("disable".to_owned());
            args.push(watcher.id.clone());
            display = format!("/automations disable {}", watcher.id);
            title = format!("Turn off {}", watcher.name);
        }
        self.request_screen_cli_approval(&title, "Automations", args, Some(display));
    }

    fn select_automation_watcher_by_id(&mut self, watcher_id: &str) -> bool {
        let Some(state) = self.automations_manager.as_mut() else {
            return false;
        };
        if let Some(index) = state.rows.iter().position(|row| {
            matches!(
                row,
                AutomationManagerRow::Watcher(watcher_index)
                    if state
                        .watchers
                        .get(*watcher_index)
                        .is_some_and(|watcher| watcher.id == watcher_id)
            )
        }) {
            state.selected = index;
            state.message = None;
            true
        } else {
            state.message = Some(format!("Automation check `{watcher_id}` was not found."));
            false
        }
    }

