    fn close_config_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.config_manager = None;
        self.return_to_home_after_surface_close("Settings closed.");
    }

    fn move_config_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.config_manager.as_mut() else {
            return;
        };
        state.message = None;
        match &mut state.screen {
            ConfigManagerScreen::Main => {
                state.selected =
                    cycle_index(state.selected, config_menu_choices().len(), direction);
                state.detail_scroll = 0;
            }
            ConfigManagerScreen::Provider {
                selected,
                confirming_clear,
                ..
            } => {
                *selected = cycle_index(
                    *selected,
                    config_provider_choices(*confirming_clear).len(),
                    direction,
                );
                state.detail_scroll = 0;
            }
        }
        self.status = "Setting selected. Press Enter to change it.".to_owned();
    }

    fn selected_config_menu_choice(&self) -> ConfigMenuChoice {
        let selected = self
            .config_manager
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        config_menu_choices()
            .get(selected)
            .copied()
            .unwrap_or(ConfigMenuChoice::Telemetry)
    }

    fn select_config_menu_choice(&mut self, choice: ConfigMenuChoice) {
        if self.config_manager.is_none() {
            self.open_config_manager();
        }
        if let Some(state) = self.config_manager.as_mut()
            && let Some(index) = config_menu_choices()
                .iter()
                .position(|candidate| *candidate == choice)
        {
            state.screen = ConfigManagerScreen::Main;
            state.selected = index;
            state.detail_scroll = 0;
        }
    }

    fn select_config_provider_choice(&mut self, provider: &str, choice: ConfigProviderChoice) {
        self.open_config_provider_settings(provider);
        if let Some(state) = self.config_manager.as_mut()
            && let ConfigManagerScreen::Provider { selected, .. } = &mut state.screen
            && let Some(index) = config_provider_choices(false)
                .iter()
                .position(|candidate| *candidate == choice)
        {
            *selected = index;
            state.detail_scroll = 0;
        }
    }

    fn selected_config_provider_choice(&self) -> ConfigProviderChoice {
        let selected = self
            .config_manager
            .as_ref()
            .and_then(|state| match &state.screen {
                ConfigManagerScreen::Provider {
                    selected,
                    confirming_clear,
                    ..
                } => Some((*selected, *confirming_clear)),
                ConfigManagerScreen::Main => None,
            })
            .unwrap_or((0, false));
        config_provider_choices(selected.1)
            .get(selected.0)
            .copied()
            .unwrap_or(ConfigProviderChoice::PromptSending)
    }

    fn config_manager_editing_secret(&self) -> bool {
        self.config_manager.as_ref().is_some_and(|state| {
            matches!(
                state.screen,
                ConfigManagerScreen::Provider {
                    editing_key: true,
                    ..
                }
            )
        })
    }

    fn config_manager_confirming_provider_clear(&self) -> bool {
        self.config_manager.as_ref().is_some_and(|state| {
            matches!(
                state.screen,
                ConfigManagerScreen::Provider {
                    confirming_clear: true,
                    ..
                }
            )
        })
    }

    fn save_config_from_manager(&mut self, message: impl Into<String>) {
        match self.config.save(&self.paths) {
            Ok(()) => {
                let message = message.into();
                if let Some(state) = self.config_manager.as_mut() {
                    state.message = Some(message.clone());
                }
                self.status = message;
            }
            Err(error) => {
                if let Some(state) = self.config_manager.as_mut() {
                    state.message = Some(format!("Settings could not be saved.\n\n{error}"));
                }
                self.status = "Settings could not be saved.".to_owned();
            }
        }
    }

    fn open_setup_again_confirmation(&mut self) {
        self.overlay_card = Some(OverlayCardState {
            title: "First-time Setup".to_owned(),
            detail: [
                "Show first-time setup again?",
                "",
                "ROCm CLI will open the setup screen on the next run.",
                "",
                "ROCm installs stay on this computer.",
                "Installed ROCm folders are not removed.",
                "API keys stay saved.",
                "Provider settings stay saved.",
            ]
            .join("\n"),
            selected: 0,
            detail_scroll: 0,
            actions: vec![OverlayCardAction::Close, OverlayCardAction::ShowSetupAgain],
        });
        self.status = "Show setup again? Choose an option.".to_owned();
    }

    fn reset_setup_prompt_state(&mut self) -> bool {
        self.config.onboarding_dismissed = false;
        self.config.setup.completed = false;
        match self.config.save(&self.paths) {
            Ok(()) => true,
            Err(error) => {
                let message = format!("Setup reset could not be saved.\n\n{error}");
                if let Some(state) = self.config_manager.as_mut() {
                    state.message = Some(message.clone());
                }
                self.set_onboarding_setup_error(&message);
                self.status = "Setup reset could not be saved.".to_owned();
                false
            }
        }
    }

    fn open_onboarding_after_setup_reset(&mut self) {
        self.doctor_manager = None;
        self.logs_view = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.overlay_card = None;
        self.pending_approval = None;
        self.onboarding_active = true;
        self.onboarding_path_editing = false;
        self.reset_onboarding_install_output();
        self.reset_onboarding_selection();
        self.clear_input();
        self.status = "Setup will show again. ROCm installs were not deleted.".to_owned();
    }

    fn show_setup_again(&mut self) {
        if self.running_job_blocks_screen_switch() {
            return;
        }
        if self.reset_setup_prompt_state() {
            self.open_onboarding_after_setup_reset();
        }
    }

    fn set_config_telemetry_mode(&mut self, mode: &str) {
        self.config.telemetry.mode = mode.to_owned();
        if !self.config.telemetry.local_inspection_enabled() {
            self.gpu_telemetry.clear();
        }
        self.save_config_from_manager(format!("GPU checks set to {mode}."));
    }

    fn set_config_default_runtime_if_ready(&mut self, runtime_id: &str) {
        let matches = load_onboarding_runtimes(&self.paths)
            .into_iter()
            .filter(runtime_install_root_ready)
            .filter(|runtime| runtime.runtime_id.eq_ignore_ascii_case(runtime_id))
            .collect::<Vec<_>>();
        match matches.len() {
            1 => {
                self.open_runtime_manager();
                if let Some(runtime_key) = matches[0].runtime_key.as_deref() {
                    self.select_runtime_manager_item(runtime_key);
                }
                self.set_active_screen_message(format!(
                    "ROCm install `{runtime_id}` is selected.\n\nNothing changed yet. Use the highlighted row and press Enter to review using this install."
                ));
                self.status = "ROCm install selected. Press Enter to continue.".to_owned();
            }
            0 => {
                let looks_like_runtime_key = load_onboarding_runtimes(&self.paths)
                    .into_iter()
                    .filter(runtime_install_root_ready)
                    .any(|runtime| {
                        runtime
                            .runtime_key
                            .as_deref()
                            .is_some_and(|key| key.eq_ignore_ascii_case(runtime_id))
                    });
                self.open_runtime_manager();
                let message = if looks_like_runtime_key {
                    "That looks like a specific ROCm install.\n\nChoose it from this list and press Enter to make it the default."
                } else {
                    "I could not find a ready ROCm install with that name.\n\nChoose a ready ROCm install from this list, or install ROCm first."
                };
                self.set_active_screen_message(message);
                self.status = "Default ROCm install was not changed.".to_owned();
            }
            _ => {
                self.open_runtime_manager();
                self.set_active_screen_message(
                    "More than one ready ROCm install has that package name.\n\nChoose the exact install from this list and press Enter.",
                );
                self.status = "Choose the exact ROCm install.".to_owned();
            }
        }
    }

    fn set_config_planner_provider(&mut self, provider: Option<String>) {
        self.config.planner_provider = provider.clone();
        match provider {
            Some(provider) => {
                self.save_config_from_manager(format!("Planning help set to {provider}."));
            }
            None => self.save_config_from_manager("Planning help turned off."),
        }
    }

    fn set_config_provider_enabled(&mut self, provider: &str, enabled: bool) {
        if provider == "local" {
            if let Some(state) = self.config_manager.as_mut() {
                state.message = Some("Local provider is always available.".to_owned());
            }
            self.status = "Local provider is always available.".to_owned();
            return;
        }
        self.config.provider_config_mut(provider).enabled = enabled;
        self.save_config_from_manager(format!(
            "{} prompt sending {}.",
            provider,
            if enabled { "enabled" } else { "disabled" }
        ));
    }

    fn open_config_provider_settings(&mut self, provider: &str) {
        let label = provider_label(provider);
        if let Some(state) = self.config_manager.as_mut() {
            state.screen = ConfigManagerScreen::Provider {
                provider: provider.to_owned(),
                selected: 0,
                editing_key: false,
                confirming_clear: false,
            };
            state.message = None;
        }
        self.clear_input();
        self.status = format!("{label} settings opened. Use arrow keys, then Enter.");
    }

    fn close_config_provider_settings(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        if let Some(state) = self.config_manager.as_mut() {
            state.screen = ConfigManagerScreen::Main;
            state.message = None;
        }
        self.clear_input();
        self.status = "Back to Settings.".to_owned();
    }

    fn selected_config_provider(&self) -> Option<String> {
        self.config_manager
            .as_ref()
            .and_then(|state| match &state.screen {
                ConfigManagerScreen::Provider { provider, .. } => Some(provider.clone()),
                ConfigManagerScreen::Main => None,
            })
    }

    fn start_config_provider_key_edit(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            return;
        };
        if let Some(state) = self.config_manager.as_mut()
            && let ConfigManagerScreen::Provider {
                editing_key,
                confirming_clear,
                ..
            } = &mut state.screen
        {
            *editing_key = true;
            *confirming_clear = false;
            state.message = Some(format!(
                "Enter the {} API key below.\n\nThe key is hidden while you type. Press Enter to save or Esc to cancel.",
                provider_label(&provider)
            ));
        }
        self.clear_input();
        self.status = format!(
            "Enter {} API key. Input is hidden.",
            provider_label(&provider)
        );
    }

    fn cancel_config_provider_key_edit(&mut self) {
        if let Some(state) = self.config_manager.as_mut()
            && let ConfigManagerScreen::Provider {
                editing_key,
                confirming_clear,
                ..
            } = &mut state.screen
        {
            *editing_key = false;
            *confirming_clear = false;
            state.message = None;
        }
        self.clear_input();
        self.status = "API key entry canceled.".to_owned();
    }

    fn commit_config_provider_key_edit(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            self.clear_input();
            return;
        };
        let key = self.input.clone();
        match provider_keys::set_provider_api_key_with_store(
            self.provider_key_store.as_ref(),
            &provider,
            &key,
        ) {
            Ok(status) => {
                if let Some(state) = self.config_manager.as_mut() {
                    if let ConfigManagerScreen::Provider {
                        editing_key,
                        confirming_clear,
                        ..
                    } = &mut state.screen
                    {
                        *editing_key = false;
                        *confirming_clear = false;
                    }
                    state.message = Some(format!(
                        "{} API key saved.\n\nKey: {}",
                        provider_label(&provider),
                        provider_keys::provider_key_status_label(&status)
                    ));
                }
                self.clear_input();
                self.status = format!("{} API key saved.", provider_label(&provider));
            }
            Err(error) => {
                if let Some(state) = self.config_manager.as_mut() {
                    state.message = Some(provider_key_failure_text(&provider, "save", &error));
                }
                self.status =
                    "API key was not saved. Unlock secure storage and try again.".to_owned();
            }
        }
    }

    fn start_clear_config_provider_key_confirmation(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            return;
        };
        let label = provider_label(&provider);
        self.overlay_card = Some(OverlayCardState {
            title: "Clear API Key".to_owned(),
            detail: format!(
                "Clear the saved {label} API key?\n\nROCm CLI will forget this key from secure storage. Prompt sending for {label} will need a new key before it can work again."
            ),
            selected: 0,
            detail_scroll: 0,
            actions: vec![
                OverlayCardAction::Close,
                OverlayCardAction::ClearProviderKey,
            ],
        });
        if let Some(state) = self.config_manager.as_mut()
            && let ConfigManagerScreen::Provider {
                selected,
                confirming_clear,
                ..
            } = &mut state.screen
        {
            *confirming_clear = false;
            *selected = config_provider_choices(false)
                .iter()
                .position(|choice| *choice == ConfigProviderChoice::ClearKey)
                .unwrap_or(*selected);
            state.message = None;
        }
        self.clear_input();
        self.status = format!("Clear {label} API key? Choose an option.");
    }

    fn cancel_clear_config_provider_key_confirmation(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            return;
        };
        if let Some(state) = self.config_manager.as_mut()
            && let ConfigManagerScreen::Provider {
                selected,
                confirming_clear,
                ..
            } = &mut state.screen
        {
            *confirming_clear = false;
            *selected = config_provider_choices(false)
                .iter()
                .position(|choice| *choice == ConfigProviderChoice::ClearKey)
                .unwrap_or(0);
            state.message = Some(format!("{} API key kept.", provider_label(&provider)));
        }
        self.status = "API key was kept.".to_owned();
    }

    fn confirm_clear_config_provider_key(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            return;
        };
        match provider_keys::clear_provider_api_key_with_store(
            self.provider_key_store.as_ref(),
            &provider,
        ) {
            Ok(status) => {
                if let Some(state) = self.config_manager.as_mut() {
                    if let ConfigManagerScreen::Provider {
                        selected,
                        confirming_clear,
                        ..
                    } = &mut state.screen
                    {
                        *confirming_clear = false;
                        *selected = config_provider_choices(false)
                            .iter()
                            .position(|choice| *choice == ConfigProviderChoice::ClearKey)
                            .unwrap_or(0);
                    }
                    state.message = Some(format!(
                        "{} API key cleared.\n\nKey: {}",
                        provider_label(&provider),
                        provider_keys::provider_key_status_label(&status)
                    ));
                }
                self.status = format!("{} API key cleared.", provider_label(&provider));
            }
            Err(error) => {
                if let Some(state) = self.config_manager.as_mut() {
                    state.message = Some(provider_key_failure_text(&provider, "clear", &error));
                }
                self.status =
                    "API key could not be cleared. Unlock secure storage and try again.".to_owned();
            }
        }
    }

    fn perform_config_provider_selected_action(&mut self) {
        let Some(provider) = self.selected_config_provider() else {
            return;
        };
        match self.selected_config_provider_choice() {
            ConfigProviderChoice::PromptSending => {
                let enabled = !self.config.provider_enabled(&provider);
                self.set_config_provider_enabled(&provider, enabled);
            }
            ConfigProviderChoice::ApiKey => self.start_config_provider_key_edit(),
            ConfigProviderChoice::ClearKey => self.start_clear_config_provider_key_confirmation(),
            ConfigProviderChoice::ConfirmClearKey => self.confirm_clear_config_provider_key(),
            ConfigProviderChoice::CancelClearKey => {
                self.cancel_clear_config_provider_key_confirmation()
            }
            ConfigProviderChoice::Back => self.close_config_provider_settings(),
        }
    }

    fn cycle_config_planner_provider(&mut self) {
        let current = self.config.planner_provider.as_deref().unwrap_or("off");
        let next = match current {
            "off" | "" => Some("local"),
            "local" => Some("openai"),
            "openai" => Some("anthropic"),
            _ => None,
        }
        .map(str::to_owned);
        self.set_config_planner_provider(next);
    }

    fn perform_config_manager_selected_action(&mut self) {
        if self
            .config_manager
            .as_ref()
            .is_some_and(|state| matches!(state.screen, ConfigManagerScreen::Provider { .. }))
        {
            self.perform_config_provider_selected_action();
            return;
        }
        match self.selected_config_menu_choice() {
            ConfigMenuChoice::Telemetry => {
                if self.config.telemetry.local_inspection_enabled() {
                    self.set_config_telemetry_mode(TELEMETRY_MODE_OFF);
                } else {
                    self.set_config_telemetry_mode(TELEMETRY_MODE_LOCAL);
                }
            }
            ConfigMenuChoice::PlannerProvider => self.cycle_config_planner_provider(),
            ConfigMenuChoice::OpenAiProvider => self.open_config_provider_settings("openai"),
            ConfigMenuChoice::AnthropicProvider => self.open_config_provider_settings("anthropic"),
            ConfigMenuChoice::DefaultEngine => self.open_engine_manager(),
            ConfigMenuChoice::DefaultRuntime => self.open_runtime_manager(),
            ConfigMenuChoice::Permissions => {
                self.open_command_screen_target(CommandScreenTarget::Permissions)
            }
            ConfigMenuChoice::ShowSetupAgain => self.open_setup_again_confirmation(),
            ConfigMenuChoice::Back => self.close_config_manager(),
        }
    }

    fn handle_config_command_args(&mut self, args: &[&str]) {
        self.open_config_manager();
        match args {
            [] | ["show"] | ["status"] => {}
            ["set-telemetry", mode] if matches!(*mode, "local" | "off") => {
                self.select_config_menu_choice(ConfigMenuChoice::Telemetry);
                self.set_active_screen_message(format!(
                    "GPU checks row selected.\n\nNothing changed yet. Use the highlighted row and press Enter to change GPU checks. You asked for: {mode}."
                ));
                self.status = "Telemetry selected. Press Enter to change it.".to_owned();
            }
            ["set-telemetry", ..] => {
                self.select_config_menu_choice(ConfigMenuChoice::Telemetry);
                self.set_active_screen_message(
                    "Choose Telemetry in this settings screen, then press Enter to switch between local GPU checks and off.",
                );
                self.status = "Choose Telemetry from Settings.".to_owned();
            }
            ["set-default-engine", engine] => {
                if engine_inventory()
                    .iter()
                    .any(|(candidate, _)| candidate == engine)
                {
                    self.open_engine_manager();
                    self.select_engine_manager_item(engine);
                    self.set_active_screen_message(format!(
                        "Engine `{engine}` is selected.\n\nNothing changed yet. Use the highlighted row and press Enter to review using this engine."
                    ));
                    self.status = "Engine selected. Press Enter to continue.".to_owned();
                } else {
                    self.open_engine_manager();
                    self.set_active_screen_message(format!(
                        "Unknown engine `{engine}`.\n\nOpen /engine and choose one from the list."
                    ));
                    self.status = "Default engine was not changed.".to_owned();
                }
            }
            ["clear-default-engine"] => {
                self.select_config_menu_choice(ConfigMenuChoice::DefaultEngine);
                self.set_active_screen_message(
                    "Default engine was not changed.\n\nUse the Engine screen to choose the engine you want.",
                );
                self.status = "Choose an engine from the Engine screen.".to_owned();
            }
            ["set-default-runtime", runtime_id] => {
                self.open_runtime_manager();
                if self.select_runtime_manager_item(runtime_id) {
                    self.set_active_screen_message(format!(
                        "ROCm install `{runtime_id}` is selected.\n\nNothing changed yet. Use the highlighted row and press Enter to review using this install."
                    ));
                    self.status = "ROCm install selected. Press Enter to continue.".to_owned();
                } else {
                    self.set_config_default_runtime_if_ready(runtime_id);
                }
            }
            ["clear-default-runtime"] => {
                self.open_runtime_manager();
                self.set_active_screen_message(
                    "Default ROCm install was not changed.\n\nChoose a ROCm install from this list, then press Enter to make it the default.",
                );
                self.status = "Choose a ROCm install from the list.".to_owned();
            }
            ["set-planner-provider", provider]
                if matches!(*provider, "local" | "openai" | "anthropic") =>
            {
                self.select_config_menu_choice(ConfigMenuChoice::PlannerProvider);
                self.set_active_screen_message(format!(
                    "Planning help row selected.\n\nNothing changed yet. Use the highlighted row and press Enter until {provider} is shown."
                ));
                self.status = "Planning help selected. Press Enter to change it.".to_owned();
            }
            ["clear-planner-provider"] => {
                self.select_config_menu_choice(ConfigMenuChoice::PlannerProvider);
                self.set_active_screen_message(
                    "Planning help row selected.\n\nNothing changed yet. Use the highlighted row and press Enter until Off is shown.",
                );
                self.status = "Planning help selected. Press Enter to change it.".to_owned();
            }
            ["enable-provider", provider] if matches!(*provider, "openai" | "anthropic") => {
                self.select_config_provider_choice(provider, ConfigProviderChoice::PromptSending);
                self.set_active_screen_message(format!(
                    "{} prompt sending row selected.\n\nNothing changed yet. Use the highlighted row and press Enter to change it.",
                    provider_label(provider)
                ));
                self.status = "Prompt sending selected. Press Enter to change it.".to_owned();
            }
            ["disable-provider", provider] if matches!(*provider, "openai" | "anthropic") => {
                self.select_config_provider_choice(provider, ConfigProviderChoice::PromptSending);
                self.set_active_screen_message(format!(
                    "{} prompt sending row selected.\n\nNothing changed yet. Use the highlighted row and press Enter to change it.",
                    provider_label(provider)
                ));
                self.status = "Prompt sending selected. Press Enter to change it.".to_owned();
            }
            ["set-provider-key", provider] if matches!(*provider, "openai" | "anthropic") => {
                self.open_config_provider_settings(provider);
                self.start_config_provider_key_edit();
            }
            ["clear-provider-key", provider] if matches!(*provider, "openai" | "anthropic") => {
                self.open_config_provider_settings(provider);
                self.start_clear_config_provider_key_confirmation();
            }
            ["set-engine", ..] => {
                self.set_active_screen_message(
                    "Engine runtime preferences are managed from /engine and /runtimes.",
                );
                self.status = "Use the Engine or Runtimes screen.".to_owned();
            }
            _ => {
                self.set_active_screen_message(
                    "Use arrow keys here for settings.\n\nCommon choices are available on this screen:\n  telemetry\n  default engine\n  default ROCm install\n  planner provider\n  OpenAI and Anthropic settings\n\nTip: press Enter on OpenAI or Anthropic to enable prompt sending, save a key, or clear a saved key.",
                );
                self.status = "Choose a setting from the list.".to_owned();
            }
        }
    }

    fn move_provider_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.provider_manager.as_mut() else {
            return;
        };
        let options = provider_options();
        state.message = None;
        state.selected = match direction {
            CompletionDirection::Next => (state.selected + 1) % options.len(),
            CompletionDirection::Previous => {
                if state.selected == 0 {
                    options.len().saturating_sub(1)
                } else {
                    state.selected - 1
                }
            }
        };
        state.detail_scroll = 0;
        self.status = "Provider selected. Press Enter to use it.".to_owned();
    }

    fn select_provider_by_name(&mut self, provider: &str) -> bool {
        let Some(index) = provider_options()
            .iter()
            .position(|option| option.name == provider)
        else {
            if let Some(state) = self.provider_manager.as_mut() {
                state.message = Some(format!(
                    "Unsupported provider: {provider}\n\nChoose local, anthropic, or openai."
                ));
            }
            self.status = "Provider update failed.".to_owned();
            return false;
        };
        if let Some(state) = self.provider_manager.as_mut() {
            state.selected = index;
            state.message = Some(format!(
                "{} selected.\n\nPress Enter to use this provider for this session.",
                provider_label(provider)
            ));
        }
        self.status = "Provider selected. Press Enter to use it.".to_owned();
        true
    }

    fn use_selected_provider(&mut self) {
        let Some(state) = self.provider_manager.as_mut() else {
            return;
        };
        let option = provider_options()
            .get(state.selected)
            .unwrap_or(&provider_options()[0]);
        self.provider = option.name.to_owned();
        state.message = Some(format!(
            "{} is now the chat provider for this session.",
            option.label
        ));
        self.status = format!("Provider set to {}.", option.label);
    }

    fn open_services_manager(&mut self) {
        self.remember_current_chat_session();
        self.doctor_manager = None;
        self.logs_view = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.command_screen = None;
        let items = load_visible_managed_services(&self.paths);
        self.services_manager = Some(ServicesManagerState {
            items,
            selected: 0,
            last_item_selected: 0,
            detail_scroll: 0,
            message: None,
        });
        self.mode = TuiMode::Act;
        self.status = "Services opened. Use arrow keys, then Enter for logs.".to_owned();
    }

    fn close_services_manager(&mut self) {
        if self.running_job_blocks_screen_close() {
            return;
        }
        self.services_manager = None;
        self.return_to_home_after_surface_close("Services closed.");
    }

    fn refresh_services_manager(&mut self) {
        let selected_id = self
            .services_manager
            .as_ref()
            .and_then(|state| {
                state
                    .items
                    .get(state.selected)
                    .or_else(|| state.items.get(state.last_item_selected))
            })
            .map(|record| record.service_id.clone());
        let message = self
            .services_manager
            .as_ref()
            .and_then(|state| state.message.clone());
        let items = load_visible_managed_services(&self.paths);
        let selected = selected_id
            .and_then(|id| items.iter().position(|record| record.service_id == id))
            .unwrap_or(0)
            .min(items.len().saturating_sub(1));
        self.services_manager = Some(ServicesManagerState {
            items,
            selected,
            last_item_selected: selected,
            detail_scroll: 0,
            message,
        });
        self.status = "Services refreshed.".to_owned();
    }

    fn move_services_manager_selection(&mut self, direction: CompletionDirection) {
        let Some(state) = self.services_manager.as_mut() else {
            return;
        };
        let count = services_manager_choice_count(state);
        if count == 0 {
            self.status = "No managed services found.".to_owned();
            return;
        }
        state.message = None;
        state.selected = cycle_index(state.selected, count, direction);
        if state.selected < state.items.len() {
            state.last_item_selected = state.selected;
        }
        state.detail_scroll = 0;
        self.status = "Service choice selected. Press Enter to continue.".to_owned();
    }

    fn selected_service_record(&self) -> Option<ManagedServiceRecord> {
        self.services_manager
            .as_ref()
            .and_then(|state| state.items.get(state.selected))
            .cloned()
    }

    fn selected_service_target_record(&self) -> Option<ManagedServiceRecord> {
        self.services_manager
            .as_ref()
            .and_then(|state| {
                state
                    .items
                    .get(state.selected)
                    .or_else(|| state.items.get(state.last_item_selected))
            })
            .cloned()
    }

    fn first_ready_builtin_assistant_service(&self) -> Option<ManagedServiceRecord> {
        load_visible_managed_services(&self.paths)
            .into_iter()
            .find(|record| {
                managed_service_is_chat_ready(record) && tui_service_is_builtin_assistant(record)
            })
    }

    fn selected_services_manager_action(&self) -> Option<ServicesManagerAction> {
        let state = self.services_manager.as_ref()?;
        state
            .selected
            .checked_sub(state.items.len())
            .and_then(|index| services_manager_actions(state).get(index).copied())
    }

    fn select_service_by_id(&mut self, service_id: &str) -> bool {
        let Some(state) = self.services_manager.as_mut() else {
            return false;
        };
        if let Some(index) = state
            .items
            .iter()
            .position(|record| record.service_id == service_id)
        {
            state.selected = index;
            state.last_item_selected = index;
            state.message = None;
            self.status = "Service selected. Press Enter to open logs.".to_owned();
            true
        } else {
            state.message = Some(format!("Managed service `{service_id}` was not found."));
            self.status = "Service not found.".to_owned();
            false
        }
    }

    fn open_selected_service_logs(&mut self) {
        if self.running_job_blocks_screen_switch() {
            return;
        }
        let Some(record) = self.selected_service_target_record() else {
            if let Some(state) = self.services_manager.as_mut() {
                state.message =
                    Some("No managed services found. Start one from /serve first.".to_owned());
            }
            self.status = "No managed services found.".to_owned();
            return;
        };
        let detail = render_service_logs_text_for_tui(&self.paths, &record.service_id, false)
            .unwrap_or_else(|error| format!("Service log lookup failed.\n\n{error}"));
        self.open_log_output_card("Service Logs", detail);
    }

    fn open_selected_service_chat(&mut self) {
        if self.running_job_blocks_screen_switch() {
            return;
        }
        let Some(mut record) = self.selected_service_target_record() else {
            if let Some(state) = self.services_manager.as_mut() {
                state.message =
                    Some("No managed services found. Start one from /serve first.".to_owned());
            }
            self.status = "No managed service is selected.".to_owned();
            return;
        };
        if !managed_service_is_chat_ready(&record) {
            if let Some(state) = self.services_manager.as_mut() {
                state.message = Some(match record.status.as_str() {
                    "failed" | "unreachable" | "exited" => {
                        "This server did not start.\n\nOpen logs to see why, or choose Restart selected server after fixing the problem."
                            .to_owned()
                    }
                    _ => {
                        "This server is still starting.\n\nOpen logs to watch progress, or press F5 until it is ready."
                            .to_owned()
                    }
                });
            }
            self.status = match record.status.as_str() {
                "failed" | "unreachable" | "exited" => {
                    "Selected server failed before chat could start.".to_owned()
                }
                _ => "Selected server is not ready for chat yet.".to_owned(),
            };
            return;
        }
        record.canonical_model_id = VALIDATED_LOCAL_ASSISTANT_MODEL.to_owned();
        self.open_local_rocm_tools_chat_session(Some(record));
    }

    fn open_selected_service_details_overlay(&mut self) {
        let Some(record) = self.selected_service_target_record() else {
            if let Some(state) = self.services_manager.as_mut() {
                state.message =
                    Some("No managed service is selected. Start one from /serve first.".to_owned());
            }
            self.status = "No managed service is selected.".to_owned();
            return;
        };
        self.open_detail_overlay("Service Details", managed_service_detail_text(&record));
    }

    fn open_local_rocm_tools_chat_session(&mut self, service: Option<ManagedServiceRecord>) {
        self.provider = "local".to_owned();
        let detail = render_local_rocm_tools_chat_intro(service.as_ref());
        let service_model = service
            .as_ref()
            .map(|record| record.canonical_model_id.clone());
        let service_id = service.as_ref().map(|record| record.service_id.clone());
        let endpoint_url = service.as_ref().map(|record| record.endpoint_url.clone());
        self.open_command_screen("Chat", detail, None, Vec::new());
        if let Some(state) = self.command_screen.as_mut() {
            let mut session = self
                .saved_chat_session
                .clone()
                .unwrap_or_else(|| ChatSessionState {
                    provider: "local".to_owned(),
                    model: service_model.clone(),
                    service_id: service_id.clone(),
                    endpoint_url: endpoint_url.clone(),
                    turns: Vec::new(),
                    pending_install_args: None,
                });
            session.provider = "local".to_owned();
            if service_model.is_some() {
                session.model = service_model;
            }
            if service_id.is_some() || endpoint_url.is_some() {
                session.service_id = service_id;
                session.endpoint_url = endpoint_url.clone();
            }
            state.chat_model = session.model.clone();
            state.chat_tools = true;
            state.chat_session = Some(session);
        }
        self.sync_chat_session_actions();
        self.status = endpoint_url
            .map(|url| format!("Local assistant ready at {url}."))
            .unwrap_or_else(|| "Local assistant ready.".to_owned());
    }

    fn open_local_assistant_start_flow(&mut self, model: Option<String>) {
        self.remember_current_chat_session();
        let model = model.filter(|value| !value.trim().is_empty());
        if let Some(model) = model {
            self.open_serve_wizard_from_plan(ServeCommandPlan {
                model: Some(model),
                engine: Some(default_engine_for_platform().to_owned()),
                device: Some("gpu_required".to_owned()),
                managed: true,
                ..ServeCommandPlan::default()
            });
        } else {
            self.open_serve_wizard();
        }
        if let Some(state) = self.serve_wizard.as_mut() {
            state.message = Some(local_chat_needs_server_message());
        }
        self.status = "Choose a local model, then press Enter on Start.".to_owned();
    }

    fn ready_local_chat_records(&self) -> Vec<ManagedServiceRecord> {
        load_visible_managed_services(&self.paths)
            .into_iter()
            .filter(managed_service_is_chat_ready)
            .collect()
    }

    fn ready_local_chat_record_for_model(
        &self,
        model: Option<&str>,
    ) -> Option<ManagedServiceRecord> {
        let model = model.map(str::trim).filter(|value| !value.is_empty());
        self.ready_local_chat_records()
            .into_iter()
            .find(|record| match model {
                Some(model) => {
                    record.canonical_model_id.eq_ignore_ascii_case(model)
                        || record.model_ref.eq_ignore_ascii_case(model)
                }
                None => record
                    .canonical_model_id
                    .eq_ignore_ascii_case(VALIDATED_LOCAL_ASSISTANT_MODEL),
            })
    }

    fn ready_local_chat_record_for_session(
        &self,
        session: &ChatSessionState,
    ) -> Option<ManagedServiceRecord> {
        let services = self.ready_local_chat_records();
        if let Some(service_id) = session
            .service_id
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            && let Some(record) = services
                .iter()
                .find(|record| record.service_id.eq_ignore_ascii_case(service_id))
        {
            return Some(record.clone());
        }
        if let Some(endpoint_url) = session
            .endpoint_url
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            && let Some(record) = services
                .iter()
                .find(|record| record.endpoint_url.eq_ignore_ascii_case(endpoint_url))
        {
            return Some(record.clone());
        }
        let model = session
            .model
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty());
        services.into_iter().find(|record| match model {
            Some(model) => {
                record.canonical_model_id.eq_ignore_ascii_case(model)
                    || record.model_ref.eq_ignore_ascii_case(model)
            }
            None => record
                .canonical_model_id
                .eq_ignore_ascii_case(VALIDATED_LOCAL_ASSISTANT_MODEL),
        })
    }

    fn local_chat_service_available(&self, model: Option<&str>) -> bool {
        self.ready_local_chat_record_for_model(model).is_some()
    }

    fn handle_managed_serve_completion(&mut self, rendered: &str) {
        let service_id = managed_serve_service_id(rendered);
        if let Some(service_id) = service_id.as_ref() {
            self.tui_owned_service_ids.insert(service_id.clone());
        }
        if let Some(service_id) = service_id.as_deref()
            && let Some(record) = load_managed_services(&self.paths).ok().and_then(|records| {
                records
                    .into_iter()
                    .find(|record| record.service_id == service_id)
            })
            && managed_service_is_chat_ready(&record)
        {
            if self.command_screen_is_chat_session() {
                let endpoint = record.endpoint_url.clone();
                if let Some(state) = self.command_screen.as_mut()
                    && let Some(session) = state.chat_session.as_mut()
                {
                    state.chat_model = Some(record.canonical_model_id.clone());
                    session.model = Some(record.canonical_model_id.clone());
                    session.service_id = Some(record.service_id.clone());
                    session.endpoint_url = Some(record.endpoint_url.clone());
                }
                self.sync_chat_session_actions();
                self.status = format!("Local assistant ready at {endpoint}.");
                return;
            }
            self.open_local_rocm_tools_chat_session(Some(record));
            return;
        }

        self.open_services_manager();
        if let Some(service_id) = service_id.as_deref() {
            self.select_service_by_id(service_id);
        }
        let selected_record = self.selected_service_target_record();
        let selected_status = selected_record
            .as_ref()
            .map(|record| record.status.clone())
            .unwrap_or_default();
        if let Some(state) = self.services_manager.as_mut() {
            state.message = Some(match selected_status.as_str() {
                "failed" | "unreachable" | "exited" => {
                    "Local assistant did not start.\n\nOpen logs for the reason.".to_owned()
                }
                _ => selected_record
                    .as_ref()
                    .map(|record| format!("Starting at {}.", record.endpoint_url))
                    .unwrap_or_else(|| "Local assistant is starting.".to_owned()),
            });
        }
        self.status = match selected_status.as_str() {
            "failed" | "unreachable" | "exited" => {
                "Local assistant failed to start. Open logs for the reason.".to_owned()
            }
            _ => selected_record
                .as_ref()
                .map(|record| format!("Local assistant starting at {}.", record.endpoint_url))
                .unwrap_or_else(|| "Local assistant is starting.".to_owned()),
        };
    }

    fn request_selected_service_lifecycle(&mut self, action: ServiceLifecycleAction) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(record) = self.selected_service_target_record() else {
            if let Some(state) = self.services_manager.as_mut() {
                state.message =
                    Some("No managed services found. Start one from /serve first.".to_owned());
            }
            self.status = "No managed service is selected.".to_owned();
            return;
        };
        if action == ServiceLifecycleAction::Stop && record.status == "stopped" {
            if let Some(state) = self.services_manager.as_mut() {
                state.message = Some("This server is already stopped.".to_owned());
            }
            self.status = "Service is already stopped.".to_owned();
            return;
        }
        self.request_service_lifecycle_action(action, record.service_id);
    }

    fn perform_services_manager_selected_action(&mut self) {
        if let Some(record) = self.selected_service_record() {
            if managed_service_is_chat_ready(&record) {
                self.open_local_rocm_tools_chat_session(Some(record));
            } else {
                self.open_selected_service_logs();
            }
            return;
        }
        match self.selected_services_manager_action() {
            Some(ServicesManagerAction::Details) => self.open_selected_service_details_overlay(),
            Some(ServicesManagerAction::Chat) => self.open_selected_service_chat(),
            Some(ServicesManagerAction::OpenLogs) => self.open_selected_service_logs(),
            Some(ServicesManagerAction::Stop) => {
                self.request_selected_service_lifecycle(ServiceLifecycleAction::Stop)
            }
            Some(ServicesManagerAction::Restart) => {
                self.request_selected_service_lifecycle(ServiceLifecycleAction::Restart)
            }
            Some(ServicesManagerAction::Back) => self.close_services_manager(),
            None => self.open_selected_service_logs(),
        }
    }

    fn request_service_lifecycle_action(
        &mut self,
        action: ServiceLifecycleAction,
        service_id: String,
    ) {
        let args = vec![
            "sandbox-run".to_owned(),
            action.tool_name().to_owned(),
            "--allow-native-fallback".to_owned(),
            "--service-id".to_owned(),
            service_id.clone(),
        ];
        self.request_screen_rocmd_approval(
            &action.approval_title(&service_id),
            "Services",
            args,
            RunningJobKind::ServiceLifecycle { action, service_id },
        );
    }

    fn handle_setup_command(&mut self, args: &[&str]) {
        match args {
            [] | ["status"] => {
                self.onboarding_active = true;
                self.reset_onboarding_selection();
                self.status = "Setup opened. Choose an option, then press Enter.".to_owned();
            }
            ["skip"] => {
                self.onboarding_active = true;
                if setup_venv_ready(&self.paths, &self.config) {
                    self.select_onboarding_choice(OnboardingMenuChoice::Back);
                    self.status = "Setup is ready. Press Enter to return to ROCm CLI.".to_owned();
                } else {
                    self.reset_onboarding_selection();
                    self.status =
                        "Setup is required before local ROCm can run. Press Enter to install ROCm."
                            .to_owned();
                }
            }
            ["reset"] => {
                self.show_setup_again();
            }
            [other, ..] => {
                self.onboarding_active = true;
                self.reset_onboarding_selection();
                self.set_onboarding_setup_error(&format!(
                    "I do not recognize setup option `{other}`. Use the choices below."
                ));
                self.status =
                    format!("I do not recognize setup option `{other}`. Use arrow keys here.");
            }
        }
    }

    fn handle_permissions_command(&mut self, args: &[&str]) {
        match args {
            [] | ["status"] => {
                self.open_command_screen_target(CommandScreenTarget::Permissions);
            }
            ["full-access"] | ["full"] => {
                self.open_command_screen_target(CommandScreenTarget::Permissions);
                if self.config.permissions.full_access_enabled() {
                    self.status = "Full access is already on.".to_owned();
                } else {
                    self.pending_approval = Some(PendingApproval {
                        title: "Full Access".to_owned(),
                        selected: 0,
                        detail_scroll: 0,
                        action: ApprovalAction::EnableFullAccess,
                    });
                    self.status =
                        "Confirm full access with Enter/Y, or cancel with Esc/N.".to_owned();
                }
            }
            ["ask"] | ["reset"] => {
                self.open_command_screen_target(CommandScreenTarget::Permissions);
                if let Some(state) = self.command_screen.as_mut() {
                    if let Some(index) = state
                        .actions
                        .iter()
                        .position(|action| *action == CommandScreenAction::ResetPermissions)
                    {
                        state.selected = index;
                        state.message = Some(
                            "Press Enter to go back to asking before setup actions run.".to_owned(),
                        );
                        self.status =
                            "Reset permissions selected. Press Enter to apply.".to_owned();
                    } else {
                        state.message =
                            Some("Permissions are already set to ask first.".to_owned());
                        self.status = "Permissions already ask first.".to_owned();
                    }
                }
            }
            [other, ..] => {
                self.open_command_screen(
                    "Permissions",
                    format!(
                        "I do not recognize permissions option `{other}`.\n\nUse the choices on the left to allow full access or go back to asking first."
                    ),
                    Some(CommandScreenTarget::Permissions),
                    self.command_screen_actions_for_target(CommandScreenTarget::Permissions),
                );
                self.status = "Permissions option was not recognized.".to_owned();
            }
        }
    }

    fn close_onboarding(&mut self) {
        self.onboarding_active = false;
        self.pending_approval = None;
        self.onboarding_selection = 0;
        self.onboarding_path_editing = false;
        self.onboarding_success_modal = false;
        self.clear_input();
        self.status = "Setup closed.".to_owned();
    }

    fn return_from_onboarding(&mut self) {
        if setup_venv_ready(&self.paths, &self.config) {
            self.finish_onboarding();
        } else if self.config.onboarding_dismissed {
            self.close_onboarding();
        } else {
            self.onboarding_active = true;
            self.reset_onboarding_selection();
            self.status = "Finish setup to continue, or choose Quit setup.".to_owned();
        }
    }

    fn finish_onboarding(&mut self) {
        self.config.onboarding_dismissed = true;
        self.reconcile_onboarding_engine_preference();
        match self.config.save(&self.paths) {
            Ok(()) => {
                self.onboarding_active = false;
                self.pending_approval = None;
                self.onboarding_selection = 0;
                self.onboarding_path_editing = false;
                self.onboarding_success_modal = false;
                self.clear_input();
                self.reset_main_transcript();
                self.status = "Setup complete. ROCm CLI is ready.".to_owned();
            }
            Err(error) => {
                self.onboarding_success_modal = false;
                self.set_onboarding_setup_error(&format!(
                    "Setup completion could not be saved: {error}"
                ));
                self.status = "Setup completion could not be saved.".to_owned();
            }
        }
    }

    fn onboarding_action(&self) -> OnboardingAction {
        if setup_venv_ready(&self.paths, &self.config) {
            OnboardingAction::Finish
        } else {
            OnboardingAction::InstallSdk
        }
    }

    fn onboarding_choice_count(&self) -> usize {
        onboarding_menu_choices(self).len()
    }

    fn reset_onboarding_selection(&mut self) {
        self.onboarding_selection = onboarding_default_selection(self);
    }

    fn move_onboarding_cancel_install_selection(&mut self, direction: CompletionDirection) {
        let count = onboarding_cancel_install_choices().len();
        if count <= 1 {
            self.onboarding_cancel_install_selection = 0;
            return;
        }
        self.onboarding_cancel_install_selection = cycle_index(
            self.onboarding_cancel_install_selection
                .min(count.saturating_sub(1)),
            count,
            direction,
        );
        self.status = onboarding_cancel_install_status(self.onboarding_cancel_install_selection);
    }

    fn perform_onboarding_cancel_install_selection(&mut self) {
        match self.onboarding_cancel_install_selection {
            0 => self.keep_waiting_for_onboarding_install(),
            _ => self.cancel_onboarding_install(),
        }
    }

    fn select_onboarding_choice(&mut self, choice: OnboardingMenuChoice) {
        if let Some(index) = onboarding_menu_choices(self)
            .iter()
            .position(|candidate| *candidate == choice)
        {
            self.onboarding_selection = index;
        }
    }

    fn selected_onboarding_choice(&self) -> OnboardingMenuChoice {
        onboarding_selected_choice(self)
    }

    fn move_onboarding_selection(&mut self, direction: CompletionDirection) {
        let count = self.onboarding_choice_count();
        if count <= 1 {
            self.onboarding_selection = 0;
            return;
        }
        self.onboarding_selection = match direction {
            CompletionDirection::Next => (self.onboarding_selection + 1) % count,
            CompletionDirection::Previous => {
                if self.onboarding_selection == 0 {
                    count - 1
                } else {
                    self.onboarding_selection - 1
                }
            }
        };
        self.status = onboarding_selection_status(self);
    }

    fn start_onboarding_path_edit(&mut self) {
        if self.pending_approval.is_some() || self.running_job.is_some() {
            return;
        }
        self.onboarding_path_editing = true;
        self.set_input(
            setup_install_root(&self.paths, &self.config)
                .display()
                .to_string(),
        );
        self.status = "Type a folder for ROCm, then press Enter.".to_owned();
    }

    fn commit_onboarding_path_edit(&mut self) {
        let value = self.input.trim();
        let path = match validate_onboarding_install_folder(value) {
            Ok(path) => path,
            Err(error) => {
                self.status = error.to_string();
                return;
            }
        };
        self.config.setup.therock_venv = Some(path);
        match self.config.save(&self.paths) {
            Ok(()) => {
                self.rebase_paths_to_saved_setup_folder();
                self.onboarding_path_editing = false;
                self.clear_input();
                self.select_onboarding_choice(OnboardingMenuChoice::Primary);
                self.status = "ROCm folder saved. Press Enter to install.".to_owned();
            }
            Err(error) => {
                self.status = "ROCm folder could not be saved.".to_owned();
                self.set_onboarding_setup_error(&format!(
                    "ROCm folder could not be saved: {error}"
                ));
            }
        }
    }

    fn cancel_onboarding_path_edit(&mut self) {
        self.onboarding_path_editing = false;
        self.onboarding_cancel_install_confirm = false;
        self.clear_input();
        self.status = "ROCm folder unchanged.".to_owned();
    }

    fn cycle_onboarding_folder_preset(&mut self, direction: CompletionDirection) {
        if self.pending_approval.is_some() || self.running_job.is_some() {
            return;
        }
        self.select_onboarding_choice(OnboardingMenuChoice::Folder);
        let presets = onboarding_folder_presets(&self.paths, &self.config);
        if presets.len() <= 1 {
            self.status = "Press Enter to choose another install folder.".to_owned();
            return;
        }
        let current = setup_install_root(&self.paths, &self.config);
        let current_key = onboarding_folder_preset_key(&current);
        let current_index = presets
            .iter()
            .position(|path| onboarding_folder_preset_key(path) == current_key)
            .unwrap_or(0);
        let next_index = cycle_index(current_index, presets.len(), direction);
        let next_path = presets[next_index].clone();
        self.config.setup.therock_venv = Some(next_path);
        match self.config.save(&self.paths) {
            Ok(()) => {
                self.rebase_paths_to_saved_setup_folder();
                self.onboarding_setup_error = None;
                self.status =
                    "Install folder changed. Press Left/Right for another, or Down to install."
                        .to_owned();
            }
            Err(error) => {
                self.onboarding_setup_error =
                    Some(format!("Install folder could not be saved: {error}"));
                self.status = "Install folder could not be saved.".to_owned();
            }
        }
    }

    fn open_onboarding_install_folder_browser(&mut self) {
        if self.pending_approval.is_some() || self.running_job.is_some() {
            return;
        }
        self.open_folder_browser(
            "Choose ROCm Folder",
            "Pick where ROCm/TheRock should be installed.",
            FolderBrowserContext::OnboardingInstallFolder,
        );
    }

    fn onboarding_install_running(&self) -> bool {
        self.onboarding_active
            && self
                .running_job
                .as_ref()
                .is_some_and(|job| matches!(job.title.as_str(), "Install" | "Reinstall"))
    }

    fn request_onboarding_install_cancel(&mut self) {
        self.onboarding_cancel_install_confirm = true;
        self.onboarding_cancel_install_selection = 0;
        self.status = "ROCm is still installing. Choose what to do.".to_owned();
    }

    fn keep_waiting_for_onboarding_install(&mut self) {
        self.onboarding_cancel_install_confirm = false;
        self.onboarding_cancel_install_selection = 0;
        self.status = "Still installing ROCm. Progress is shown in the install card.".to_owned();
    }

    fn cancel_onboarding_install(&mut self) {
        let Some(cancel_requested) = self.running_job_cancel_requested.as_ref() else {
            self.onboarding_cancel_install_confirm = false;
            self.onboarding_cancel_install_selection = 0;
            return;
        };
        cancel_requested.store(true, Ordering::SeqCst);
        self.onboarding_cancel_install_confirm = false;
        self.onboarding_cancel_install_selection = 0;
        self.push_onboarding_install_log("Stopping installer...");
        self.status = "Stopping ROCm install...".to_owned();
    }

    fn reset_onboarding_install_output(&mut self) {
        self.onboarding_install_log.clear();
        self.onboarding_install_log_scroll = 0;
        self.onboarding_install_failure = None;
        self.onboarding_setup_error = None;
        self.onboarding_install_full_log = None;
        self.onboarding_show_log_location = false;
        self.onboarding_cancel_install_confirm = false;
        self.onboarding_cancel_install_selection = 0;
    }

    fn push_onboarding_install_log(&mut self, line: &str) {
        let line = sanitize_terminal_text(line).replace(['\r', '\n'], " ");
        let line = truncate_stream_line(line.trim());
        if line.is_empty() {
            return;
        }
        let following_live_output =
            self.onboarding_install_log_scroll == 0 && self.running_job_log_scroll == 0;
        self.onboarding_install_log.push_back(line);
        if following_live_output {
            self.onboarding_install_log_scroll = 0;
            self.running_job_log_scroll = 0;
        } else {
            self.onboarding_install_log_scroll =
                self.onboarding_install_log_scroll.saturating_add(1);
            self.running_job_log_scroll = self.running_job_log_scroll.saturating_add(1);
        }
        while self.onboarding_install_log.len() > 80 {
            self.onboarding_install_log.pop_front();
        }
    }

    fn scroll_onboarding_install_log(&mut self, direction: LogPageDirection) {
        let len = self.onboarding_scrollable_log_len();
        if len == 0 {
            self.status = if self.onboarding_show_log_location {
                "No saved setup log output to scroll.".to_owned()
            } else {
                "No installer output to scroll yet.".to_owned()
            };
            return;
        }
        let max_offset = len.saturating_sub(1);
        self.onboarding_install_log_scroll = match direction {
            LogPageDirection::Previous => self
                .onboarding_install_log_scroll
                .saturating_add(8)
                .min(max_offset),
            LogPageDirection::Next => self.onboarding_install_log_scroll.saturating_sub(8),
            LogPageDirection::Refresh => 0,
        };
    }

    fn scroll_onboarding_install_log_by(&mut self, lines: i16) {
        let len = self.onboarding_scrollable_log_len();
        if len == 0 {
            self.status = if self.onboarding_show_log_location {
                "No saved setup log output to scroll.".to_owned()
            } else {
                "No installer output to scroll yet.".to_owned()
            };
            return;
        }
        let max_offset = len.saturating_sub(1);
        if lines.is_negative() {
            self.onboarding_install_log_scroll = self
                .onboarding_install_log_scroll
                .saturating_add(usize::from(lines.unsigned_abs()))
                .min(max_offset);
        } else {
            self.onboarding_install_log_scroll = self
                .onboarding_install_log_scroll
                .saturating_sub(lines as usize);
        }
    }

    fn scroll_running_job_log(&mut self, lines: i16) {
        let len = running_job_output_line_count(self);
        if len == 0 {
            self.status = "No live output to scroll yet.".to_owned();
            return;
        }
        let max_offset = self.running_job_log_max_offset();
        if self.onboarding_install_running() {
            self.onboarding_install_log_scroll =
                scroll_latest_offset_by(self.onboarding_install_log_scroll, lines, max_offset);
            self.running_job_log_scroll = self.onboarding_install_log_scroll;
        } else {
            self.running_job_log_scroll =
                scroll_latest_offset_by(self.running_job_log_scroll, lines, max_offset);
        }
    }

    fn running_job_log_max_offset(&self) -> usize {
        running_job_output_visual_line_count(self, 8).saturating_sub(1)
    }

    fn onboarding_scrollable_log_len(&self) -> usize {
        if self.onboarding_show_log_location
            && let Some(path) = self.onboarding_install_full_log.as_ref()
            && let Some(len) = saved_onboarding_log_line_count(path)
        {
            return len;
        }
        self.onboarding_install_log.len()
    }

    fn toggle_onboarding_log_file(&mut self) {
        let Some(path) = self.onboarding_install_full_log.as_ref() else {
            self.status = "No saved setup log yet.".to_owned();
            return;
        };
        let detail = render_saved_onboarding_log_card(path);
        self.overlay_card = Some(OverlayCardState {
            title: "Saved Setup Log".to_owned(),
            detail,
            selected: 0,
            detail_scroll: 0,
            actions: Vec::new(),
        });
        self.onboarding_show_log_location = false;
        self.onboarding_install_log_scroll = 0;
        self.status = "Saved setup log opened. Press Esc to close it.".to_owned();
    }

    fn push_onboarding_install_rendered_output(&mut self, rendered: &str) {
        for line in rendered.lines() {
            let trimmed = line.trim();
            if trimmed.is_empty()
                || trimmed == "stdout:"
                || trimmed == "stderr:"
                || trimmed.starts_with("command:")
                || trimmed.starts_with("status:")
                || trimmed.starts_with("streamed_")
            {
                continue;
            }
            self.push_onboarding_install_log(trimmed);
        }
    }

    fn write_onboarding_install_full_log(&mut self, rendered: &str) {
        match write_onboarding_install_full_log(&self.paths, rendered) {
            Ok(path) => {
                self.onboarding_install_full_log = Some(path);
            }
            Err(error) => {
                self.push_onboarding_install_log(&format!("full log could not be saved: {error}"));
            }
        }
    }

    fn perform_onboarding_primary_action(&mut self) {
        self.refresh_config();
        match self.onboarding_action() {
            OnboardingAction::InstallSdk => {
                let title = if setup_has_current_install(&self.paths, &self.config) {
                    "Reinstall"
                } else {
                    "Install"
                };
                self.request_onboarding_install(title);
            }
            OnboardingAction::Finish => self.finish_onboarding(),
        }
    }

    fn request_onboarding_install(&mut self, title: &str) {
        self.reset_onboarding_install_output();
        self.rebase_paths_to_saved_setup_folder();
        let mut args = vec![
            "install".to_owned(),
            "sdk".to_owned(),
            "--channel".to_owned(),
            "release".to_owned(),
            "--format".to_owned(),
            "wheel".to_owned(),
        ];
        let venv_path = setup_install_root(&self.paths, &self.config);
        args.push("--prefix".to_owned());
        args.push(venv_path.display().to_string());
        let mut display_command =
            "/install sdk --channel release --format wheel --prefix ".to_owned();
        display_command.push_str(&quote_tui_arg(&venv_path.display().to_string()));
        let reason = if title == "Reinstall" {
            "Reinstall ROCm into the selected folder."
        } else {
            "Install ROCm into the selected folder."
        };
        self.request_cli_approval_with_display(title, args, reason, display_command);
        self.reset_onboarding_selection();
    }

    fn request_onboarding_reinstall(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        self.request_onboarding_install("Reinstall");
        self.status = "Review reinstall, then press Enter to start.".to_owned();
    }

    fn request_onboarding_uninstall(&mut self) {
        if self.running_job_blocks_action() {
            return;
        }
        let Some(runtime) = current_setup_runtime(&self.paths, &self.config) else {
            self.set_onboarding_setup_error(
                "I could not find the saved ROCm install to uninstall.",
            );
            self.status = "ROCm install was not found.".to_owned();
            return;
        };
        let Some(runtime_key) = runtime.runtime_key.as_deref() else {
            self.set_onboarding_setup_error(
                "This ROCm install is missing its saved install id. Open ROCm Installs to repair it.",
            );
            self.status = "ROCm install needs repair before uninstall.".to_owned();
            return;
        };
        if let Err(error) = ensure_setup_runtime_registered(&self.paths, &runtime) {
            self.set_onboarding_setup_error(&format!(
                "I found this ROCm install, but could not prepare uninstall: {error}"
            ));
            self.status = "ROCm uninstall needs repair.".to_owned();
            return;
        }
        self.reset_onboarding_install_output();
        self.request_cli_approval_with_display(
            "Uninstall",
            vec![
                "runtimes".to_owned(),
                "uninstall".to_owned(),
                runtime_key.to_owned(),
            ],
            "Uninstall the current ROCm install.",
            format!("/runtimes uninstall {}", quote_tui_arg(runtime_key)),
        );
        self.reset_onboarding_selection();
        self.status = "Review uninstall, then press Enter to remove ROCm.".to_owned();
    }

    fn perform_onboarding_selected_action(&mut self) {
        match self.selected_onboarding_choice() {
            OnboardingMenuChoice::Folder if self.pending_approval.is_none() => {
                self.open_onboarding_install_folder_browser()
            }
            OnboardingMenuChoice::Primary if self.pending_approval.is_some() => {
                self.approve_focused_action();
                self.reset_onboarding_selection();
            }
            OnboardingMenuChoice::Primary if self.running_job.is_none() => {
                self.perform_onboarding_primary_action()
            }
            OnboardingMenuChoice::Reinstall if self.pending_approval.is_none() => {
                self.request_onboarding_reinstall()
            }
            OnboardingMenuChoice::Uninstall if self.pending_approval.is_none() => {
                self.request_onboarding_uninstall()
            }
            OnboardingMenuChoice::ShowLog if self.pending_approval.is_none() => {
                self.toggle_onboarding_log_file()
            }
            OnboardingMenuChoice::Back if self.pending_approval.is_some() => {
                self.cancel_focused_action();
                self.reset_onboarding_selection();
            }
            OnboardingMenuChoice::Back if self.running_job.is_none() => {
                self.return_from_onboarding()
            }
            OnboardingMenuChoice::Quit if self.running_job.is_none() => {
                self.request_quit_overlay_or_wait()
            }
            _ => {}
        }
    }

    fn reconcile_onboarding_engine_preference(&mut self) {
        let Some(engine) = self.config.default_engine.clone() else {
            return;
        };
        let Some(env_id) = ready_engine_env_id(&self.paths, &self.config, &engine) else {
            return;
        };
        let engine_config = self.config.engine_config_mut(&engine);
        engine_config.preferred_env_id = Some(env_id);
        engine_config.preferred_runtime_id = None;
    }

    fn refresh_sidebar_state(&mut self) {
        self.refresh_config();
        if self.onboarding_active {
            self.poll_running_job();
            return;
        }
        if self.config.telemetry.local_inspection_enabled() {
            self.gpu_telemetry.maybe_refresh();
        } else {
            self.gpu_telemetry.clear();
        }
        self.poll_running_job();
        self.refresh_following_logs();
    }

    fn sidebar_text(&self) -> String {
        let mut output = render_sidebar_text(
            &self.paths,
            &self.config,
            &self.provider,
            setup_runtime_ready_for_sidebar(&self.paths, &self.config),
        );
        let gpu_text = if self.config.telemetry.local_inspection_enabled() {
            self.gpu_telemetry.sidebar_text()
        } else {
            disabled_gpu_telemetry_text(&self.config)
        };
        if !gpu_text.is_empty() {
            output.push_str("\n\n");
            output.push_str(&gpu_text);
        }
        output
    }

    fn paste_text(&mut self, text: &str) {
        if self.pending_approval.is_some() {
            self.clear_input();
            self.status = "Review card is open. Use arrows, Enter/Y, N, or Esc.".to_owned();
            return;
        }
        let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
        for ch in normalized.chars() {
            if ch == '\n' {
                self.submit();
            } else {
                self.insert_input_char(ch);
            }
        }
    }

    #[allow(dead_code)]
    fn push_user_input(&mut self, input: &str) {
        self.home_dashboard_visible = false;
        self.transcript.push(TranscriptLine::user_input(input));
        self.transcript.push(TranscriptLine::blank());
        self.record_activity(format!("input: {input}"));
        self.trim_transcript();
        self.scroll_to_bottom();
    }

    fn push_block(&mut self, title: &str, body: &str) {
        if title != "Welcome" {
            self.home_dashboard_visible = false;
        }
        let block_start = self.transcript.len();
        self.transcript.push(TranscriptLine::block_header(title));
        self.transcript.extend(
            body.lines()
                .map(|line| TranscriptLine::block_body(title, line)),
        );
        self.transcript.push(TranscriptLine::blank());
        let drained = self.trim_transcript();
        self.scroll_to_line(block_start.saturating_sub(drained));
    }

    fn trim_transcript(&mut self) -> usize {
        const MAX_LINES: usize = 800;
        if self.transcript.len() > MAX_LINES {
            let drain = self.transcript.len() - MAX_LINES;
            self.transcript.drain(0..drain);
            self.transcript_scroll = self.transcript_scroll.saturating_sub(drain as u16);
            drain
        } else {
            0
        }
    }

    fn transcript_text(&self) -> String {
        if self.transcript.is_empty() {
            "No activity yet.".to_owned()
        } else {
            self.transcript.join("\n")
        }
    }

    fn should_draw_home_dashboard(&self) -> bool {
        self.home_dashboard_visible
            && !self.onboarding_active
            && self.doctor_manager.is_none()
            && self.logs_view.is_none()
            && self.runtime_manager.is_none()
            && self.install_manager.is_none()
            && self.engine_manager.is_none()
            && self.model_picker.is_none()
            && self.serve_wizard.is_none()
            && self.update_manager.is_none()
            && self.automations_manager.is_none()
            && self.provider_manager.is_none()
            && self.config_manager.is_none()
            && self.services_manager.is_none()
            && self.command_screen.is_none()
    }

    fn max_scroll(&self) -> u16 {
        if let Ok((terminal_width, terminal_height)) = size() {
            let area = main_content_area(self, terminal_width, terminal_height);
            return self.transcript_max_scroll_for_area(area);
        }
        self.transcript
            .len()
            .saturating_sub(1)
            .min(u16::MAX as usize) as u16
    }

    fn transcript_max_scroll_for_area(&self, area: Rect) -> u16 {
        text_scroll_metrics(
            &self.transcript_text(),
            area.width.saturating_sub(2).max(1) as usize,
            area.height.saturating_sub(2).max(1) as usize,
            u16::MAX,
        )
        .offset_u16()
    }

    fn scroll_to_bottom(&mut self) {
        self.transcript_scroll = self.max_scroll();
    }

    fn scroll_to_line(&mut self, line: usize) {
        self.transcript_scroll = line.min(u16::MAX as usize) as u16;
    }

    fn clear_transcript(&mut self) {
        self.transcript.clear();
        self.transcript_scroll = 0;
        self.home_dashboard_visible = true;
        self.home_selection = 0;
        self.status = "Transcript cleared.".to_owned();
        self.record_activity("transcript cleared");
    }

    fn open_home_dashboard(&mut self) {
        if self.pending_approval.is_some() {
            self.status = "Finish the approval first, or press Esc to cancel it.".to_owned();
            return;
        }
        if self.running_job_blocks_screen_switch() {
            return;
        }
        self.doctor_manager = None;
        self.logs_view = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        self.command_screen = None;
        self.home_dashboard_visible = true;
        self.home_selection = self
            .home_selection
            .min(home_dashboard_actions(self).len().saturating_sub(1));
        self.status = "Home opened. Use arrow keys, then Enter.".to_owned();
    }

    fn return_to_home_after_surface_close(&mut self, status: impl Into<String>) {
        self.clear_input();
        self.home_dashboard_visible = true;
        self.home_selection = self
            .home_selection
            .min(home_dashboard_actions(self).len().saturating_sub(1));
        self.status = status.into();
    }

    fn selected_home_dashboard_action(&self) -> Option<HomeDashboardAction> {
        let actions = home_dashboard_actions(self);
        actions
            .get(self.home_selection.min(actions.len().saturating_sub(1)))
            .copied()
    }

    fn move_home_dashboard_selection(&mut self, direction: CompletionDirection) {
        let count = home_dashboard_actions(self).len();
        if count <= 1 {
            self.home_selection = 0;
            return;
        }
        self.home_selection = match direction {
            CompletionDirection::Next => (self.home_selection + 1) % count,
            CompletionDirection::Previous => {
                if self.home_selection == 0 {
                    count - 1
                } else {
                    self.home_selection - 1
                }
            }
        };
        if let Some(action) = self.selected_home_dashboard_action() {
            self.status = home_dashboard_action_status(action).to_owned();
        }
    }

    fn perform_home_dashboard_action(&mut self) {
        let Some(action) = self.selected_home_dashboard_action() else {
            self.status = "Choose an action first.".to_owned();
            return;
        };
        if action == HomeDashboardAction::Quit {
            self.request_quit_overlay_or_wait();
            return;
        }
        if action == HomeDashboardAction::Help {
            self.open_interactive_help_overlay();
            return;
        }
        let command = home_dashboard_action_command(action);
        self.handle_command(command);
    }

    fn record_activity(&mut self, message: impl Into<String>) {
        let message = truncate_activity_message(message.into());
        self.activity_log.push_back(message);
        while self.activity_log.len() > MAX_ACTIVITY_LOG_ITEMS {
            self.activity_log.pop_front();
        }
    }

    #[cfg(test)]
    fn activity_text(&self) -> String {
        if self.activity_log.is_empty() {
            "No activity yet.".to_owned()
        } else {
            self.activity_log
                .iter()
                .rev()
                .map(String::as_str)
                .collect::<Vec<_>>()
                .join("\n")
        }
    }

    fn refresh_status(&mut self) {
        self.refresh_config();
        if self.config.telemetry.local_inspection_enabled() {
            self.gpu_telemetry.force_refresh();
            self.status = "Status refreshed.".to_owned();
        } else {
            self.gpu_telemetry.clear();
            self.status = "Status refreshed; GPU local checks are turned off.".to_owned();
        }
        self.record_activity("status refreshed");
    }

    fn open_command_screen_target(&mut self, target: CommandScreenTarget) {
        let (title, detail) = self.render_command_screen_target(target, false);
        self.open_command_screen(
            title,
            detail,
            Some(target),
            self.command_screen_actions_for_target(target),
        );
    }

    fn open_command_screen(
        &mut self,
        title: impl Into<String>,
        detail: impl Into<String>,
        refresh_target: Option<CommandScreenTarget>,
        actions: Vec<CommandScreenAction>,
    ) {
        self.remember_current_chat_session();
        self.command_screen_last_area.set(None);
        self.overlay_card = None;
        self.doctor_manager = None;
        self.logs_view = None;
        self.runtime_manager = None;
        self.install_manager = None;
        self.engine_manager = None;
        self.model_picker = None;
        self.serve_wizard = None;
        self.update_manager = None;
        self.automations_manager = None;
        self.provider_manager = None;
        self.config_manager = None;
        self.services_manager = None;
        let title = title.into();
        self.command_screen = Some(CommandScreenState {
            title: title.clone(),
            detail: detail.into(),
            selected: 0,
            detail_scroll: 0,
            detail_modal: None,
            refresh_target,
            actions,
            plan_request: None,
            plan_action: None,
            chat_prompt: None,
            chat_tools: false,
            chat_model: None,
            chat_session: None,
            message: None,
        });
        self.status = format!("{title} opened. Use arrow keys, then Enter.");
    }

    fn remember_current_chat_session(&mut self) {
        if let Some(session) = self
            .command_screen
            .as_ref()
            .and_then(|state| state.chat_session.clone())
        {
            self.saved_chat_session = Some(session);
        }
    }

