fn status_sidebar_width(total_width: u16) -> u16 {
    if total_width < 100 {
        return total_width / 3;
    }
    (total_width / 3)
        .clamp(42, 64)
        .min(total_width.saturating_sub(60))
}

fn input_viewport(input: &str, cursor: usize, width: u16) -> (String, u16) {
    let width = usize::from(width);
    if width == 0 {
        return (String::new(), 0);
    }
    let chars = input.chars().collect::<Vec<_>>();
    let total = chars.len();
    let cursor = cursor.min(total);
    if total <= width {
        return (input.to_owned(), cursor.min(width.saturating_sub(1)) as u16);
    }

    let mut start = if cursor >= width {
        cursor + 1 - width
    } else {
        0
    };
    if start + width > total {
        start = total.saturating_sub(width);
    }
    let end = (start + width).min(total);
    let visible = chars[start..end].iter().collect::<String>();
    let cursor_column = cursor.saturating_sub(start).min(width.saturating_sub(1));
    (visible, cursor_column as u16)
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct ScrollMetrics {
    content_len: usize,
    viewport_len: usize,
    offset: usize,
}

impl ScrollMetrics {
    fn max_offset(self) -> usize {
        self.content_len.saturating_sub(self.viewport_len)
    }

    fn offset_u16(self) -> u16 {
        self.offset.min(u16::MAX as usize) as u16
    }

    fn should_draw(self) -> bool {
        self.content_len > self.viewport_len
    }
}

fn scroll_metrics(
    content_len: usize,
    viewport_len: usize,
    requested_offset: usize,
) -> ScrollMetrics {
    let viewport_len = viewport_len.max(1);
    let content_len = content_len.max(1);
    let max_offset = content_len.saturating_sub(viewport_len);
    ScrollMetrics {
        content_len,
        viewport_len,
        offset: requested_offset.min(max_offset),
    }
}

fn text_scroll_metrics(
    text: &str,
    content_width: usize,
    viewport_height: usize,
    requested_offset: u16,
) -> ScrollMetrics {
    let content_len = paragraph_visual_line_count(text, content_width);
    let viewport_height = scrollable_text_viewport_len(content_len, viewport_height);
    scroll_metrics(content_len, viewport_height, usize::from(requested_offset))
}

fn styled_text_scroll_metrics(
    text: &Text<'_>,
    content_width: usize,
    viewport_height: usize,
    requested_offset: u16,
) -> ScrollMetrics {
    let content_len = styled_text_visual_line_count(text, content_width);
    let viewport_height = scrollable_text_viewport_len(content_len, viewport_height);
    scroll_metrics(content_len, viewport_height, usize::from(requested_offset))
}

fn scrollable_text_viewport_len(content_len: usize, viewport_height: usize) -> usize {
    let viewport_height = viewport_height.max(1);
    if content_len > viewport_height {
        viewport_height.saturating_sub(1).max(1)
    } else {
        viewport_height
    }
}

fn scroll_latest_offset_by(current: usize, lines: i16, max_offset: usize) -> usize {
    let current = current.min(max_offset);
    if lines.is_negative() {
        current
            .saturating_add(usize::from(lines.unsigned_abs()))
            .min(max_offset)
    } else {
        current.saturating_sub(lines as usize)
    }
}

fn draw_scrollbar(frame: &mut Frame<'_>, area: Rect, metrics: ScrollMetrics) {
    if area.width == 0 || area.height == 0 || !metrics.should_draw() {
        return;
    }
    let mut scrollbar_state = ScrollbarState::new(metrics.max_offset().saturating_add(1))
        .position(metrics.offset)
        .viewport_content_length(metrics.viewport_len);
    frame.render_stateful_widget(
        Scrollbar::default().orientation(ScrollbarOrientation::VerticalRight),
        area,
        &mut scrollbar_state,
    );
}

fn draw_completion_menu(frame: &mut Frame<'_>, menu: &CompletionMenu, area: Rect) {
    if area.width == 0 || area.height < 2 {
        return;
    }
    let (visible_start, visible_end) = completion_visible_range(menu);
    let items = menu
        .items
        .iter()
        .enumerate()
        .skip(visible_start)
        .take(visible_end.saturating_sub(visible_start))
        .map(|(index, item)| {
            let style = if menu
                .replacements
                .get(index)
                .is_some_and(|replacement| replacement.is_some())
            {
                Style::default()
            } else {
                Style::default().fg(Color::DarkGray)
            };
            ListItem::new(item.as_str()).style(style)
        })
        .collect::<Vec<_>>();
    let mut state = ListState::default();
    if menu
        .replacements
        .get(menu.selected)
        .is_some_and(|replacement| replacement.is_some())
    {
        state.select(Some(menu.selected.saturating_sub(visible_start)));
    }
    let completions = List::new(items)
        .block(
            Block::default()
                .borders(Borders::ALL)
                .title(menu.title.clone())
                .border_style(Style::default().fg(THEME_ACCENT)),
        )
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
        .highlight_symbol("> ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(completions, area, &mut state);
    let visible_len = visible_end.saturating_sub(visible_start);
    draw_scrollbar(
        frame,
        area,
        scroll_metrics(menu.items.len(), visible_len.max(1), visible_start),
    );
}

fn centered_size_rect(width: u16, height: u16, area: Rect) -> Rect {
    let width = width.min(area.width);
    let height = height.min(area.height);
    Rect {
        x: area.x.saturating_add(area.width.saturating_sub(width) / 2),
        y: area
            .y
            .saturating_add(area.height.saturating_sub(height) / 2),
        width,
        height,
    }
}

fn draw_command_prompt_popup(
    frame: &mut Frame<'_>,
    app: &App,
    area: Rect,
    completion_menu: Option<&CompletionMenu>,
) {
    if area.width < 12 || area.height < 8 {
        return;
    }
    let completion_height = completion_menu
        .map(|menu| menu.items.len().min(MAX_COMPLETION_MENU_ITEMS) as u16 + 2)
        .unwrap_or(0);
    let wanted_width = area.width.saturating_sub(4).min(96).max(48.min(area.width));
    let wanted_height = completion_height
        .saturating_add(6)
        .min(area.height.saturating_sub(2).max(8))
        .max(7);
    let modal = centered_size_rect(wanted_width, wanted_height, area);
    draw_modal_clear(frame, modal, area);
    let block = surface_block(" Command ", THEME_ACCENT);
    let inner = block.inner(modal);
    frame.render_widget(block, modal);

    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(completion_height),
            Constraint::Length(3),
            Constraint::Length(1),
        ])
        .split(inner);
    if let Some(menu) = completion_menu {
        draw_completion_menu(frame, menu, rows[0]);
    }

    let input_inner_width = rows[1].width.saturating_sub(2);
    let (visible_input, visible_cursor) =
        input_viewport(&app.input, app.input_cursor, input_inner_width);
    let input = Paragraph::new(visible_input)
        .block(surface_block("Run a / command", THEME_ACCENT))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3));
    frame.render_widget(input, rows[1]);
    let hint = Paragraph::new("Tab suggestions | Enter run | Esc close")
        .style(Style::default().fg(THEME_MUTED).bg(THEME_PANEL_3));
    frame.render_widget(hint, rows[2]);
    frame.set_cursor_position((
        rows[1]
            .x
            .saturating_add(1)
            .saturating_add(visible_cursor)
            .min(rows[1].right().saturating_sub(2)),
        rows[1].y.saturating_add(1),
    ));
}

fn chat_input_area_height(app: &App, terminal_width: u16, terminal_height: u16) -> u16 {
    if !app.command_screen_is_chat_session() || app.input.is_empty() {
        return 3;
    }
    let inner_width = terminal_width.saturating_sub(2).max(1) as usize;
    let wanted = chat_input_visual_line_count(&app.input, app.input_cursor, inner_width)
        .min(6)
        .saturating_add(2) as u16;
    let max_height = terminal_height.saturating_sub(10).clamp(3, 8);
    wanted.max(3).min(max_height)
}

fn mouse_over_chat_input(app: &App, terminal_width: u16, terminal_height: u16, row: u16) -> bool {
    let input_height = chat_input_area_height(app, terminal_width, terminal_height);
    row >= terminal_height.saturating_sub(input_height.saturating_add(1))
        && row < terminal_height.saturating_sub(1)
}

fn chat_input_visual_line_count(input: &str, cursor: usize, width: usize) -> usize {
    let lines = wrapped_input_lines(input, width).len();
    let (cursor_row, _) = wrapped_input_cursor_position(input, cursor, width);
    lines.max(cursor_row.saturating_add(1)).max(1)
}

fn wrapped_input_lines(input: &str, width: usize) -> Vec<String> {
    let width = width.max(1);
    let mut lines = Vec::new();
    let mut current = String::new();
    let mut current_width = 0usize;
    for ch in input.chars() {
        if ch == '\n' {
            lines.push(current);
            current = String::new();
            current_width = 0;
            continue;
        }
        if current_width >= width {
            lines.push(current);
            current = String::new();
            current_width = 0;
        }
        current.push(ch);
        current_width = current_width.saturating_add(1);
    }
    lines.push(current);
    lines
}

fn wrapped_input_cursor_position(input: &str, cursor: usize, width: usize) -> (usize, usize) {
    let width = width.max(1);
    let mut row = 0usize;
    let mut col = 0usize;
    for ch in input.chars().take(cursor.min(input.chars().count())) {
        if ch == '\n' {
            row = row.saturating_add(1);
            col = 0;
            continue;
        }
        if col >= width {
            row = row.saturating_add(1);
            col = 0;
        }
        col = col.saturating_add(1);
    }
    if col >= width {
        row = row.saturating_add(1);
        col = 0;
    }
    (row, col.min(width.saturating_sub(1)))
}

fn bounded_chat_input_scroll(
    input: &str,
    cursor: usize,
    width: u16,
    inner_height: u16,
    requested: u16,
) -> u16 {
    let width = usize::from(width.max(1));
    let inner_height = usize::from(inner_height.max(1));
    let line_count = chat_input_visual_line_count(input, cursor, width);
    let max_scroll = line_count
        .saturating_sub(inner_height)
        .min(u16::MAX as usize) as u16;
    requested.min(max_scroll)
}

fn chat_input_cursor_position(
    input: &str,
    cursor: usize,
    width: u16,
    scroll: u16,
    inner_height: u16,
) -> Option<(u16, u16)> {
    let (row, col) = wrapped_input_cursor_position(input, cursor, usize::from(width.max(1)));
    let scroll = usize::from(scroll);
    let inner_height = usize::from(inner_height.max(1));
    if row < scroll || row >= scroll.saturating_add(inner_height) {
        return None;
    }
    Some((col as u16, row.saturating_sub(scroll) as u16))
}

fn run_loop(terminal: &mut Terminal<CrosstermBackend<Stdout>>, app: &mut App) -> Result<()> {
    let mut fallback_events: Option<Receiver<Event>> = None;
    while !app.should_quit {
        app.refresh_sidebar_state();
        terminal
            .draw(|frame| draw(frame, app))
            .context("failed to render rocm TUI")?;

        let poll_interval = if app.running_job.is_some() {
            TUI_ACTIVE_POLL_INTERVAL
        } else {
            TUI_IDLE_POLL_INTERVAL
        };
        let next_event = match event::poll(poll_interval) {
            Ok(false) => None,
            Ok(true) => match event::read() {
                Ok(event) => Some(event),
                Err(error) => fallback_terminal_event(
                    &mut fallback_events,
                    poll_interval,
                    &mut app.status,
                    error,
                )?,
            },
            Err(error) => fallback_terminal_event(
                &mut fallback_events,
                poll_interval,
                &mut app.status,
                error,
            )?,
        };

        if let Some(event) = next_event {
            handle_terminal_event(app, event);
        }
    }
    Ok(())
}

fn fallback_terminal_event(
    receiver: &mut Option<Receiver<Event>>,
    poll_interval: Duration,
    status: &mut String,
    error: std::io::Error,
) -> Result<Option<Event>> {
    if receiver.is_none() {
        *status = "Keyboard ready. Arrow keys and Enter still work.".to_owned();
        *receiver = Some(spawn_fallback_terminal_reader());
        let _ = error;
    }
    let Some(receiver) = receiver else {
        return Ok(None);
    };
    match receiver.recv_timeout(poll_interval) {
        Ok(event) => Ok(Some(event)),
        Err(mpsc::RecvTimeoutError::Timeout) => Ok(None),
        Err(mpsc::RecvTimeoutError::Disconnected) => {
            bail!("portable terminal input reader stopped")
        }
    }
}

fn spawn_fallback_terminal_reader() -> Receiver<Event> {
    let (sender, receiver) = mpsc::channel();
    std::thread::spawn(move || {
        let (byte_sender, byte_receiver) = mpsc::channel();
        std::thread::spawn(move || {
            let stdin = io::stdin();
            let mut stdin = stdin.lock();
            let mut byte = [0u8; 1];
            while stdin.read_exact(&mut byte).is_ok() {
                if byte_sender.send(byte[0]).is_err() {
                    break;
                }
            }
        });
        while let Some(event) = read_fallback_terminal_event_from_receiver(
            &byte_receiver,
            FALLBACK_ESCAPE_SEQUENCE_TIMEOUT,
        ) {
            if sender.send(event).is_err() {
                break;
            }
        }
    });
    receiver
}

fn read_fallback_terminal_event_from_receiver(
    receiver: &Receiver<u8>,
    escape_timeout: Duration,
) -> Option<Event> {
    let byte = receiver.recv().ok()?;
    fallback_terminal_event_from_byte(byte, &mut |timeout| {
        receiver.recv_timeout(timeout.min(escape_timeout)).ok()
    })
}

#[cfg(test)]
fn read_fallback_terminal_event<R: Read>(reader: &mut R) -> Option<Event> {
    let mut byte = [0u8; 1];
    reader.read_exact(&mut byte).ok()?;
    fallback_terminal_event_from_byte(byte[0], &mut |_| {
        let mut next = [0u8; 1];
        reader.read_exact(&mut next).ok()?;
        Some(next[0])
    })
}

fn fallback_terminal_event_from_byte(
    byte: u8,
    next_byte: &mut impl FnMut(Duration) -> Option<u8>,
) -> Option<Event> {
    match byte {
        b'\r' | b'\n' => Some(fallback_key(KeyCode::Enter)),
        b'\t' => Some(fallback_key(KeyCode::Tab)),
        0x08 | 0x7f => Some(fallback_key(KeyCode::Backspace)),
        0x03 => Some(Event::Key(KeyEvent::new(
            KeyCode::Char('c'),
            KeyModifiers::CONTROL,
        ))),
        0x1b => {
            read_fallback_escape_sequence(next_byte).or_else(|| Some(fallback_key(KeyCode::Esc)))
        }
        value if value.is_ascii_control() => None,
        value => Some(fallback_key(KeyCode::Char(value as char))),
    }
}

fn read_fallback_escape_sequence(
    next_byte: &mut impl FnMut(Duration) -> Option<u8>,
) -> Option<Event> {
    let second = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?;
    if second == b'O' {
        let third = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?;
        return Some(fallback_key(match third {
            b'P' => KeyCode::F(1),
            b'Q' => KeyCode::F(2),
            b'R' => KeyCode::F(3),
            b'S' => KeyCode::F(4),
            _ => KeyCode::Esc,
        }));
    }
    if second != b'[' {
        return Some(fallback_key(KeyCode::Esc));
    }
    let third = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?;
    match third {
        b'A' => Some(fallback_key(KeyCode::Up)),
        b'B' => Some(fallback_key(KeyCode::Down)),
        b'C' => Some(fallback_key(KeyCode::Right)),
        b'D' => Some(fallback_key(KeyCode::Left)),
        b'<' => read_fallback_sgr_mouse_sequence(next_byte),
        b'M' => read_fallback_x10_mouse_sequence(next_byte),
        b'5' => {
            let _ = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT);
            Some(fallback_key(KeyCode::PageUp))
        }
        b'6' => {
            let _ = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT);
            Some(fallback_key(KeyCode::PageDown))
        }
        value if value.is_ascii_digit() => read_fallback_csi_numbered_key(next_byte, value),
        _ => Some(fallback_key(KeyCode::Esc)),
    }
}

fn read_fallback_csi_numbered_key(
    next_byte: &mut impl FnMut(Duration) -> Option<u8>,
    first: u8,
) -> Option<Event> {
    let mut bytes = vec![first];
    loop {
        let byte = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?;
        if byte == b'~' {
            break;
        }
        if !byte.is_ascii_digit() || bytes.len() > 3 {
            return Some(fallback_key(KeyCode::Esc));
        }
        bytes.push(byte);
    }
    let number = std::str::from_utf8(&bytes).ok()?.parse::<u16>().ok()?;
    let code = match number {
        1 => KeyCode::Home,
        2 => KeyCode::Insert,
        3 => KeyCode::Delete,
        4 => KeyCode::End,
        15 => KeyCode::F(5),
        17 => KeyCode::F(6),
        18 => KeyCode::F(7),
        19 => KeyCode::F(8),
        20 => KeyCode::F(9),
        21 => KeyCode::F(10),
        23 => KeyCode::F(11),
        24 => KeyCode::F(12),
        11 => KeyCode::F(1),
        12 => KeyCode::F(2),
        13 => KeyCode::F(3),
        14 => KeyCode::F(4),
        5 => KeyCode::PageUp,
        6 => KeyCode::PageDown,
        _ => KeyCode::Esc,
    };
    Some(fallback_key(code))
}

fn read_fallback_sgr_mouse_sequence(
    next_byte: &mut impl FnMut(Duration) -> Option<u8>,
) -> Option<Event> {
    let mut bytes = Vec::new();
    let final_byte = loop {
        let byte = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?;
        if matches!(byte, b'M' | b'm') {
            break byte;
        }
        if bytes.len() > 64 {
            return Some(fallback_noop_event());
        }
        bytes.push(byte);
    };
    let text = String::from_utf8(bytes).ok()?;
    let mut parts = text.split(';');
    let code = parts.next()?.parse::<u16>().ok()?;
    let column = parts.next()?.parse::<u16>().ok()?.saturating_sub(1);
    let row = parts.next()?.parse::<u16>().ok()?.saturating_sub(1);
    fallback_mouse_event(code, column, row, final_byte)
}

fn read_fallback_x10_mouse_sequence(
    next_byte: &mut impl FnMut(Duration) -> Option<u8>,
) -> Option<Event> {
    let code = next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?.saturating_sub(32) as u16;
    let column = u16::from(next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?.saturating_sub(33));
    let row = u16::from(next_byte(FALLBACK_ESCAPE_SEQUENCE_TIMEOUT)?.saturating_sub(33));
    fallback_mouse_event(code, column, row, b'M')
}

fn fallback_mouse_event(code: u16, column: u16, row: u16, final_byte: u8) -> Option<Event> {
    let button = code & !(4 | 8 | 16 | 32);
    let kind = match button {
        64 => MouseEventKind::ScrollUp,
        65 => MouseEventKind::ScrollDown,
        _ => return Some(fallback_noop_event()),
    };
    if final_byte == b'm' {
        return Some(fallback_noop_event());
    }
    Some(Event::Mouse(MouseEvent {
        kind,
        column,
        row,
        modifiers: fallback_mouse_modifiers(code),
    }))
}

fn fallback_mouse_modifiers(code: u16) -> KeyModifiers {
    let mut modifiers = KeyModifiers::empty();
    if code & 4 != 0 {
        modifiers.insert(KeyModifiers::SHIFT);
    }
    if code & 8 != 0 {
        modifiers.insert(KeyModifiers::ALT);
    }
    if code & 16 != 0 {
        modifiers.insert(KeyModifiers::CONTROL);
    }
    modifiers
}

fn fallback_noop_event() -> Event {
    Event::FocusGained
}

fn fallback_key(code: KeyCode) -> Event {
    Event::Key(KeyEvent::new(code, KeyModifiers::NONE))
}

fn handle_terminal_event(app: &mut App, event: Event) {
    match event {
        Event::Key(key) => handle_key(app, key),
        Event::Mouse(mouse) => handle_mouse(app, mouse),
        Event::Paste(text) if app.onboarding_active && app.onboarding_path_editing => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.install_manager_editing_text() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.logs_view_editing_text() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.runtime_manager_editing_text() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.serve_wizard_editing_text() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.automations_manager_editing_text() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if app.config_manager_editing_secret() => {
            let normalized = text.replace("\r\n", "\n").replace('\r', "\n");
            for ch in normalized.chars().filter(|ch| *ch != '\n') {
                app.insert_input_char(ch);
            }
        }
        Event::Paste(text) if surface_command_prompt_active(app) || should_draw_prompt_box(app) => {
            app.paste_text(&text)
        }
        Event::Paste(_) => {
            app.status =
                "Use the visible choices here; there is no text box on this screen.".to_owned();
        }
        _ => {}
    }
}

fn handle_mouse(app: &mut App, mouse: MouseEvent) {
    if app.onboarding_success_modal {
        if matches!(mouse.kind, MouseEventKind::Down(_)) {
            app.finish_onboarding();
        }
        return;
    }

    match mouse.kind {
        MouseEventKind::Down(MouseButton::Left) => {
            let (terminal_width, terminal_height) = size().unwrap_or((0, 0));
            if app.folder_browser.is_some()
                && click_folder_browser(
                    app,
                    mouse.column,
                    mouse.row,
                    terminal_width,
                    terminal_height,
                )
            {
                return;
            }
            if app.should_draw_home_dashboard()
                && click_home_dashboard(
                    app,
                    mouse.column,
                    mouse.row,
                    terminal_width,
                    terminal_height,
                )
            {
                return;
            }
        }
        MouseEventKind::Drag(_) | MouseEventKind::Moved | MouseEventKind::Up(_) => {
            return;
        }
        _ => {}
    }

    let lines = match mouse.kind {
        MouseEventKind::ScrollUp => -MOUSE_SCROLL_LINES,
        MouseEventKind::ScrollDown => MOUSE_SCROLL_LINES,
        _ => return,
    };

    if should_draw_running_job_modal(app) {
        app.scroll_running_job_log(lines);
        return;
    }
    if app.folder_browser.is_some() {
        app.page_folder_browser_selection(lines);
        return;
    }
    if app.overlay_card.is_some() {
        app.scroll_overlay_card_detail(lines);
        return;
    }
    if app.pending_approval.is_some() {
        app.scroll_pending_approval_detail(lines);
        return;
    }
    if app.onboarding_active {
        app.scroll_onboarding_install_log_by(lines);
        return;
    }
    let command_detail_modal_open = app
        .command_screen
        .as_ref()
        .is_some_and(|state| state.detail_modal.is_some());
    if app.command_screen_is_chat_session() || command_detail_modal_open {
        let (terminal_width, terminal_height) = size().unwrap_or((0, 0));
        if !command_detail_modal_open
            && app.command_screen_is_chat_session()
            && !app.input.is_empty()
            && mouse_over_chat_input(app, terminal_width, terminal_height, mouse.row)
        {
            app.scroll_chat_input(lines);
        } else {
            app.scroll_command_screen_detail(lines);
        }
        return;
    }
    if app
        .logs_view
        .as_ref()
        .is_some_and(|state| state.detail_modal.is_some())
    {
        app.scroll_logs_view_detail_modal(lines);
        return;
    }
    if app.doctor_manager.is_some() {
        app.scroll_doctor_manager_detail(lines);
    } else if app.logs_view.is_some() {
        app.scroll_logs_view_detail(lines);
    } else if app.runtime_manager.is_some()
        || app.install_manager.is_some()
        || app.engine_manager.is_some()
        || app.model_picker.is_some()
        || app.serve_wizard.is_some()
        || app.update_manager.is_some()
        || app.automations_manager.is_some()
        || app.config_manager.is_some()
        || app.provider_manager.is_some()
        || app.services_manager.is_some()
    {
        app.scroll_active_manager_detail(lines);
    } else if app.command_screen.is_some() {
        app.scroll_command_screen_detail(lines);
    } else if lines.is_negative() {
        app.scroll_up(lines.unsigned_abs());
    } else {
        app.scroll_down(lines as u16);
    }
}

fn click_home_dashboard(app: &mut App, column: u16, row: u16, width: u16, height: u16) -> bool {
    let area = main_content_area(app, width, height);
    let Some(list_inner) = home_dashboard_list_inner_rect(app, area) else {
        return false;
    };
    if !rect_contains(list_inner, column, row) {
        return false;
    }
    let index = usize::from(row.saturating_sub(list_inner.y));
    let actions = home_dashboard_actions(app);
    if index >= actions.len() {
        return false;
    }
    app.home_selection = index;
    app.perform_home_dashboard_action();
    true
}

fn click_folder_browser(app: &mut App, column: u16, row: u16, width: u16, height: u16) -> bool {
    let area = Rect {
        x: 0,
        y: 0,
        width,
        height,
    };
    let Some(list_inner) = folder_browser_list_inner_rect(area) else {
        return false;
    };
    if !rect_contains(list_inner, column, row) {
        return false;
    }
    let Some(state) = app.folder_browser.as_ref() else {
        return false;
    };
    let (visible_start, visible_end) =
        folder_browser_visible_range(state, usize::from(list_inner.height));
    let index = visible_start.saturating_add(usize::from(row.saturating_sub(list_inner.y)));
    if index >= visible_end || index >= state.entries.len() {
        return false;
    }
    if let Some(state) = app.folder_browser.as_mut() {
        state.selected = index;
        state.scroll_offset = visible_start;
    }
    app.perform_folder_browser_selection();
    true
}

fn main_content_area(app: &App, width: u16, height: u16) -> Rect {
    let area = Rect {
        x: 0,
        y: 0,
        width,
        height,
    };
    let command_prompt_popup = surface_command_prompt_active(app);
    let prompt_box_visible = should_draw_prompt_box(app) && !command_prompt_popup;
    let completion_height = if prompt_box_visible {
        app.slash_completion_menu()
            .as_ref()
            .map(|menu| menu.items.len().min(MAX_COMPLETION_MENU_ITEMS) as u16 + 2)
            .unwrap_or(0)
    } else {
        0
    };
    let input_height = if prompt_box_visible {
        chat_input_area_height(app, width, height)
    } else {
        0
    };
    let layout = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Min(8),
            Constraint::Length(completion_height),
            Constraint::Length(input_height),
            Constraint::Length(1),
        ])
        .split(area);
    let sidebar_width = if app.command_screen_is_chat_session() {
        0
    } else {
        status_sidebar_width(layout[0].width)
    };
    let body = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Min(60), Constraint::Length(sidebar_width)])
        .split(layout[0]);
    body[0]
}

fn home_dashboard_list_inner_rect(app: &App, area: Rect) -> Option<Rect> {
    let overview_text = render_home_dashboard_overview_text(app);
    let overview_height = (overview_text.lines().count() as u16).saturating_add(2);
    let action_height = (home_dashboard_actions(app).len() as u16).saturating_add(2);
    if area.width < 78 || area.height < overview_height.saturating_add(action_height) {
        return None;
    }
    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Length(overview_height), Constraint::Min(8)])
        .split(area);
    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(40), Constraint::Min(40)])
        .split(rows[1]);
    Some(rect_inner(panes[0]))
}

fn folder_browser_list_inner_rect(area: Rect) -> Option<Rect> {
    if area.width == 0 || area.height == 0 {
        return None;
    }
    let modal = centered_rect(92, 86, area);
    let inner = rect_inner(modal);
    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(5),
            Constraint::Min(8),
            Constraint::Length(3),
        ])
        .split(inner);
    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(58), Constraint::Min(28)])
        .split(rows[1]);
    Some(rect_inner(panes[0]))
}

fn rect_inner(rect: Rect) -> Rect {
    Rect {
        x: rect.x.saturating_add(1),
        y: rect.y.saturating_add(1),
        width: rect.width.saturating_sub(2),
        height: rect.height.saturating_sub(2),
    }
}

fn rect_contains(rect: Rect, column: u16, row: u16) -> bool {
    column >= rect.x && column < rect.right() && row >= rect.y && row < rect.bottom()
}

fn handle_key(app: &mut App, key: KeyEvent) {
    if key.kind == KeyEventKind::Release {
        return;
    }

    clear_prompt_for_active_surface_action(app, key);

    if app.onboarding_success_modal {
        app.finish_onboarding();
        return;
    }

    if app.pending_approval.is_some() {
        if app.onboarding_active {
            if handle_onboarding_key(app, key) {
                return;
            }
        } else if handle_pending_approval_key(app, key) {
            return;
        }
        app.status = if matches!(
            (key.modifiers, key.code),
            (KeyModifiers::CONTROL, KeyCode::Char('c'))
        ) {
            "Finish or cancel this review before quitting.".to_owned()
        } else {
            "Review card is open. Use arrows, Enter/Y, N, or Esc.".to_owned()
        };
        return;
    }

    if matches!(key.code, KeyCode::F(1)) {
        app.open_interactive_help_overlay();
        return;
    }

    if app.overlay_card.is_some() && handle_overlay_card_key(app, key) {
        return;
    }

    if app.folder_browser.is_some() && handle_folder_browser_key(app, key) {
        return;
    }

    if should_draw_running_job_modal(app) && handle_running_job_modal_key(app, key) {
        return;
    }

    if app.onboarding_active && handle_onboarding_key(app, key) {
        return;
    }
    if app.onboarding_active {
        return;
    }

    if app.doctor_manager.is_some() && handle_doctor_manager_key(app, key) {
        return;
    }

    if app.logs_view.is_some() && handle_logs_view_key(app, key) {
        return;
    }

    if app.runtime_manager.is_some() && handle_runtime_manager_key(app, key) {
        return;
    }

    if app.install_manager.is_some() && handle_install_manager_key(app, key) {
        return;
    }

    if app.engine_manager.is_some() && handle_engine_manager_key(app, key) {
        return;
    }

    if app.model_picker.is_some() && handle_model_picker_key(app, key) {
        return;
    }

    if app.serve_wizard.is_some() && handle_serve_wizard_key(app, key) {
        return;
    }

    if app.update_manager.is_some() && handle_update_manager_key(app, key) {
        return;
    }

    if app.automations_manager.is_some() && handle_automations_manager_key(app, key) {
        return;
    }

    if app.config_manager.is_some() && handle_config_manager_key(app, key) {
        return;
    }

    if app.provider_manager.is_some() && handle_provider_manager_key(app, key) {
        return;
    }

    if app.services_manager.is_some() && handle_services_manager_key(app, key) {
        return;
    }

    if app.command_screen.is_some() && handle_command_screen_key(app, key) {
        return;
    }

    if app.should_draw_home_dashboard() && handle_home_dashboard_key(app, key) {
        return;
    }

    if !should_draw_prompt_box(app) && handle_hidden_prompt_key(app, key) {
        return;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
            app.request_quit_overlay_or_wait();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('a')) => {
            app.move_input_start();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('e')) => {
            app.move_input_end();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('u')) => {
            app.clear_input();
            app.status = "Input cleared.".to_owned();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('w')) => {
            app.delete_input_word_before_cursor();
            app.status = "Deleted previous word.".to_owned();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('l')) => {
            app.open_clear_overlay();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('r')) => {
            app.refresh_status();
        }
        (_, KeyCode::F(5)) => {
            app.refresh_status();
        }
        (_, KeyCode::Tab) => {
            if !app.cycle_completion(CompletionDirection::Next) {
                app.status = "No completion menu available.".to_owned();
            }
        }
        (_, KeyCode::BackTab) => {
            if !app.cycle_completion(CompletionDirection::Previous) {
                app.status = "No completion menu available.".to_owned();
            }
        }
        (_, KeyCode::Char('y' | 'Y')) if app.pending_approval.is_some() && app.input.is_empty() => {
            app.approve_focused_action();
        }
        (_, KeyCode::Char('n' | 'N')) if app.pending_approval.is_some() && app.input.is_empty() => {
            app.reject_or_cancel_focused_action();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            if surface_command_prompt_active(app) && command_popup_should_submit_on_enter(app) {
                app.submit();
                return;
            }
            if app.accept_completion() {
                return;
            }
            if app.pending_approval.is_some() && app.input.is_empty() {
                app.approve_focused_action();
            } else {
                app.submit();
            }
        }
        (_, KeyCode::Char('?')) if app.input.is_empty() => {
            app.handle_command("?");
        }
        (_, KeyCode::Backspace) => {
            app.backspace_input();
        }
        (_, KeyCode::Delete) => {
            app.delete_input_char();
        }
        (_, KeyCode::Esc) => {
            if app.pending_approval.is_some() {
                app.cancel_focused_action();
            } else if app.input.is_empty() {
                app.status = "Input already empty. Use /quit or Ctrl-C to exit.".to_owned();
            } else {
                app.clear_input();
                app.status = "Input cleared.".to_owned();
            }
        }
        (_, KeyCode::Left) => app.move_input_left(),
        (_, KeyCode::Right) => app.move_input_right(),
        (_, KeyCode::Up) => {
            if !app.cycle_completion(CompletionDirection::Previous) {
                app.previous_history();
            }
        }
        (_, KeyCode::Down) => {
            if !app.cycle_completion(CompletionDirection::Next) {
                app.next_history();
            }
        }
        (_, KeyCode::PageUp) => {
            app.scroll_up(10);
        }
        (_, KeyCode::PageDown) => {
            app.scroll_down(10);
        }
        (_, KeyCode::Home) => {
            if app.input.is_empty() {
                app.transcript_scroll = 0;
                app.status = "Transcript moved to top.".to_owned();
            } else {
                app.move_input_start();
            }
        }
        (_, KeyCode::End) => {
            if app.input.is_empty() {
                app.scroll_to_bottom();
                app.status = "Transcript moved to bottom.".to_owned();
            } else {
                app.move_input_end();
            }
        }
        (modifiers, KeyCode::Char(ch))
            if !modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER) =>
        {
            app.insert_input_char(ch);
        }
        _ => {}
    }
}

fn handle_home_dashboard_key(app: &mut App, key: KeyEvent) -> bool {
    if !app.input.is_empty() {
        return false;
    }
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm')) | (_, KeyCode::Enter) => {
            app.perform_home_dashboard_action();
            true
        }
        (_, KeyCode::Down) | (_, KeyCode::Tab) => {
            app.move_home_dashboard_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Up) | (_, KeyCode::BackTab) => {
            app.move_home_dashboard_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Home) => {
            app.home_selection = 0;
            if let Some(action) = app.selected_home_dashboard_action() {
                app.status = home_dashboard_action_status(action).to_owned();
            }
            true
        }
        (_, KeyCode::End) => {
            app.home_selection = home_dashboard_actions(app).len().saturating_sub(1);
            if let Some(action) = app.selected_home_dashboard_action() {
                app.status = home_dashboard_action_status(action).to_owned();
            }
            true
        }
        (_, KeyCode::Esc) => {
            app.request_quit_overlay_or_wait();
            true
        }
        (_, KeyCode::Backspace) => {
            app.status = "Main menu is open. Use arrows or mouse.".to_owned();
            true
        }
        _ => false,
    }
}

fn handle_hidden_prompt_key(app: &mut App, key: KeyEvent) -> bool {
    if surface_command_prompt_active(app) {
        return false;
    }
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Esc) => {
            app.open_home_dashboard();
            true
        }
        (_, KeyCode::Char('/')) if app.input.is_empty() => {
            app.insert_input_char('/');
            app.status = "Command prompt opened. Type a / command, then Enter.".to_owned();
            true
        }
        (_, KeyCode::Char('?')) if app.input.is_empty() => {
            app.handle_command("?");
            true
        }
        (modifiers, KeyCode::Char(_))
            if !modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER) =>
        {
            app.status = "Use the menu. Press Esc for the main menu.".to_owned();
            true
        }
        (_, KeyCode::Backspace | KeyCode::Delete | KeyCode::Left | KeyCode::Right) => {
            app.status = "Use the menu. Press Esc for the main menu.".to_owned();
            true
        }
        _ => false,
    }
}

fn active_surface_should_defer_to_prompt(app: &App, key: KeyEvent) -> bool {
    app.pending_approval.is_some()
        || surface_command_prompt_active(app)
        || (app.input.is_empty()
            && !app.onboarding_active
            && matches!(key.code, KeyCode::Char('/')))
        || (!app.input.is_empty() && !active_surface_navigation_key(key))
}

fn command_popup_should_submit_on_enter(app: &App) -> bool {
    let trimmed = app.input.trim();
    let Some(name) = trimmed.strip_prefix('/') else {
        return false;
    };
    if name.is_empty() {
        return false;
    }
    if app
        .slash_completion_menu()
        .as_ref()
        .and_then(CompletionMenu::selected_replacement)
        .is_some()
    {
        return false;
    }
    if name.chars().any(char::is_whitespace) {
        return true;
    }
    SLASH_COMMANDS.iter().any(|command| command.name == name)
}

fn surface_command_prompt_active(app: &App) -> bool {
    app.input.starts_with('/')
        && !app.onboarding_active
        && !should_draw_prompt_box(app)
        && app.pending_approval.is_none()
        && app.overlay_card.is_none()
        && app.folder_browser.is_none()
        && !should_draw_running_job_modal(app)
}

fn active_surface_navigation_key(key: KeyEvent) -> bool {
    active_surface_action_key(key)
        || matches!(
            key.code,
            KeyCode::Up
                | KeyCode::Down
                | KeyCode::Tab
                | KeyCode::BackTab
                | KeyCode::Home
                | KeyCode::End
                | KeyCode::PageUp
                | KeyCode::PageDown
                | KeyCode::F(5)
                | KeyCode::Left
                | KeyCode::Right
                | KeyCode::Esc
        )
}

fn active_surface_action_key(key: KeyEvent) -> bool {
    matches!(
        (key.modifiers, key.code),
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
            | (_, KeyCode::Char('\n' | '\r'))
            | (_, KeyCode::Enter)
    )
}

fn clear_prompt_for_active_surface_action(app: &mut App, key: KeyEvent) {
    if app.input.is_empty()
        || app.pending_approval.is_some()
        || app.overlay_card.is_some()
        || app.folder_browser.is_some()
        || should_draw_running_job_modal(app)
        || !active_surface_action_key(key)
        || app.onboarding_path_editing
        || app.install_manager_editing_text()
        || app.logs_view_editing_text()
        || app.runtime_manager_editing_text()
        || app.serve_wizard_editing_text()
        || app.automations_manager_editing_text()
        || app.config_manager_editing_secret()
        || surface_command_prompt_active(app)
    {
        return;
    }

    if app.onboarding_active
        || app.doctor_manager.is_some()
        || app.logs_view.is_some()
        || app.runtime_manager.is_some()
        || app.install_manager.is_some()
        || app.engine_manager.is_some()
        || app.model_picker.is_some()
        || app.serve_wizard.is_some()
        || app.update_manager.is_some()
        || app.automations_manager.is_some()
        || app.config_manager.is_some()
        || app.provider_manager.is_some()
        || app.services_manager.is_some()
        || (app.command_screen.is_some() && !app.command_screen_is_chat_session())
    {
        app.clear_input();
    }
}

fn handle_pending_approval_key(app: &mut App, key: KeyEvent) -> bool {
    app.clear_input();

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_pending_approval_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_pending_approval_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(pending) = app.pending_approval.as_mut() {
                pending.selected = 0;
            }
            app.status = "Approve selected. Press Enter to continue.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(pending) = app.pending_approval.as_mut() {
                pending.selected = 1;
            }
            app.status =
                if app.pending_approval.as_ref().is_some_and(|pending| {
                    matches!(pending.action, ApprovalAction::Proposal { .. })
                }) {
                    "Reject selected. Press Enter to reject.".to_owned()
                } else {
                    "Cancel selected. Press Enter to cancel.".to_owned()
                };
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_pending_approval_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_pending_approval_detail(10);
            true
        }
        (_, KeyCode::Char('y' | 'Y')) => {
            app.approve_focused_action();
            true
        }
        (_, KeyCode::Char('n' | 'N')) => {
            app.reject_or_cancel_focused_action();
            true
        }
        (_, KeyCode::Esc) => {
            app.cancel_focused_action_to_home();
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_pending_approval_selection();
            true
        }
        _ => false,
    }
}

fn handle_overlay_card_key(app: &mut App, key: KeyEvent) -> bool {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_overlay_card_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_overlay_card_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.overlay_card.as_mut() {
                state.selected = 0;
                state.detail_scroll = 0;
            }
            app.status = "Moved to first card option.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.overlay_card.as_mut() {
                state.selected = state.actions.len().saturating_sub(1);
                state.detail_scroll = 0;
            }
            app.status = "Moved to last card option.".to_owned();
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_overlay_card_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_overlay_card_detail(10);
            true
        }
        (_, KeyCode::Esc) => {
            app.close_overlay_card();
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_overlay_card_action();
            true
        }
        (_, KeyCode::Char('y' | 'Y')) => {
            if !app.confirm_overlay_card_danger_action() {
                app.status = "Use Enter to choose, or Esc to close this card.".to_owned();
            }
            true
        }
        (_, KeyCode::Char('n' | 'N')) => {
            app.close_overlay_card();
            true
        }
        _ => {
            app.status = "Use arrows, Enter, or Esc while this card is open.".to_owned();
            true
        }
    }
}

fn handle_folder_browser_key(app: &mut App, key: KeyEvent) -> bool {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_folder_browser_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_folder_browser_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.folder_browser.as_mut() {
                state.selected = 0;
            }
            app.status = "Moved to the top of the folder list.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.folder_browser.as_mut() {
                state.selected = state.entries.len().saturating_sub(1);
            }
            app.status = "Moved to the bottom of the folder list.".to_owned();
            true
        }
        (_, KeyCode::PageUp) => {
            app.page_folder_browser_selection(-PAGE_SCROLL_LINES);
            true
        }
        (_, KeyCode::PageDown) => {
            app.page_folder_browser_selection(PAGE_SCROLL_LINES);
            true
        }
        (_, KeyCode::Left | KeyCode::Backspace) => {
            let parent = app.folder_browser.as_ref().and_then(|state| {
                state
                    .current_dir
                    .parent()
                    .filter(|parent| !parent.as_os_str().is_empty())
                    .map(Path::to_path_buf)
            });
            if let Some(parent) = parent {
                app.navigate_folder_browser_to(parent);
            } else {
                app.status = "Already at the top.".to_owned();
            }
            true
        }
        (_, KeyCode::Esc) => {
            app.close_folder_browser();
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_folder_browser_selection();
            true
        }
        (modifiers, KeyCode::Char(ch))
            if !modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER) =>
        {
            if let Some(drive) = folder_browser_drive_root_for_key(ch) {
                app.navigate_folder_browser_to(drive);
            } else {
                app.status = "Choose a folder, or type a drive letter like D.".to_owned();
            }
            true
        }
        _ => {
            app.status = "Choose a folder, then press Enter.".to_owned();
            true
        }
    }
}

fn handle_running_job_modal_key(app: &mut App, key: KeyEvent) -> bool {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
            app.request_quit_overlay_or_wait();
        }
        (_, KeyCode::PageUp) => {
            app.scroll_running_job_log(-PAGE_SCROLL_LINES);
        }
        (_, KeyCode::PageDown) => {
            app.scroll_running_job_log(PAGE_SCROLL_LINES);
        }
        (_, KeyCode::Esc) => {
            app.status = "Wait for this work to finish before leaving this screen.".to_owned();
        }
        (_, KeyCode::Up | KeyCode::Down | KeyCode::Tab | KeyCode::BackTab) => {
            if app.onboarding_install_running() {
                let lines = if matches!(key.code, KeyCode::Up | KeyCode::BackTab) {
                    -1
                } else {
                    1
                };
                app.scroll_running_job_log(lines);
            } else {
                app.status = "This work is still running. Choices are paused for now.".to_owned();
            }
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.status =
                "Wait for the running work to finish before choosing another action.".to_owned();
        }
        _ => {
            app.status = "This work is still running.".to_owned();
        }
    }
    true
}

fn handle_doctor_manager_key(app: &mut App, key: KeyEvent) -> bool {
    if active_surface_should_defer_to_prompt(app, key) {
        return false;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_doctor_manager_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_doctor_manager_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_doctor_manager_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_doctor_manager_detail(10);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.doctor_manager.as_mut() {
                state.selected = 0;
                state.message = None;
                state.detail_scroll = 0;
            }
            app.status = "Moved to first doctor check.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.doctor_manager.as_mut() {
                state.selected = doctor_manager_choices().len().saturating_sub(1);
                state.message = None;
                state.detail_scroll = 0;
            }
            app.status = "Moved to last doctor choice.".to_owned();
            true
        }
        (_, KeyCode::F(5)) => {
            app.refresh_doctor_manager();
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_doctor_manager_selected_action();
            true
        }
        (_, KeyCode::Esc) | (_, KeyCode::Char('q' | 'Q')) => {
            app.close_doctor_manager();
            true
        }
        _ => false,
    }
}

fn handle_runtime_manager_key(app: &mut App, key: KeyEvent) -> bool {
    if app.runtime_manager_editing_text() {
        return handle_runtime_manager_text_key(app, key);
    }
    if active_surface_should_defer_to_prompt(app, key) {
        return false;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_runtime_manager_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_runtime_manager_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_active_manager_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_active_manager_detail(10);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.runtime_manager.as_mut() {
                match &mut state.screen {
                    RuntimeManagerScreen::List => {
                        state.selected = 0;
                        state.last_item_selected = 0;
                    }
                    RuntimeManagerScreen::Advanced { selected } => *selected = 0,
                    RuntimeManagerScreen::ImportManifest { selected, .. }
                    | RuntimeManagerScreen::AdoptExisting { selected, .. } => *selected = 0,
                }
                state.detail_scroll = 0;
            }
            app.status = "Moved to first choice.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.runtime_manager.as_mut() {
                match &mut state.screen {
                    RuntimeManagerScreen::List => {
                        state.selected = runtime_manager_choice_count(state).saturating_sub(1);
                    }
                    RuntimeManagerScreen::Advanced { selected } => {
                        *selected = runtime_advanced_choices().len().saturating_sub(1);
                    }
                    RuntimeManagerScreen::ImportManifest { selected, .. } => {
                        *selected = runtime_import_choices().len().saturating_sub(1);
                    }
                    RuntimeManagerScreen::AdoptExisting { selected, .. } => {
                        *selected = runtime_adopt_choices().len().saturating_sub(1);
                    }
                }
                if matches!(state.screen, RuntimeManagerScreen::List)
                    && state.selected < state.items.len()
                {
                    state.last_item_selected = state.selected;
                }
                state.detail_scroll = 0;
            }
            app.status = "Moved to last choice.".to_owned();
            true
        }
        (_, KeyCode::F(5)) => {
            app.refresh_runtime_manager();
            app.status = "Runtime list refreshed.".to_owned();
            true
        }
        (_, KeyCode::Char('i' | 'I')) => {
            if app
                .runtime_manager
                .as_ref()
                .is_some_and(|state| matches!(state.screen, RuntimeManagerScreen::List))
            {
                app.request_runtime_manager_install();
            } else {
                app.status = "Use arrow keys and Enter on this screen.".to_owned();
            }
            true
        }
        (_, KeyCode::Char('u' | 'U')) | (_, KeyCode::Delete) => {
            if app
                .runtime_manager
                .as_ref()
                .is_some_and(|state| matches!(state.screen, RuntimeManagerScreen::List))
            {
                app.request_runtime_manager_uninstall();
            } else {
                app.status = "Use arrow keys and Enter on this screen.".to_owned();
            }
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_runtime_manager_selected_action();
            true
        }
        (_, KeyCode::Esc) | (_, KeyCode::Char('q' | 'Q')) => {
            if app
                .runtime_manager
                .as_ref()
                .is_some_and(|state| !matches!(state.screen, RuntimeManagerScreen::List))
            {
                app.close_runtime_subscreen();
            } else {
                app.close_runtime_manager();
            }
            true
        }
        _ => false,
    }
}

fn handle_runtime_manager_text_key(app: &mut App, key: KeyEvent) -> bool {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
            app.close_runtime_subscreen();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('a')) => app.move_input_start(),
        (KeyModifiers::CONTROL, KeyCode::Char('e')) => app.move_input_end(),
        (KeyModifiers::CONTROL, KeyCode::Char('u')) => app.clear_input(),
        (KeyModifiers::CONTROL, KeyCode::Char('w')) => app.delete_input_word_before_cursor(),
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            let import_editing = app.runtime_manager.as_ref().is_some_and(|state| {
                matches!(
                    state.screen,
                    RuntimeManagerScreen::ImportManifest {
                        editing_path: true,
                        ..
                    }
                )
            });
            if import_editing {
                app.commit_runtime_import_path_edit();
            } else {
                app.commit_runtime_adopt_python_edit();
            }
        }
        (_, KeyCode::Esc) => {
            let import_editing = app.runtime_manager.as_ref().is_some_and(|state| {
                matches!(
                    state.screen,
                    RuntimeManagerScreen::ImportManifest {
                        editing_path: true,
                        ..
                    }
                )
            });
            if import_editing {
                app.cancel_runtime_import_path_edit();
            } else {
                app.cancel_runtime_adopt_python_edit();
            }
        }
        (_, KeyCode::Backspace) => app.backspace_input(),
        (_, KeyCode::Delete) => app.delete_input_char(),
        (_, KeyCode::Left) => app.move_input_left(),
        (_, KeyCode::Right) => app.move_input_right(),
        (_, KeyCode::Home) => app.move_input_start(),
        (_, KeyCode::End) => app.move_input_end(),
        (modifiers, KeyCode::Char(ch))
            if !modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER) =>
        {
            app.insert_input_char(ch);
        }
        _ => {}
    }
    true
}

fn handle_install_manager_key(app: &mut App, key: KeyEvent) -> bool {
    if app.install_manager_editing_text() {
        return handle_install_manager_text_key(app, key);
    }
    if active_surface_should_defer_to_prompt(app, key) {
        return false;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_install_manager_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_install_manager_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Left) => {
            match app.selected_install_sdk_choice() {
                InstallSdkChoice::Folder => {
                    app.cycle_install_sdk_folder_preset(CompletionDirection::Previous)
                }
                _ => {
                    app.status = "Use Up and Down to choose an install option.".to_owned();
                }
            }
            true
        }
        (_, KeyCode::Right) => {
            match app.selected_install_sdk_choice() {
                InstallSdkChoice::Folder => {
                    app.cycle_install_sdk_folder_preset(CompletionDirection::Next)
                }
                _ => {
                    app.status = "Use Up and Down to choose an install option.".to_owned();
                }
            }
            true
        }
        (_, KeyCode::Char('t' | 'T'))
            if app.selected_install_sdk_choice() == InstallSdkChoice::Folder =>
        {
            app.start_install_sdk_folder_edit();
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_active_manager_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_active_manager_detail(10);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.install_manager.as_mut() {
                match &mut state.screen {
                    InstallManagerScreen::Main => state.selected = 0,
                    InstallManagerScreen::Sdk { selected, .. } => *selected = 0,
                }
                state.detail_scroll = 0;
            }
            app.status = "Moved to first install option.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.install_manager.as_mut() {
                match &mut state.screen {
                    InstallManagerScreen::Main => {
                        state.selected = install_menu_choices().len().saturating_sub(1);
                    }
                    InstallManagerScreen::Sdk { selected, .. } => {
                        *selected = install_sdk_choices().len().saturating_sub(1);
                    }
                }
                state.detail_scroll = 0;
            }
            app.status = "Moved to last install option.".to_owned();
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_install_manager_selected_action();
            true
        }
        (_, KeyCode::Esc) | (_, KeyCode::Char('q' | 'Q')) => {
            if app
                .install_manager
                .as_ref()
                .is_some_and(|state| matches!(state.screen, InstallManagerScreen::Sdk { .. }))
            {
                app.close_install_sdk_form();
            } else {
                app.close_install_manager();
            }
            true
        }
        _ => false,
    }
}

