fn handle_engine_manager_key(app: &mut App, key: KeyEvent) -> bool {
    if active_surface_should_defer_to_prompt(app, key) {
        return false;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_engine_manager_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_engine_manager_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_active_manager_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_active_manager_detail(10);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.engine_manager.as_mut() {
                state.selected = 0;
                state.last_item_selected = 0;
                state.detail_scroll = 0;
                state.message = None;
            }
            app.status = "Moved to first engine option.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.engine_manager.as_mut() {
                state.selected = engine_manager_choice_count(state).saturating_sub(1);
                if state.selected < state.items.len() {
                    state.last_item_selected = state.selected;
                }
                state.detail_scroll = 0;
                state.message = None;
            }
            app.status = "Moved to last engine option.".to_owned();
            true
        }
        (_, KeyCode::Char('i' | 'I')) => {
            app.request_selected_engine_install(false);
            true
        }
        (_, KeyCode::Char('r' | 'R')) => {
            app.request_selected_engine_install(true);
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_engine_manager_selected_action();
            true
        }
        (_, KeyCode::Esc) | (_, KeyCode::Char('q' | 'Q')) => {
            app.close_engine_manager();
            true
        }
        _ => false,
    }
}

