fn handle_automations_manager_key(app: &mut App, key: KeyEvent) -> bool {
    if app.automations_manager_editing_text() {
        return handle_automations_manager_text_key(app, key);
    }
    if active_surface_should_defer_to_prompt(app, key) {
        return false;
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => false,
        (_, KeyCode::Up | KeyCode::BackTab) => {
            app.move_automations_manager_selection(CompletionDirection::Previous);
            true
        }
        (_, KeyCode::Down | KeyCode::Tab) => {
            app.move_automations_manager_selection(CompletionDirection::Next);
            true
        }
        (_, KeyCode::Left) => {
            if let Some((proposal, field)) = app.selected_automation_prefetch_field() {
                match field {
                    AutomationPrefetchField::AllowDownload
                    | AutomationPrefetchField::AllowHuggingFace => {
                        app.update_prefetch_bool_field(proposal, field, false)
                    }
                    AutomationPrefetchField::MaxBytes => {
                        app.cycle_prefetch_max_bytes(proposal, CompletionDirection::Previous)
                    }
                }
            } else {
                app.status = "Use Up and Down to choose an automation item.".to_owned();
            }
            true
        }
        (_, KeyCode::Right) => {
            if let Some((proposal, field)) = app.selected_automation_prefetch_field() {
                match field {
                    AutomationPrefetchField::AllowDownload
                    | AutomationPrefetchField::AllowHuggingFace => {
                        app.update_prefetch_bool_field(proposal, field, true)
                    }
                    AutomationPrefetchField::MaxBytes => {
                        app.cycle_prefetch_max_bytes(proposal, CompletionDirection::Next)
                    }
                }
            } else {
                app.status = "Use Up and Down to choose an automation item.".to_owned();
            }
            true
        }
        (_, KeyCode::PageUp) => {
            app.scroll_active_manager_detail(-10);
            true
        }
        (_, KeyCode::PageDown) => {
            app.scroll_active_manager_detail(10);
            true
        }
        (_, KeyCode::Home) => {
            if let Some(state) = app.automations_manager.as_mut() {
                state.selected = 0;
                state.detail_scroll = 0;
                state.message = None;
            }
            app.status = "Moved to first automation item.".to_owned();
            true
        }
        (_, KeyCode::End) => {
            if let Some(state) = app.automations_manager.as_mut() {
                state.selected = state.rows.len().saturating_sub(1);
                state.detail_scroll = 0;
                state.message = None;
            }
            app.status = "Moved to last automation item.".to_owned();
            true
        }
        (_, KeyCode::F(5)) => {
            app.refresh_automations_manager();
            true
        }
        (_, KeyCode::Char('y' | 'Y' | 'a' | 'A')) => {
            if let Some((proposal, field)) = app.selected_automation_prefetch_field() {
                match field {
                    AutomationPrefetchField::AllowDownload
                    | AutomationPrefetchField::AllowHuggingFace => {
                        app.update_prefetch_bool_field(proposal, field, true)
                    }
                    AutomationPrefetchField::MaxBytes => {
                        app.start_prefetch_max_bytes_edit(&proposal)
                    }
                }
            } else if let Some(watcher) = app.selected_automation_watcher() {
                if watcher.enabled {
                    app.status = format!("{} is already on.", watcher.name);
                } else {
                    app.request_automation_watcher_enabled(&watcher, true);
                }
            } else {
                app.focus_selected_automation_proposal();
            }
            true
        }
        (_, KeyCode::Char('n' | 'N')) | (_, KeyCode::Delete) => {
            if let Some((proposal, field)) = app.selected_automation_prefetch_field() {
                match field {
                    AutomationPrefetchField::AllowDownload
                    | AutomationPrefetchField::AllowHuggingFace => {
                        app.update_prefetch_bool_field(proposal, field, false)
                    }
                    AutomationPrefetchField::MaxBytes => {
                        app.status = "Press Enter to edit the max download.".to_owned()
                    }
                }
            } else if let Some(watcher) = app.selected_automation_watcher() {
                if watcher.enabled {
                    app.request_automation_watcher_enabled(&watcher, false);
                } else {
                    app.status = format!("{} is already off.", watcher.name);
                }
            } else if let Some(proposal) = app.selected_automation_proposal() {
                if proposal.status == "pending" {
                    app.focus_selected_automation_proposal();
                } else {
                    if let Some(state) = app.automations_manager.as_mut() {
                        state.message = Some(format!(
                            "{} is already {}.",
                            proposal.proposal_id,
                            proposal_status_for_user(&proposal.status)
                        ));
                    }
                    app.status = "Review request is not pending.".to_owned();
                }
            } else {
                app.show_no_automation_review_selected_message();
            }
            true
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => {
            app.perform_automations_manager_selected_action();
            true
        }
        (_, KeyCode::Esc) | (_, KeyCode::Char('q' | 'Q')) => {
            app.close_automations_manager();
            true
        }
        _ => false,
    }
}

