fn handle_onboarding_key(app: &mut App, key: KeyEvent) -> bool {
    if app.overlay_card.is_some() && handle_overlay_card_key(app, key) {
        return true;
    }
    if app.onboarding_path_editing {
        return handle_onboarding_path_key(app, key);
    }

    if app.onboarding_cancel_install_confirm {
        match (key.modifiers, key.code) {
            (_, KeyCode::Char('y' | 'Y')) => app.cancel_onboarding_install(),
            (_, KeyCode::Char('n' | 'N')) | (_, KeyCode::Esc) => {
                app.keep_waiting_for_onboarding_install()
            }
            (_, KeyCode::Up | KeyCode::BackTab) => {
                app.move_onboarding_cancel_install_selection(CompletionDirection::Previous)
            }
            (_, KeyCode::Down | KeyCode::Tab) => {
                app.move_onboarding_cancel_install_selection(CompletionDirection::Next)
            }
            (_, KeyCode::Home) => {
                app.onboarding_cancel_install_selection = 0;
                app.status = onboarding_cancel_install_status(0);
            }
            (_, KeyCode::End) => {
                app.onboarding_cancel_install_selection =
                    onboarding_cancel_install_choices().len().saturating_sub(1);
                app.status =
                    onboarding_cancel_install_status(app.onboarding_cancel_install_selection);
            }
            (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
            | (_, KeyCode::Char('\n' | '\r'))
            | (_, KeyCode::Enter) => app.perform_onboarding_cancel_install_selection(),
            (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
                app.status = "Choose Keep waiting or Stop install.".to_owned();
            }
            _ => {}
        }
        return true;
    }

    if app.pending_approval.is_some()
        && !matches!(
            (key.modifiers, key.code),
            (KeyModifiers::CONTROL, KeyCode::Char('c'))
        )
    {
        let handled = handle_pending_approval_key(app, key);
        if handled {
            if app.pending_approval.is_none() {
                app.reset_onboarding_selection();
            }
            return true;
        }
    }

    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) if app.onboarding_install_running() => {
            app.request_onboarding_install_cancel();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
            app.request_quit_overlay_or_wait();
        }
        (_, KeyCode::Up | KeyCode::BackTab) if app.running_job.is_none() => {
            app.move_onboarding_selection(CompletionDirection::Previous);
        }
        (_, KeyCode::Down | KeyCode::Tab) if app.running_job.is_none() => {
            app.move_onboarding_selection(CompletionDirection::Next);
        }
        (_, KeyCode::PageUp) => {
            app.scroll_onboarding_install_log(LogPageDirection::Previous);
        }
        (_, KeyCode::PageDown) => {
            app.scroll_onboarding_install_log(LogPageDirection::Next);
        }
        (_, KeyCode::Left)
            if app.pending_approval.is_none()
                && app.running_job.is_none()
                && app.selected_onboarding_choice() == OnboardingMenuChoice::Folder =>
        {
            app.cycle_onboarding_folder_preset(CompletionDirection::Previous);
        }
        (_, KeyCode::Right)
            if app.pending_approval.is_none()
                && app.running_job.is_none()
                && app.selected_onboarding_choice() == OnboardingMenuChoice::Folder =>
        {
            app.cycle_onboarding_folder_preset(CompletionDirection::Next);
        }
        (_, KeyCode::Home) if app.running_job.is_none() => {
            app.onboarding_selection = 0;
            app.status = onboarding_selection_status(app);
        }
        (_, KeyCode::End) if app.running_job.is_none() => {
            app.onboarding_selection = app.onboarding_choice_count().saturating_sub(1);
            app.status = onboarding_selection_status(app);
        }
        (_, KeyCode::Char(ch))
            if app.pending_approval.is_none()
                && app.running_job.is_none()
                && ch.is_ascii_digit()
                && ch != '0' =>
        {
            let index = (ch as u8 - b'1') as usize;
            if index < app.onboarding_choice_count() {
                app.onboarding_selection = index;
                app.perform_onboarding_selected_action();
            }
        }
        (_, KeyCode::Char('c' | 'C' | 'f' | 'F'))
            if app.pending_approval.is_none() && app.running_job.is_none() =>
        {
            app.select_onboarding_choice(OnboardingMenuChoice::Folder);
            app.open_onboarding_install_folder_browser();
        }
        (_, KeyCode::Char('t' | 'T'))
            if app.pending_approval.is_none()
                && app.running_job.is_none()
                && app.selected_onboarding_choice() == OnboardingMenuChoice::Folder =>
        {
            app.start_onboarding_path_edit();
        }
        (_, KeyCode::Char('?')) if app.pending_approval.is_none() && app.running_job.is_none() => {
            app.status = "Setup is open. Use Up/Down, then Enter.".to_owned();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter)
            if app.pending_approval.is_none() && app.running_job.is_none() =>
        {
            app.perform_onboarding_selected_action();
        }
        (_, KeyCode::Char('s' | 'S'))
            if app.pending_approval.is_none() && app.running_job.is_none() =>
        {
            app.status = "Finish setup to continue, or choose Quit setup.".to_owned();
        }
        (_, KeyCode::Esc) if app.pending_approval.is_none() && app.running_job.is_none() => {
            if onboarding_can_return(app) {
                app.return_from_onboarding();
            } else {
                app.select_onboarding_choice(OnboardingMenuChoice::Quit);
                app.status = "Quit setup selected. Press Enter to confirm.".to_owned();
            }
        }
        (_, KeyCode::Char('q' | 'Q'))
            if app.pending_approval.is_none() && app.running_job.is_none() =>
        {
            app.request_quit_overlay_or_wait();
        }
        _ => {}
    }
    true
}

fn handle_onboarding_path_key(app: &mut App, key: KeyEvent) -> bool {
    match (key.modifiers, key.code) {
        (KeyModifiers::CONTROL, KeyCode::Char('c')) => {
            app.request_quit_overlay_or_wait();
        }
        (KeyModifiers::CONTROL, KeyCode::Char('a')) => app.move_input_start(),
        (KeyModifiers::CONTROL, KeyCode::Char('e')) => app.move_input_end(),
        (KeyModifiers::CONTROL, KeyCode::Char('u')) => app.clear_input(),
        (KeyModifiers::CONTROL, KeyCode::Char('w')) => app.delete_input_word_before_cursor(),
        (KeyModifiers::CONTROL, KeyCode::Char('j' | 'm'))
        | (_, KeyCode::Char('\n' | '\r'))
        | (_, KeyCode::Enter) => app.commit_onboarding_path_edit(),
        (_, KeyCode::Esc) => app.cancel_onboarding_path_edit(),
        (_, KeyCode::Backspace) => app.backspace_input(),
        (_, KeyCode::Delete) => app.delete_input_char(),
        (_, KeyCode::Left) => app.move_input_left(),
        (_, KeyCode::Right) => app.move_input_right(),
        (_, KeyCode::Home) => app.move_input_start(),
        (_, KeyCode::End) => app.move_input_end(),
        (modifiers, KeyCode::Char(ch))
            if !modifiers
                .intersects(KeyModifiers::CONTROL | KeyModifiers::ALT | KeyModifiers::SUPER) =>
        {
            app.insert_input_char(ch);
        }
        _ => {}
    }
    true
}

fn draw(frame: &mut Frame<'_>, app: &App) {
    if app.onboarding_active {
        draw_onboarding(frame, app);
        return;
    }
    frame.render_widget(Clear, frame.area());

    let command_prompt_popup = surface_command_prompt_active(app);
    let prompt_box_visible = should_draw_prompt_box(app) && !command_prompt_popup;
    let completion_menu = if (prompt_box_visible || command_prompt_popup)
        && app.overlay_card.is_none()
        && app.folder_browser.is_none()
        && !should_draw_running_job_modal(app)
    {
        app.slash_completion_menu()
    } else {
        None
    };
    let completion_open = completion_menu
        .as_ref()
        .is_some_and(|menu| !menu.selectable_indices().is_empty());
    let completion_height = if command_prompt_popup {
        0
    } else {
        completion_menu
            .as_ref()
            .map(|menu| menu.items.len().min(MAX_COMPLETION_MENU_ITEMS) as u16 + 2)
            .unwrap_or(0)
    };
    let input_height = if prompt_box_visible {
        chat_input_area_height(app, frame.area().width, frame.area().height)
    } else {
        0
    };
    let layout = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Min(8),
            Constraint::Length(completion_height),
            Constraint::Length(input_height),
            Constraint::Length(1),
        ])
        .split(frame.area());
    let sidebar_width = if app.command_screen_is_chat_session() {
        0
    } else {
        status_sidebar_width(layout[0].width)
    };
    let body = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Min(60), Constraint::Length(sidebar_width)])
        .split(layout[0]);

    if app.doctor_manager.is_some() {
        draw_doctor_manager(frame, app, body[0]);
    } else if app.logs_view.is_some() {
        draw_logs_view(frame, app, body[0]);
    } else if app.runtime_manager.is_some() {
        draw_runtime_manager(frame, app, body[0]);
    } else if app.install_manager.is_some() {
        draw_install_manager(frame, app, body[0]);
    } else if app.engine_manager.is_some() {
        draw_engine_manager(frame, app, body[0]);
    } else if app.model_picker.is_some() {
        draw_model_picker(frame, app, body[0]);
    } else if app.serve_wizard.is_some() {
        draw_serve_wizard(frame, app, body[0]);
    } else if app.update_manager.is_some() {
        draw_update_manager(frame, app, body[0]);
    } else if app.automations_manager.is_some() {
        draw_automations_manager(frame, app, body[0]);
    } else if app.config_manager.is_some() {
        draw_config_manager(frame, app, body[0]);
    } else if app.provider_manager.is_some() {
        draw_provider_manager(frame, app, body[0]);
    } else if app.services_manager.is_some() {
        draw_services_manager(frame, app, body[0]);
    } else if app.command_screen.is_some() {
        draw_command_screen(frame, app, body[0]);
    } else if app.should_draw_home_dashboard() {
        draw_home_dashboard(frame, app, body[0]);
    } else {
        draw_scrollable_text_with_block(
            frame,
            app.transcript_text(),
            body[0],
            surface_block(transcript_title(app), THEME_MUTED),
            Style::default().fg(THEME_TEXT).bg(THEME_PANEL),
            app.transcript_scroll,
        );
    }

    if sidebar_width > 0 {
        let sidebar = Paragraph::new(app.sidebar_text())
            .block(surface_block("Status", sidebar_border_color(app)))
            .style(Style::default().fg(THEME_TEXT))
            .wrap(Wrap { trim: false });
        frame.render_widget(sidebar, body[1]);
    }

    if let Some(menu) = completion_menu.as_ref()
        && !command_prompt_popup
    {
        draw_completion_menu(frame, menu, layout[1]);
    }

    let input_area = layout[2];
    let mut cursor_position = None;
    if prompt_box_visible && input_area.height > 0 {
        let input_inner_width = input_area.width.saturating_sub(2);
        let input_inner_height = input_area.height.saturating_sub(2).max(1);
        let display_input = if app.config_manager_editing_secret() {
            "*".repeat(app.input_len_chars())
        } else {
            app.input.clone()
        };
        let chat_input_mode = app.command_screen_is_chat_session();
        let chat_input_scroll = if chat_input_mode {
            bounded_chat_input_scroll(
                &display_input,
                app.input_cursor,
                input_inner_width,
                input_inner_height,
                app.chat_input_scroll,
            )
        } else {
            0
        };
        let (input_text, input_cursor_position) = if chat_input_mode {
            (
                display_input.clone(),
                chat_input_cursor_position(
                    &display_input,
                    app.input_cursor,
                    input_inner_width,
                    chat_input_scroll,
                    input_inner_height,
                ),
            )
        } else {
            let (visible_input, visible_cursor) =
                input_viewport(&display_input, app.input_cursor, input_inner_width);
            (visible_input, Some((visible_cursor, 0)))
        };
        cursor_position = input_cursor_position;
        let input = Paragraph::new(input_text)
            .block(surface_block(input_title(app), THEME_ACCENT))
            .style(Style::default().fg(THEME_TEXT))
            .wrap(Wrap { trim: false })
            .scroll((chat_input_scroll, 0));
        frame.render_widget(input, input_area);
        if chat_input_mode {
            let line_count = chat_input_visual_line_count(
                &display_input,
                app.input_cursor,
                usize::from(input_inner_width.max(1)),
            );
            draw_scrollbar(
                frame,
                input_area,
                scroll_metrics(
                    line_count,
                    usize::from(input_inner_height),
                    usize::from(chat_input_scroll),
                ),
            );
        }
    }

    let key_hint = if app.folder_browser.is_some() {
        "folder picker | Enter select | Backspace up | PageUp/PageDown scroll | Esc cancel"
    } else if app.overlay_card.is_some() {
        overlay_card_key_hint(app)
    } else if should_draw_running_job_modal(app) {
        "running | live output shown | wait for finish"
    } else if command_prompt_popup {
        "Command popup | Tab suggestions | Enter run | Esc close"
    } else if completion_open {
        "Tab/Down next | Shift+Tab/Up previous | Enter choose | Ctrl-C quit"
    } else if app.config_manager_editing_secret() {
        "Enter save key | Esc cancel | input hidden"
    } else if app.install_manager_editing_text() {
        "Enter use folder | Esc cancel | Left/Right move cursor"
    } else if app.logs_view_editing_text() {
        "Enter search | Esc cancel | Left/Right move cursor"
    } else if app.serve_wizard_editing_text() {
        "Enter save | Esc cancel | Left/Right move cursor"
    } else if app.automations_manager_editing_text() {
        "Enter save limit | Esc cancel | digits only"
    } else if app
        .command_screen
        .as_ref()
        .is_some_and(|state| state.detail_modal.is_some())
        || app
            .logs_view
            .as_ref()
            .is_some_and(|state| state.detail_modal.is_some())
    {
        "Up/Down scroll | PageUp/PageDown scroll | Esc close"
    } else if app.doctor_manager.is_some() {
        "Up/Down choose | Enter select | PageUp/PageDown scroll | F5 refresh | Esc back"
    } else if app.runtime_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Enter use highlighted row | PageUp/PageDown scroll | Esc back"
    } else if app.install_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Left/Right change | Enter select | PageUp/PageDown scroll | Esc back"
    } else if app.engine_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Enter use highlighted row | PageUp/PageDown scroll | Esc back"
    } else if app.model_picker.is_some() {
        "Up/Down choose | Enter start | PageUp/PageDown scroll | F5 refresh | Esc back"
    } else if app.serve_wizard.is_some() && app.pending_approval.is_none() {
        "Up/Down choose row | Left/Right change | Enter edit/start | PageUp/PageDown scroll | F5 refresh | Esc back"
    } else if app.update_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Enter select | PageUp/PageDown scroll | F5 refresh | Esc back"
    } else if app.automations_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Left/Right change | Enter select/edit | PageUp/PageDown scroll | Y yes/approve | N no/reject | F5 refresh | Esc back"
    } else if app.config_manager.is_some() {
        "Up/Down choose | Enter change | PageUp/PageDown scroll | F5 refresh | Esc back"
    } else if app.provider_manager.is_some() {
        "Up/Down choose | Enter use | PageUp/PageDown scroll | Esc back"
    } else if app.services_manager.is_some() && app.pending_approval.is_none() {
        "Up/Down choose | Enter use highlighted row | PageUp/PageDown scroll | Esc back"
    } else if app.command_screen.is_some() && app.pending_approval.is_none() {
        if app.command_screen_is_chat_session() {
            if app.input.is_empty() {
                "Type message, Enter sends | Up/Down/PageUp/PageDown scroll chat | Esc back"
            } else {
                "Enter sends | PageUp/PageDown scroll chat | Ctrl+PageUp/PageDown scroll draft | Esc back"
            }
        } else {
            "Up/Down choose | Enter select | PageUp/PageDown scroll | Esc back"
        }
    } else if app.logs_view.is_some() {
        "Up/Down choose | Enter select/search | PageUp/PageDown scroll | Left/Right page | F5 refresh | Esc back"
    } else if app
        .pending_approval
        .as_ref()
        .is_some_and(|pending| matches!(pending.action, ApprovalAction::Proposal { .. }))
    {
        "Up/Down choose | Enter/Y approve | N reject | PageUp/PageDown scroll | Esc back | Ctrl-C quit"
    } else if app.pending_approval.is_some() {
        "Up/Down choose | Enter/Y approve | N/Esc cancel | PageUp/PageDown scroll | Ctrl-C quit"
    } else if app
        .running_job
        .as_ref()
        .is_some_and(|job| matches!(job.kind, RunningJobKind::Planner { .. }))
    {
        "planning | Ctrl-C quit"
    } else if app.running_job.is_some() {
        "command running | live log shown | wait for finish"
    } else if app.should_draw_home_dashboard() {
        "Up/Down choose | Enter open | Tab next | F1 help | Ctrl-L clear | Ctrl-C quit"
    } else {
        "Enter submit | Tab suggestions | F1 help | F5 refresh | Ctrl-L clear | Ctrl-C quit"
    };
    let footer = Paragraph::new(footer_line(&app.status, key_hint, layout[3].width)).style(
        Style::default()
            .fg(THEME_MUTED)
            .bg(THEME_BG)
            .add_modifier(Modifier::DIM),
    );
    frame.render_widget(footer, layout[3]);

    let cursor = cursor_position.map(|(cursor_x, cursor_y)| {
        (
            input_area
                .x
                .saturating_add(1)
                .saturating_add(cursor_x)
                .min(input_area.right().saturating_sub(2)),
            input_area
                .y
                .saturating_add(1)
                .saturating_add(cursor_y)
                .min(input_area.bottom().saturating_sub(2)),
        )
    });
    let running_modal = should_draw_running_job_modal(app);
    if app.pending_approval.is_none()
        && app.overlay_card.is_none()
        && app.folder_browser.is_none()
        && !running_modal
        && prompt_box_visible
        && let Some(cursor) = cursor
    {
        frame.set_cursor_position(cursor);
    }

    if running_modal {
        draw_running_job_modal(frame, app, body[0]);
    }

    if app.overlay_card.is_some() {
        draw_overlay_card(frame, app, body[0]);
    }

    if app.folder_browser.is_some() {
        draw_folder_browser_modal(frame, app, frame.area());
    }

    if app.pending_approval.is_some() && should_draw_modal_approval(app) {
        draw_pending_approval_modal(frame, app, body[0]);
    }

    if command_prompt_popup {
        draw_command_prompt_popup(frame, app, frame.area(), completion_menu.as_ref());
    }
}

fn footer_line(status: &str, key_hint: &str, width: u16) -> String {
    let width = usize::from(width);
    if width == 0 {
        return String::new();
    }
    let key_hint_len = key_hint.chars().count();
    if status.trim().is_empty() {
        return truncate_chars(key_hint, width);
    }
    if key_hint_len >= width {
        return truncate_chars(key_hint, width);
    }
    let separator = " | ";
    let reserved = key_hint_len + separator.chars().count();
    if reserved >= width {
        return truncate_chars(key_hint, width);
    }
    let status = truncate_chars(status.trim(), width - reserved);
    format!("{status}{separator}{key_hint}")
}

fn truncate_chars(value: &str, max_chars: usize) -> String {
    if value.chars().count() <= max_chars {
        return value.to_owned();
    }
    if max_chars <= 3 {
        return value.chars().take(max_chars).collect();
    }
    let mut output = value.chars().take(max_chars - 3).collect::<String>();
    output.push_str("...");
    output
}

fn input_title(app: &App) -> &'static str {
    if app.config_manager_editing_secret() {
        "API Key"
    } else if app.install_manager_editing_text() {
        "Folder"
    } else if app.logs_view_editing_text() {
        "Search"
    } else if app.serve_wizard_editing_text() {
        app.serve_wizard_editing_title()
    } else if app.automations_manager_editing_text() {
        app.automations_manager_editing_title()
    } else if app.command_screen_is_chat_session() {
        "Message"
    } else {
        "Prompt"
    }
}

fn should_draw_prompt_box(app: &App) -> bool {
    if app.onboarding_active {
        return false;
    }
    if app.config_manager_editing_secret()
        || app.install_manager_editing_text()
        || app.logs_view_editing_text()
        || app.runtime_manager_editing_text()
        || app.serve_wizard_editing_text()
        || app.automations_manager_editing_text()
        || app.command_screen_is_chat_session()
    {
        return true;
    }
    app.doctor_manager.is_none()
        && app.logs_view.is_none()
        && app.runtime_manager.is_none()
        && app.install_manager.is_none()
        && app.engine_manager.is_none()
        && app.model_picker.is_none()
        && app.serve_wizard.is_none()
        && app.update_manager.is_none()
        && app.automations_manager.is_none()
        && app.provider_manager.is_none()
        && app.config_manager.is_none()
        && app.services_manager.is_none()
        && app.command_screen.is_none()
        && !app.should_draw_home_dashboard()
}

fn transcript_title(app: &App) -> &'static str {
    if app.transcript.is_empty() {
        "Home"
    } else {
        "Conversation"
    }
}

fn draw_home_dashboard(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let overview_text = render_home_dashboard_overview_text(app);
    let overview_height = (overview_text.lines().count() as u16).saturating_add(2);
    let action_height = (home_dashboard_actions(app).len() as u16).saturating_add(2);
    if area.width < 78 || area.height < overview_height.saturating_add(action_height) {
        let dashboard = Paragraph::new(render_home_dashboard_text(app))
            .block(surface_block("ROCm CLI", THEME_ACCENT))
            .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_2))
            .wrap(Wrap { trim: false });
        frame.render_widget(dashboard, area);
        return;
    }

    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([Constraint::Length(overview_height), Constraint::Min(8)])
        .split(area);
    let overview = Paragraph::new(render_home_dashboard_overview_styled(&overview_text))
        .block(surface_block("ROCm CLI", THEME_ACCENT))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_2))
        .wrap(Wrap { trim: false });
    frame.render_widget(overview, rows[0]);

    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(40), Constraint::Min(40)])
        .split(rows[1]);
    let actions = home_dashboard_actions(app);
    let items = actions
        .iter()
        .map(|action| {
            ListItem::new(Line::from(Span::styled(
                home_dashboard_action_label(*action),
                Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
            )))
        })
        .collect::<Vec<_>>();
    let mut list_state = ListState::default();
    if !items.is_empty() {
        list_state.select(Some(app.home_selection.min(items.len().saturating_sub(1))));
    }
    let list = List::new(items)
        .block(surface_block("Choose", THEME_ACCENT))
        .highlight_symbol("> ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(list, panes[0], &mut list_state);

    let detail = Paragraph::new(render_home_dashboard_detail_text(app))
        .block(detail_block("Next Step"))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
        .wrap(Wrap { trim: false });
    frame.render_widget(detail, panes[1]);
}

fn render_home_dashboard_text(app: &App) -> String {
    let mut output = render_home_dashboard_overview_text(app);
    let _ = writeln!(output);
    let _ = writeln!(output, "Choose");
    for (index, action) in home_dashboard_actions(app).into_iter().enumerate() {
        let marker = if index == app.home_selection {
            ">"
        } else {
            " "
        };
        let label = home_dashboard_action_label(action);
        let _ = writeln!(output, "{marker} {label}");
    }
    let _ = writeln!(output);
    output.push_str(&render_home_dashboard_detail_text(app));
    output.trim_end().to_owned()
}

fn render_home_dashboard_overview_styled(overview_text: &str) -> Text<'static> {
    let lines = overview_text
        .lines()
        .enumerate()
        .map(|(index, line)| {
            if index == 0 {
                return Line::from(Span::styled(
                    line.to_owned(),
                    Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
                ));
            }
            if line == "At a glance" {
                return Line::from(Span::styled(
                    line.to_owned(),
                    Style::default()
                        .fg(THEME_ACCENT)
                        .add_modifier(Modifier::BOLD),
                ));
            }
            if let Some(rest) = line.strip_prefix("  [READY]") {
                return home_dashboard_badge_line("READY", rest, THEME_GOOD);
            }
            if let Some(rest) = line.strip_prefix("  [SETUP NEEDED]") {
                return home_dashboard_badge_line("SETUP NEEDED", rest, THEME_WARN);
            }
            if let Some(rest) = line.strip_prefix("  [RUNNER]") {
                return home_dashboard_badge_line("RUNNER", rest, THEME_ACCENT);
            }
            if let Some(rest) = line.strip_prefix("  [MODELS]") {
                return home_dashboard_badge_line("MODELS", rest, THEME_ACCENT);
            }
            if let Some(rest) = line.strip_prefix("  [PERMISSIONS]") {
                return home_dashboard_badge_line("PERMISSIONS", rest, THEME_ACCENT);
            }
            if line.starts_with("  ") || line.starts_with("      ") {
                return Line::from(Span::styled(
                    line.to_owned(),
                    Style::default().fg(THEME_MUTED),
                ));
            }
            Line::from(line.to_owned())
        })
        .collect::<Vec<_>>();
    Text::from(lines)
}

