fn render_home_dashboard_overview_text(app: &App) -> String {
    let setup_ready = setup_runtime_ready_for_sidebar(&app.paths, &app.config);
    let runtime_count = therock::load_runtime_manifests(&app.paths)
        .map(|manifests| manifests.len())
        .unwrap_or(0);
    let services = load_visible_managed_services(&app.paths);
    let service_counts = managed_service_sidebar_counts(&services);
    let default_engine = app
        .config
        .default_engine
        .as_deref()
        .unwrap_or(default_engine_for_platform());
    let default_engine_label = match default_engine {
        "pytorch" => "PyTorch",
        "lemonade" => "Lemonade",
        "llama.cpp" => "llama.cpp",
        other => other,
    };
    let permission_mode = if app.config.permissions.full_access_enabled() {
        "full access is on"
    } else {
        "asks before changes"
    };
    let setup_badge = if setup_ready { "READY" } else { "SETUP NEEDED" };
    let setup_line = if setup_ready {
        format!("{runtime_count} install(s) saved")
    } else {
        "Install ROCm first".to_owned()
    };
    let mut server_bits = Vec::new();
    if service_counts.ready > 0 {
        server_bits.push(format!("{} ready", service_counts.ready));
    }
    if service_counts.starting > 0 {
        server_bits.push(format!("{} starting", service_counts.starting));
    }
    if server_bits.is_empty() {
        server_bits.push("none yet".to_owned());
    }

    let mut output = String::new();
    let _ = writeln!(output, "Local AI on your AMD GPU");
    let _ = writeln!(output, "  Use the arrows or mouse to choose.");
    let _ = writeln!(output);
    let _ = writeln!(output, "At a glance");
    let _ = writeln!(output, "  [{setup_badge}] AMD GPU setup - {setup_line}");
    let _ = writeln!(output, "  [RUNNER] Model runner - {default_engine_label}");
    let _ = writeln!(
        output,
        "  [MODELS] Local models - {}",
        server_bits.join(", ")
    );
    let _ = writeln!(output, "  [PERMISSIONS] Changes - {permission_mode}");
    output.trim_end().to_owned()
}

fn render_home_dashboard_detail_text(app: &App) -> String {
    let Some(action) = app.selected_home_dashboard_action() else {
        return "Choose a row on the left.".to_owned();
    };
    let title = home_dashboard_action_label(action);
    let body = match action {
        HomeDashboardAction::Setup => {
            "Install ROCm into a Python folder managed by rocm-cli.\n\nThis is the first thing to do on a new machine."
        }
        HomeDashboardAction::Doctor => {
            "Check your GPU, ROCm install, model runner, driver, and useful folders.\n\nThis does not change your computer."
        }
        HomeDashboardAction::Serve => {
            "Start the recommended Lemonade local model server on your AMD GPU.\n\nYou will see a review card before it starts."
        }
        HomeDashboardAction::Chat => {
            "Talk to a local assistant inside this TUI.\n\nThe assistant can ask to use rocm commands, and you approve changes first."
        }
        HomeDashboardAction::ComfyUi => {
            "Install or start ComfyUI in the ROCm folder managed by rocm-cli.\n\nAfter it starts, rocm-cli shows the URL to open."
        }
        HomeDashboardAction::Services => {
            "See local model servers, open their logs, stop them, or restart them.\n\nOnly real running or starting servers are counted."
        }
        HomeDashboardAction::Engine => {
            "Choose how local models run.\n\nLemonade is the default local assistant runner. Use llama.cpp for local model files through llama-server."
        }
        HomeDashboardAction::Permissions => {
            "Choose whether rocm-cli asks before changes or can run with full access.\n\nYou can reset this whenever you want."
        }
        HomeDashboardAction::Help => {
            "Open the interactive help browser.\n\nUse F1 anytime to see topics, shortcuts, and common commands."
        }
        HomeDashboardAction::Quit => "Exit ROCm CLI.",
    };
    let assistant_line = home_dashboard_assistant_line(app);
    if action == HomeDashboardAction::Quit {
        format!("{title}\n\n{body}\n\nPress Enter to quit.")
    } else {
        format!("{title}\n\n{body}\n\nStatus\n  {assistant_line}")
    }
}

fn home_dashboard_assistant_line(app: &App) -> String {
    let services = load_visible_managed_services(&app.paths);
    let service_counts = managed_service_sidebar_counts(&services);
    if service_counts.ready > 0 {
        format!("{} local model(s) ready to chat.", service_counts.ready)
    } else if service_counts.starting > 0 {
        format!("{} local model(s) starting.", service_counts.starting)
    } else {
        "No local model is running yet.".to_owned()
    }
}

