fn selection_style() -> Style {
    Style::default()
        .fg(Color::Black)
        .bg(THEME_ACCENT)
        .add_modifier(Modifier::BOLD)
}

fn surface_block<'a>(title: &'a str, color: Color) -> Block<'a> {
    Block::default()
        .borders(Borders::ALL)
        .title(title)
        .border_style(Style::default().fg(color))
        .style(Style::default().bg(THEME_PANEL))
}

fn detail_block<'a>(title: &'a str) -> Block<'a> {
    surface_block(title, THEME_BORDER)
}

fn draw_scrollable_text_with_block<'a>(
    frame: &mut Frame<'_>,
    text: String,
    area: Rect,
    block: Block<'a>,
    style: Style,
    requested_scroll: u16,
) -> ScrollMetrics {
    let inner = block.inner(area);
    let metrics = text_scroll_metrics(
        &text,
        usize::from(inner.width.max(1)),
        usize::from(inner.height.max(1)),
        requested_scroll,
    );
    let paragraph = Paragraph::new(text)
        .block(block)
        .style(style)
        .wrap(Wrap { trim: false })
        .scroll((metrics.offset_u16(), 0));
    frame.render_widget(paragraph, area);
    draw_scrollbar(frame, area, metrics);
    metrics
}

fn draw_scrollable_text(
    frame: &mut Frame<'_>,
    text: String,
    area: Rect,
    style: Style,
    requested_scroll: u16,
) -> ScrollMetrics {
    let metrics = text_scroll_metrics(
        &text,
        usize::from(area.width.max(1)),
        usize::from(area.height.max(1)),
        requested_scroll,
    );
    let paragraph = Paragraph::new(text)
        .style(style)
        .wrap(Wrap { trim: false })
        .scroll((metrics.offset_u16(), 0));
    frame.render_widget(paragraph, area);
    draw_scrollbar(frame, area, metrics);
    metrics
}

fn draw_scrollable_styled_text_with_block<'a>(
    frame: &mut Frame<'_>,
    styled_text: Text<'static>,
    area: Rect,
    block: Block<'a>,
    style: Style,
    requested_scroll: u16,
) -> ScrollMetrics {
    let inner = block.inner(area);
    let metrics = styled_text_scroll_metrics(
        &styled_text,
        usize::from(inner.width.max(1)),
        usize::from(inner.height.max(1)),
        requested_scroll,
    );
    let paragraph = Paragraph::new(styled_text)
        .block(block)
        .style(style)
        .wrap(Wrap { trim: false })
        .scroll((metrics.offset_u16(), 0));
    frame.render_widget(paragraph, area);
    draw_scrollbar(frame, area, metrics);
    metrics
}

fn draw_modal_shadow(frame: &mut Frame<'_>, modal: Rect, bounds: Rect) {
    let x = modal.x.saturating_add(2);
    let y = modal.y.saturating_add(1);
    if x >= bounds.right() || y >= bounds.bottom() {
        return;
    }
    let width = modal.width.min(bounds.right().saturating_sub(x));
    let height = modal.height.min(bounds.bottom().saturating_sub(y));
    if width == 0 || height == 0 {
        return;
    }
    let shadow = Rect {
        x,
        y,
        width,
        height,
    };
    frame.render_widget(
        Block::default().style(Style::default().bg(THEME_SHADOW)),
        shadow,
    );
}

fn draw_modal_clear(frame: &mut Frame<'_>, modal: Rect, bounds: Rect) {
    draw_modal_shadow(frame, modal, bounds);
    frame.render_widget(Clear, modal);
}

fn approval_modal_border_color(pending: &PendingApproval) -> Color {
    let title = pending.title.to_ascii_lowercase();
    if title.contains("uninstall") || title.contains("stop") || title.contains("disable") {
        THEME_DANGER
    } else {
        THEME_WARN
    }
}

fn sidebar_border_color(app: &App) -> Color {
    if app.pending_approval.is_some() {
        THEME_WARN
    } else if app.running_job.is_some() {
        THEME_ACCENT
    } else if app.status.to_ascii_lowercase().contains("ready")
        || app.status.to_ascii_lowercase().contains("complete")
    {
        THEME_GOOD
    } else if app.status.to_ascii_lowercase().contains("fail")
        || app.status.to_ascii_lowercase().contains("error")
    {
        THEME_DANGER
    } else {
        THEME_MUTED
    }
}

fn should_draw_modal_approval(_app: &App) -> bool {
    true
}

fn centered_rect(percent_x: u16, percent_y: u16, area: Rect) -> Rect {
    let vertical = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Percentage((100 - percent_y) / 2),
            Constraint::Percentage(percent_y),
            Constraint::Percentage((100 - percent_y) / 2),
        ])
        .split(area);
    Layout::default()
        .direction(Direction::Horizontal)
        .constraints([
            Constraint::Percentage((100 - percent_x) / 2),
            Constraint::Percentage(percent_x),
            Constraint::Percentage((100 - percent_x) / 2),
        ])
        .split(vertical[1])[1]
}

fn draw_pending_approval_modal(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(pending) = app.pending_approval.as_ref() else {
        return;
    };
    let modal = centered_rect(72, 82, area);
    draw_modal_clear(frame, modal, area);
    let title = format!(" Review: {} ", pending.title);
    draw_scrollable_styled_text_with_block(
        frame,
        render_modal_approval_text(app, pending),
        modal,
        surface_block(&title, approval_modal_border_color(pending)),
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
        modal_detail_scroll(app),
    );
}

fn render_modal_approval_text(app: &App, pending: &PendingApproval) -> Text<'static> {
    let rendered = render_modal_approval(app, pending);
    let lines = rendered
        .lines()
        .map(|line| {
            let trimmed = line.trim_start();
            let leading = line.len().saturating_sub(trimmed.len());
            if let Some(selected) = trimmed.strip_prefix("> ") {
                return Line::from(vec![
                    Span::raw(" ".repeat(leading)),
                    Span::styled(format!(" {selected} "), selection_style()),
                ]);
            }
            if trimmed.starts_with("Enter or Y:")
                || trimmed.starts_with("Esc or N:")
                || trimmed.starts_with("PageUp/PageDown:")
            {
                return Line::from(vec![
                    Span::raw(" ".repeat(leading)),
                    Span::styled(trimmed.to_owned(), Style::default().fg(THEME_MUTED)),
                ]);
            }
            Line::from(line.to_owned())
        })
        .collect::<Vec<_>>();
    Text::from(lines)
}

fn draw_overlay_card(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(state) = app.overlay_card.as_ref() else {
        return;
    };
    let modal = centered_rect(82, 74, area);
    draw_modal_clear(frame, modal, area);
    let title = format!(" {} ", state.title);
    let block = surface_block(&title, THEME_ACCENT);
    let inner = block.inner(modal);
    frame.render_widget(block, modal);
    if state.actions.is_empty() {
        draw_scrollable_text(
            frame,
            state.detail.clone(),
            inner,
            Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
            state.detail_scroll,
        );
        return;
    }

    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(36), Constraint::Min(28)])
        .split(inner);
    let items = state
        .actions
        .iter()
        .map(|action| ListItem::new(overlay_card_action_label(state, *action)))
        .collect::<Vec<_>>();
    let mut list_state = ListState::default();
    list_state.select(Some(state.selected.min(items.len().saturating_sub(1))));
    let list = List::new(items)
        .block(surface_block("Choose", THEME_ACCENT))
        .highlight_symbol("> ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(list, panes[0], &mut list_state);

    draw_scrollable_text_with_block(
        frame,
        overlay_card_detail_text(state),
        panes[1],
        detail_block("Details"),
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
        state.detail_scroll,
    );
}

fn draw_folder_browser_modal(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(state) = app.folder_browser.as_ref() else {
        return;
    };
    frame.render_widget(Clear, area);
    frame.render_widget(Block::default().style(Style::default().bg(THEME_BG)), area);
    let modal = centered_rect(92, 86, area);
    draw_modal_clear(frame, modal, area);
    let title = format!(" {} ", state.title);
    let block = surface_block(&title, THEME_ACCENT);
    let inner = block.inner(modal);
    frame.render_widget(block, modal);

    let rows = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Length(5),
            Constraint::Min(8),
            Constraint::Length(3),
        ])
        .split(inner);

    let header = Paragraph::new(folder_browser_header_text(state))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3))
        .wrap(Wrap { trim: false });
    frame.render_widget(header, rows[0]);

    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(58), Constraint::Min(28)])
        .split(rows[1]);

    let list_inner_height = panes[0].height.saturating_sub(2) as usize;
    let (visible_start, visible_end) = folder_browser_visible_range(state, list_inner_height);
    let items = state
        .entries
        .iter()
        .skip(visible_start)
        .take(visible_end.saturating_sub(visible_start))
        .map(folder_browser_list_item)
        .collect::<Vec<_>>();
    let mut list_state = ListState::default();
    if !items.is_empty() {
        list_state.select(Some(state.selected.saturating_sub(visible_start)));
    }
    let list = List::new(items)
        .block(surface_block("Folders", THEME_ACCENT))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
        .highlight_symbol("  ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(list, panes[0], &mut list_state);
    draw_scrollbar(
        frame,
        panes[0],
        scroll_metrics(state.entries.len(), list_inner_height.max(1), visible_start),
    );

    let detail = Paragraph::new(folder_browser_detail_text(state))
        .block(detail_block("Selected"))
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3))
        .wrap(Wrap { trim: false });
    frame.render_widget(detail, panes[1]);

    let footer =
        Paragraph::new("Enter open/select | Backspace up | PageUp/PageDown scroll | Esc cancel")
            .style(Style::default().fg(THEME_MUTED).bg(THEME_PANEL));
    frame.render_widget(footer, rows[2]);
}

fn folder_browser_header_text(state: &FolderBrowserState) -> Text<'static> {
    Text::from(vec![
        Line::from(vec![Span::styled(
            state.prompt.clone(),
            Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
        )]),
        Line::from(""),
        Line::from(vec![
            Span::styled("Current  ", Style::default().fg(THEME_MUTED)),
            Span::styled(
                display_runtime_folder_path(&state.current_dir),
                Style::default().fg(THEME_ACCENT),
            ),
        ]),
    ])
}

fn folder_browser_list_item(entry: &FolderBrowserEntry) -> ListItem<'static> {
    let style = match entry.kind {
        FolderBrowserEntryKind::UseCurrent => {
            Style::default().fg(THEME_GOOD).add_modifier(Modifier::BOLD)
        }
        FolderBrowserEntryKind::NewChild => {
            Style::default().fg(THEME_WARN).add_modifier(Modifier::BOLD)
        }
        FolderBrowserEntryKind::Parent => Style::default().fg(THEME_MUTED),
        FolderBrowserEntryKind::Drive => Style::default()
            .fg(THEME_ACCENT)
            .add_modifier(Modifier::BOLD),
        FolderBrowserEntryKind::Directory => Style::default().fg(THEME_TEXT),
    };
    ListItem::new(Line::from(Span::styled(entry.label.clone(), style)))
}

fn folder_browser_detail_text(state: &FolderBrowserState) -> Text<'static> {
    let selected = state.entries.get(state.selected);
    let mut lines = Vec::new();
    if let Some(entry) = selected {
        for line in wrap_plain_line(&display_runtime_folder_path(&entry.path), 54) {
            lines.push(Line::from(line));
        }
        match &state.context {
            FolderBrowserContext::InstallSdk { args } => {
                if let Some(date) = cli_arg_value(args, "--build-date") {
                    lines.push(Line::from(""));
                    lines.push(Line::from(vec![
                        Span::styled("TheRock build date  ", Style::default().fg(THEME_MUTED)),
                        Span::raw(date.to_owned()),
                    ]));
                }
                if let Some(version) = cli_arg_value(args, "--version") {
                    lines.push(Line::from(""));
                    lines.push(Line::from(vec![
                        Span::styled("TheRock version  ", Style::default().fg(THEME_MUTED)),
                        Span::raw(version.to_owned()),
                    ]));
                }
                if matches!(
                    entry.kind,
                    FolderBrowserEntryKind::UseCurrent | FolderBrowserEntryKind::NewChild
                ) {
                    lines.push(Line::from(""));
                    lines.push(Line::from(vec![Span::styled(
                        "Next: review install",
                        Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
                    )]));
                }
            }
            FolderBrowserContext::InstallSdkForm => {
                if matches!(
                    entry.kind,
                    FolderBrowserEntryKind::UseCurrent | FolderBrowserEntryKind::NewChild
                ) {
                    lines.push(Line::from(""));
                    lines.push(Line::from(vec![Span::styled(
                        "Next: use in install form",
                        Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
                    )]));
                }
            }
            FolderBrowserContext::OnboardingInstallFolder => {
                if matches!(
                    entry.kind,
                    FolderBrowserEntryKind::UseCurrent | FolderBrowserEntryKind::NewChild
                ) {
                    lines.push(Line::from(""));
                    lines.push(Line::from(vec![Span::styled(
                        "Next: use for ROCm setup",
                        Style::default().fg(THEME_TEXT).add_modifier(Modifier::BOLD),
                    )]));
                }
            }
        }
    }
    if let Some(message) = state.message.as_deref() {
        lines.push(Line::from(""));
        lines.push(Line::from(vec![Span::styled(
            message.to_owned(),
            Style::default().fg(THEME_WARN),
        )]));
    }
    Text::from(lines)
}

fn folder_browser_visible_range(state: &FolderBrowserState, visible_len: usize) -> (usize, usize) {
    let visible_len = state.entries.len().min(visible_len);
    if visible_len == 0 {
        return (0, 0);
    }
    let selected = state.selected.min(state.entries.len().saturating_sub(1));
    let max_start = state.entries.len().saturating_sub(visible_len);
    let mut start = state.scroll_offset.min(max_start);
    if selected < start {
        start = selected;
    } else if selected >= start.saturating_add(visible_len) {
        start = selected.saturating_add(1).saturating_sub(visible_len);
    }
    start = start.min(max_start);
    let end = start.saturating_add(visible_len).min(state.entries.len());
    (start, end)
}

fn should_draw_running_job_modal(app: &App) -> bool {
    app.overlay_card.is_none()
        && app.folder_browser.is_none()
        && app.pending_approval.is_none()
        && !app.onboarding_cancel_install_confirm
        && app.running_job.as_ref().is_some_and(|job| {
            matches!(
                job.kind,
                RunningJobKind::Cli
                    | RunningJobKind::Planner { .. }
                    | RunningJobKind::Proposal { .. }
                    | RunningJobKind::ServiceLifecycle { .. }
            )
        })
}

#[derive(Debug, Clone, Copy)]
struct RunningJobModalLayout {
    header_area: Rect,
    log_area: Rect,
    live_output_width: usize,
    compact: bool,
}

fn running_job_modal_layout(app: &App, job: &RunningJob, area: Rect) -> RunningJobModalLayout {
    let modal = centered_rect(92, 88, area);
    let inner = rect_inner(modal);
    let live_output_width = inner.width.saturating_sub(3).max(8) as usize;
    let compact = inner.height < 10;
    let header = running_job_modal_header_text(app, job, compact);
    let desired_header_height = header.lines().count().max(1) as u16;
    let header_height = desired_header_height
        .min(inner.height.saturating_sub(1))
        .max(1)
        .min(inner.height);
    let header_area = Rect {
        x: inner.x,
        y: inner.y,
        width: inner.width,
        height: header_height,
    };
    let log_area = Rect {
        x: inner.x,
        y: inner.y.saturating_add(header_height),
        width: inner.width,
        height: inner.height.saturating_sub(header_height),
    };
    RunningJobModalLayout {
        header_area,
        log_area,
        live_output_width,
        compact,
    }
}

fn draw_running_job_modal(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(job) = app.running_job.as_ref() else {
        return;
    };
    let modal = centered_rect(92, 88, area);
    draw_modal_clear(frame, modal, area);
    let title = format!(" {} ", job.title);
    let block = surface_block(&title, THEME_WARN);
    frame.render_widget(block, modal);
    let layout = running_job_modal_layout(app, job, area);
    let header = running_job_modal_header_text(app, job, layout.compact);
    let header = Paragraph::new(header)
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3))
        .wrap(Wrap { trim: false })
        .scroll((0, 0));
    frame.render_widget(header, layout.header_area);
    if layout.log_area.height == 0 {
        return;
    }
    let viewport = usize::from(layout.log_area.height).max(1);
    let scroll = running_job_visible_output_start(app, viewport, layout.live_output_width);
    draw_scrollable_text(
        frame,
        running_job_modal_full_output_text(app, layout.live_output_width),
        layout.log_area,
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
        scroll.min(u16::MAX as usize) as u16,
    );
}

fn render_modal_approval(app: &App, pending: &PendingApproval) -> String {
    if app.onboarding_active {
        return render_onboarding_approval(app, pending);
    }
    if app.runtime_manager.is_some() {
        return render_runtime_manager_approval(app, pending);
    }
    render_screen_approval(app, pending)
}

fn modal_detail_scroll(app: &App) -> u16 {
    app.pending_approval
        .as_ref()
        .map(|pending| pending.detail_scroll)
        .unwrap_or(0)
}

