fn draw_command_screen(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(state) = app.command_screen.as_ref() else {
        return;
    };
    if state.chat_session.is_some() {
        app.command_screen_last_area.set(Some(area));
        let detail_text = command_screen_detail_text(app);
        draw_scrollable_styled_text_with_block(
            frame,
            styled_chat_detail_text(&detail_text),
            area,
            surface_block("ROCm Assistant", THEME_ACCENT),
            Style::default().fg(THEME_TEXT).bg(THEME_PANEL),
            state.detail_scroll,
        );
        if let Some(title) = command_screen_detail_modal_title(app, state) {
            draw_command_screen_detail_modal(frame, app, area, title);
        }
        return;
    }
    let panes = Layout::default()
        .direction(Direction::Horizontal)
        .constraints([Constraint::Percentage(32), Constraint::Min(40)])
        .split(area);
    let items = state
        .actions
        .iter()
        .map(|action| ListItem::new(command_screen_action_label(*action)))
        .collect::<Vec<_>>();
    let mut list_state = ListState::default();
    if !items.is_empty() {
        list_state.select(Some(state.selected.min(items.len().saturating_sub(1))));
    }
    let list = List::new(items)
        .block(surface_block(state.title.as_str(), THEME_ACCENT))
        .highlight_symbol("> ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(list, panes[0], &mut list_state);

    let detail_text = command_screen_detail_text(app);
    draw_scrollable_text_with_block(
        frame,
        detail_text,
        panes[1],
        detail_block("Details"),
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL),
        state.detail_scroll,
    );

    if let Some(title) = command_screen_detail_modal_title(app, state) {
        draw_command_screen_detail_modal(frame, app, area, title);
    }
}

fn bounded_chat_session_scroll(text: &str, area: Rect, requested: u16) -> u16 {
    if requested == 0 || text.trim().is_empty() {
        return 0;
    }
    let styled_text = styled_chat_detail_text(text);
    let metrics = styled_text_scroll_metrics(
        &styled_text,
        area.width.saturating_sub(2).max(1) as usize,
        area.height.saturating_sub(2).max(1) as usize,
        requested,
    );
    metrics.offset_u16()
}

fn paragraph_visual_line_count(text: &str, width: usize) -> usize {
    Paragraph::new(text.to_owned())
        .wrap(Wrap { trim: false })
        .line_count(width.min(u16::MAX as usize) as u16)
        .max(1)
}

fn styled_text_visual_line_count(text: &Text<'_>, width: usize) -> usize {
    Paragraph::new(text.clone())
        .wrap(Wrap { trim: false })
        .line_count(width.min(u16::MAX as usize) as u16)
        .max(1)
}

