fn command_screen_detail_modal_title<'a>(
    app: &App,
    state: &'a CommandScreenState,
) -> Option<&'a str> {
    if app.pending_approval.is_some() || should_draw_running_job_modal(app) {
        return None;
    }
    state
        .detail_modal
        .as_ref()
        .map(|modal| modal.title.as_str())
}

fn draw_command_screen_detail_modal(frame: &mut Frame<'_>, app: &App, area: Rect, title: &str) {
    let Some(modal_state) = app
        .command_screen
        .as_ref()
        .and_then(|state| state.detail_modal.as_ref())
    else {
        return;
    };
    let modal = centered_rect(78, 72, area);
    draw_modal_clear(frame, modal, area);
    let block_title = format!(" {title} ");
    draw_scrollable_text_with_block(
        frame,
        modal_state.detail.clone(),
        modal,
        surface_block(&block_title, THEME_ACCENT),
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
        modal_state.scroll,
    );
}

fn draw_logs_view_detail_modal(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let Some(modal_state) = app
        .logs_view
        .as_ref()
        .and_then(|state| state.detail_modal.as_ref())
    else {
        return;
    };
    let modal = centered_rect(78, 72, area);
    draw_modal_clear(frame, modal, area);
    let block_title = format!(" {} ", modal_state.title);
    draw_scrollable_text_with_block(
        frame,
        modal_state.detail.clone(),
        modal,
        surface_block(&block_title, THEME_ACCENT),
        Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3),
        modal_state.scroll,
    );
}

fn doctor_manager_choices() -> &'static [DoctorManagerChoice] {
    &[
        DoctorManagerChoice::Overview,
        DoctorManagerChoice::Gpu,
        DoctorManagerChoice::Runtimes,
        DoctorManagerChoice::Engines,
        DoctorManagerChoice::DriverAndWsl,
        DoctorManagerChoice::Folders,
        DoctorManagerChoice::Back,
    ]
}

fn doctor_manager_label(choice: DoctorManagerChoice) -> &'static str {
    match choice {
        DoctorManagerChoice::Overview => "Overview",
        DoctorManagerChoice::Gpu => "GPU",
        DoctorManagerChoice::Runtimes => "ROCm installs",
        DoctorManagerChoice::Engines => "Engines",
        DoctorManagerChoice::DriverAndWsl => "Driver and WSL",
        DoctorManagerChoice::Folders => "Folders",
        DoctorManagerChoice::Back => "Back",
    }
}

fn runtime_manager_row_label(item: &RuntimeManagerItem) -> String {
    let state = if item.active {
        "Default"
    } else if item.status == "ready" {
        "Installed"
    } else {
        "Needs fix"
    };
    let version = runtime_manager_row_version_label(&item.version);
    if version.trim().is_empty() || version == "unknown" {
        state.to_owned()
    } else {
        format!("{state} - {version}")
    }
}

fn runtime_manager_row_version_label(version: &str) -> String {
    if let Some(date) = therock::runtime_version_build_date(version) {
        date
    } else {
        therock::runtime_version_display(version)
    }
}

