fn cycle_prefetch_max_bytes_value(current: Option<u64>, direction: CompletionDirection) -> u64 {
    const PRESETS: &[u64] = &[1_073_741_824, 2_147_483_648, 5_368_709_120, 10_737_418_240];
    let current_index =
        current.and_then(|value| PRESETS.iter().position(|preset| *preset == value));
    match (direction, current_index) {
        (CompletionDirection::Next, Some(index)) => PRESETS[(index + 1) % PRESETS.len()],
        (CompletionDirection::Previous, Some(0)) => *PRESETS.last().expect("presets are nonempty"),
        (CompletionDirection::Previous, Some(index)) => PRESETS[index - 1],
        (CompletionDirection::Next, None) => PRESETS[0],
        (CompletionDirection::Previous, None) => *PRESETS.last().expect("presets are nonempty"),
    }
}

fn render_prefetch_field_detail(
    proposal: &AutomationProposalRecord,
    selected_field: AutomationPrefetchField,
) -> String {
    let mut output = render_proposal_approval(proposal);
    let _ = writeln!(output);
    let _ = writeln!(output, "Selected download setting");
    match selected_field {
        AutomationPrefetchField::AllowDownload => {
            let _ = writeln!(
                output,
                "  Allow download: {}",
                yes_no_label(proposal_bool_argument(proposal, "allow_artifact_download"))
            );
            let _ = writeln!(
                output,
                "  Enter or Left/Right changes whether rocm-cli may download this file."
            );
        }
        AutomationPrefetchField::MaxBytes => {
            let _ = writeln!(
                output,
                "  Max download: {}",
                proposal_u64_argument(proposal, "artifact_max_bytes")
                    .map(format_bytes_for_tui)
                    .unwrap_or_else(|| "not set".to_owned())
            );
            let _ = writeln!(
                output,
                "  Enter types a custom limit. Left/Right chooses common limits."
            );
        }
        AutomationPrefetchField::AllowHuggingFace => {
            let _ = writeln!(
                output,
                "  Hugging Face token: {}",
                yes_no_label(proposal_bool_argument(
                    proposal,
                    "allow_huggingface_download",
                ))
            );
            let _ = writeln!(output, "  This is only for gated Hugging Face HTTPS files.");
        }
    }
    output.trim_end().to_owned()
}

