fn config_manager_detail_text(app: &App) -> String {
    let Some(state) = app.config_manager.as_ref() else {
        return String::new();
    };
    if let Some(message) = state.message.as_deref() {
        return message.to_owned();
    }
    if let ConfigManagerScreen::Provider {
        provider,
        confirming_clear: true,
        ..
    } = &state.screen
    {
        return config_provider_clear_confirmation_text(app, provider);
    }
    if let ConfigManagerScreen::Provider { provider, .. } = &state.screen {
        return config_provider_detail_text(app, provider);
    }
    match config_menu_choices()
        .get(state.selected)
        .copied()
        .unwrap_or(ConfigMenuChoice::Telemetry)
    {
        ConfigMenuChoice::Telemetry => {
            let mode = if app.config.telemetry.local_inspection_enabled() {
                "on"
            } else {
                "off"
            };
            [
                "GPU checks",
                "",
                &format!("Current: {mode}"),
                "",
                "When this is on, rocm-cli reads local AMD GPU status for doctor and model-fit screens.",
                "No cloud service is used.",
                "",
                "Press Enter to toggle this.",
            ]
            .join("\n")
        }
        ConfigMenuChoice::PlannerProvider => {
            let current = app.config.planner_provider.as_deref().unwrap_or("off");
            [
                "Planning help",
                "",
                &format!("Current: {current}"),
                "",
                "This only helps interpret fuzzy requests. rocm-cli still shows the command before running anything.",
                "",
                "Press Enter to cycle: off, local, OpenAI, Anthropic.",
            ]
            .join("\n")
        }
        ConfigMenuChoice::OpenAiProvider => provider_prompt_detail(app, "openai", "OpenAI"),
        ConfigMenuChoice::AnthropicProvider => {
            provider_prompt_detail(app, "anthropic", "Anthropic")
        }
        ConfigMenuChoice::DefaultEngine => [
            "Default engine",
            "",
            &format!(
                "Current: {}",
                app.config
                    .default_engine
                    .as_deref()
                    .unwrap_or(default_engine_for_platform())
            ),
            "",
            "This is the engine rocm-cli picks first for new local model runs.",
            "",
            "Press Enter to open the Engines screen.",
        ]
        .join("\n"),
        ConfigMenuChoice::DefaultRuntime => [
            "Default ROCm install",
            "",
            &format!(
                "Current: {}",
                app.config
                    .active_runtime_key
                    .as_deref()
                    .or(app.config.default_runtime_id.as_deref())
                    .unwrap_or("automatic")
            ),
            "",
            "New engines use this ROCm install. Running services keep their current runtime until restarted.",
            "",
            "Press Enter to open the ROCm installs screen.",
        ]
        .join("\n"),
        ConfigMenuChoice::Permissions => [
            "Permissions",
            "",
            &format!(
                "Current: {}",
                if app.config.permissions.full_access_enabled() {
                    "full access"
                } else {
                    "ask before changes"
                }
            ),
            "",
            "Full access lets reviewed actions run without asking each time.",
            "",
            "Press Enter to open permissions.",
        ]
        .join("\n"),
        ConfigMenuChoice::ShowSetupAgain => [
            "Show setup again",
            "",
            "Use this when you want ROCm CLI to show the setup flow again.",
            "",
            "This does not uninstall ROCm.",
            "Installed ROCm folders stay where they are.",
            "API keys stay saved.",
            "Provider settings stay saved.",
            "",
            "Press Enter to review this reset.",
        ]
        .join("\n"),
        ConfigMenuChoice::Back => "Return to the main screen.".to_owned(),
    }
}

