fn provider_manager_detail_text(app: &App) -> String {
    let Some(state) = app.provider_manager.as_ref() else {
        return String::new();
    };
    if let Some(message) = state.message.as_deref() {
        return message.to_owned();
    }
    let option = provider_options()
        .get(state.selected)
        .unwrap_or(&provider_options()[0]);
    let mut output = String::new();
    let _ = writeln!(output, "Provider");
    let _ = writeln!(output, "  name: {}", option.label);
    let _ = writeln!(
        output,
        "  current: {}",
        if app.provider == option.name {
            "yes"
        } else {
            "no"
        }
    );
    let _ = writeln!(output, "  purpose: {}", option.description);
    let _ = writeln!(output);
    let _ = writeln!(output, "Action");
    if app.provider == option.name {
        let _ = writeln!(output, "  Enter: keep using this provider");
    } else {
        let _ = writeln!(output, "  Enter: use this provider for this session");
    }
    let _ = writeln!(output);
    let _ = writeln!(output, "Note");
    match option.name {
        "local" => {
            let _ = writeln!(output, "  Local chat needs a running managed model server.");
        }
        "anthropic" | "openai" => {
            let _ = writeln!(
                output,
                "  Remote providers require opt-in and a saved provider key."
            );
        }
        _ => {}
    }
    output.trim_end().to_owned()
}

fn services_manager_detail_text(app: &App) -> String {
    if let Some(job) = app.running_job.as_ref()
        && app.active_screen_handles_command_output(&job.title)
    {
        return runtime_manager_running_text(app, &job.title);
    }
    let Some(state) = app.services_manager.as_ref() else {
        return String::new();
    };
    if let Some(message) = state.message.as_deref() {
        return message.to_owned();
    }
    if let Some(action) = app.selected_services_manager_action() {
        return services_manager_action_detail_text(app, action);
    }
    let Some(record) = state
        .items
        .get(state.selected)
        .or_else(|| state.items.first())
    else {
        return [
            "No local model servers are running.",
            "",
            "Start one from the main menu when you are ready.",
            "Press F5 to check again.",
        ]
        .join("\n");
    };
    let mut output = String::new();
    let _ = writeln!(output, "Local model server");
    let _ = writeln!(
        output,
        "  Status: {}",
        friendly_service_status(&record.status)
    );
    let _ = writeln!(output, "  Engine: {}", record.engine);
    let _ = writeln!(
        output,
        "  Model: {}",
        friendly_model_label(&record.model_ref)
    );
    if let Some(policy) = record.device_policy.as_deref() {
        let _ = writeln!(output, "  Device: {}", serve_wizard_device_label(policy));
    }
    let _ = writeln!(output);
    let _ = writeln!(output, "Actions");
    let _ = writeln!(output, "  Press Enter to open logs for this server.");
    let _ = writeln!(
        output,
        "  Choose Service details for the address, server id, and ROCm install."
    );
    let _ = writeln!(
        output,
        "  Use the rows below to chat, open logs, stop, restart, or go back."
    );
    output.trim_end().to_owned()
}

fn services_manager_action_detail_text(app: &App, action: ServicesManagerAction) -> String {
    let mut output = String::new();
    match action {
        ServicesManagerAction::Details => {
            let _ = writeln!(output, "Service details");
            let _ = writeln!(output);
            if let Some(record) = app.selected_service_target_record() {
                let _ = writeln!(output, "Open the detailed server card.");
                let _ = writeln!(output);
                let _ = writeln!(output, "Selected server");
                let _ = writeln!(
                    output,
                    "  Status: {}",
                    friendly_service_status(&record.status)
                );
                let _ = writeln!(
                    output,
                    "  Model: {}",
                    friendly_model_label(&record.model_ref)
                );
            } else {
                let _ = writeln!(output, "No managed servers are running yet.");
            }
        }
        ServicesManagerAction::OpenLogs => {
            let _ = writeln!(output, "Show server logs");
            let _ = writeln!(output);
            if let Some(record) = app.selected_service_target_record() {
                let _ = writeln!(output, "Selected server");
                let _ = writeln!(
                    output,
                    "  Status: {}",
                    friendly_service_status(&record.status)
                );
                let _ = writeln!(
                    output,
                    "  Model: {}",
                    friendly_model_label(&record.model_ref)
                );
                let _ = writeln!(output);
                let _ = writeln!(output, "Press Enter to open its logs.");
            } else {
                let _ = writeln!(output, "No managed servers are running yet.");
            }
        }
        ServicesManagerAction::Chat => {
            let _ = writeln!(output, "Chat with selected server");
            let _ = writeln!(output);
            if let Some(record) = app.selected_service_target_record() {
                let _ = writeln!(output, "Selected server");
                let _ = writeln!(
                    output,
                    "  Status: {}",
                    friendly_service_status(&record.status)
                );
                let _ = writeln!(
                    output,
                    "  Model: {}",
                    friendly_model_label(&record.canonical_model_id)
                );
                let _ = writeln!(output);
                if managed_service_is_chat_ready(&record) {
                    let _ = writeln!(output, "Press Enter to ask this local model for ROCm help.");
                    let _ = writeln!(
                        output,
                        "It can check this computer. Changes still need your OK."
                    );
                } else {
                    let _ = writeln!(output, "This server is not ready yet.");
                    let _ = writeln!(output, "Open logs or press F5, then try Chat again.");
                }
            } else {
                let _ = writeln!(output, "No managed server is selected.");
            }
        }
        ServicesManagerAction::Stop => {
            let _ = writeln!(output, "Stop selected server");
            let _ = writeln!(output);
            if let Some(record) = app.selected_service_target_record() {
                let _ = writeln!(output, "Selected server");
                let _ = writeln!(
                    output,
                    "  Status: {}",
                    friendly_service_status(&record.status)
                );
                let _ = writeln!(
                    output,
                    "  Model: {}",
                    friendly_model_label(&record.model_ref)
                );
                let _ = writeln!(output);
                if record.status == "stopped" {
                    let _ = writeln!(output, "This server is already stopped.");
                } else {
                    let _ = writeln!(output, "Press Enter to review stopping it.");
                }
            } else {
                let _ = writeln!(output, "No managed server is selected.");
            }
        }
        ServicesManagerAction::Restart => {
            let _ = writeln!(output, "Restart selected server");
            let _ = writeln!(output);
            if let Some(record) = app.selected_service_target_record() {
                let _ = writeln!(output, "Selected server");
                let _ = writeln!(
                    output,
                    "  Status: {}",
                    friendly_service_status(&record.status)
                );
                let _ = writeln!(
                    output,
                    "  Model: {}",
                    friendly_model_label(&record.model_ref)
                );
                let _ = writeln!(output);
                let _ = writeln!(output, "Press Enter to review restarting it.");
            } else {
                let _ = writeln!(output, "No managed server is selected.");
            }
        }
        ServicesManagerAction::Back => {
            let _ = writeln!(output, "Back");
            let _ = writeln!(output);
            let _ = writeln!(output, "Return to the main screen.");
        }
    }
    output.trim_end().to_owned()
}

