fn model_picker_detail_text(app: &App) -> String {
    let Some(state) = app.model_picker.as_ref() else {
        return String::new();
    };
    if let Some(message) = state.message.as_deref() {
        return message.to_owned();
    }
    let Some(recipe) = state
        .items
        .get(state.selected)
        .or_else(|| state.items.first())
    else {
        return "No model recipes found.\n\nPress F5 to refresh.".to_owned();
    };
    let mut output = String::new();
    let _ = writeln!(output, "Model");
    let _ = writeln!(output, "  name: {}", recipe.canonical_model_id);
    if !recipe.aliases.is_empty() {
        let _ = writeln!(output, "  aliases: {}", recipe.aliases.join(", "));
    }
    let _ = writeln!(output, "  task: {}", recipe.task);
    let _ = writeln!(
        output,
        "  device: {}",
        model_device_policy_label(&recipe.device_policy)
    );
    let _ = writeln!(
        output,
        "  GPU memory: {}",
        recipe
            .min_gpu_mem_gb
            .map(|gb| format!("{gb} GB minimum"))
            .unwrap_or_else(|| "not required".to_owned())
    );
    if !recipe.preferred_engines.is_empty() {
        let _ = writeln!(output, "  engines: {}", recipe.preferred_engines.join(", "));
    }
    let _ = writeln!(output);
    let _ = writeln!(output, "Fit");
    let _ = writeln!(
        output,
        "  {}",
        model_recipe_fit_summary(recipe, app.gpu_telemetry.total_vram_gib())
    );
    let _ = writeln!(output);
    let _ = writeln!(output, "Action");
    let _ = writeln!(output, "  Enter: open local model setup for this model");
    let _ = writeln!(output, "  F5: refresh model recipes");
    let _ = writeln!(output, "  Esc: back");
    if !recipe.warnings.is_empty() {
        let _ = writeln!(output);
        let _ = writeln!(output, "Notes");
        for warning in recipe.warnings.iter().take(3) {
            let _ = writeln!(output, "  {warning}");
        }
    }
    output.trim_end().to_owned()
}

fn serve_wizard_detail_text(app: &App) -> String {
    if let Some(job) = app.running_job.as_ref()
        && app.active_screen_handles_command_output(&job.title)
    {
        return runtime_manager_running_text(app, &job.title);
    }
    let Some(state) = app.serve_wizard.as_ref() else {
        return String::new();
    };
    if let Some(message) = state.message.as_deref() {
        return message.to_owned();
    }
    let engine = selected_serve_wizard_engine(state);
    let device = selected_serve_wizard_device(state);
    let mut output = String::new();
    let _ = writeln!(output, "Start a local AI model");
    let _ = writeln!(
        output,
        "  Model type: {}",
        serve_wizard_source_label(state.model_source)
    );
    match state.model_source {
        ServeModelSource::BuiltInRecipe => {
            if let Some(recipe) = selected_serve_wizard_recipe(state) {
                let _ = writeln!(output, "  Model: {}", recipe.canonical_model_id);
                if !recipe.aliases.is_empty() {
                    let _ = writeln!(output, "  Also called: {}", recipe.aliases.join(", "));
                }
            } else {
                let _ = writeln!(output, "  Model: no recommended models found");
                let _ = writeln!(output, "  Next: choose your own model file");
            }
        }
        ServeModelSource::LocalPath => {
            let _ = writeln!(
                output,
                "  Model: {}",
                serve_wizard_local_path_label(&state.local_model_path)
            );
            let _ = writeln!(
                output,
                "  Next: press Enter on Path to choose a file or folder"
            );
        }
    }
    let _ = writeln!(output, "  Runs on: {}", serve_wizard_device_label(device));
    let _ = writeln!(
        output,
        "  Address: http://{}:{}",
        format_host_for_url(&state.host),
        state.port
    );
    let _ = writeln!(
        output,
        "  After start: {}",
        if state.managed {
            "ROCm CLI keeps it running"
        } else {
            "show command only"
        }
    );
    let _ = writeln!(output);
    if let Some(recipe) = selected_serve_wizard_recipe(state)
        && state.model_source == ServeModelSource::BuiltInRecipe
    {
        let _ = writeln!(output, "Fit");
        let _ = writeln!(
            output,
            "  {}",
            model_recipe_fit_summary(recipe, app.gpu_telemetry.total_vram_gib())
        );
        if !recipe.preferred_engines.is_empty() {
            let _ = writeln!(
                output,
                "  Works best with: {}",
                recipe.preferred_engines.join(", ")
            );
        }
        let _ = writeln!(output);
    }
    let _ = writeln!(output, "Advanced");
    let _ = writeln!(output, "  Engine: {engine}");
    if let Some(runtime_id) = state.runtime_id.as_deref() {
        let _ = writeln!(output, "  ROCm install: {runtime_id}");
    }
    let _ = writeln!(
        output,
        "  Listen on: http://{}:{}",
        format_host_for_url(&state.host),
        state.port
    );
    let _ = writeln!(output);
    let _ = writeln!(output, "Controls");
    let _ = writeln!(output, "  Up/Down: choose a row");
    let _ = writeln!(output, "  Left/Right: change the highlighted choice");
    if state.model_source == ServeModelSource::LocalPath {
        let _ = writeln!(output, "  Enter on Path, Host, or Port: edit that value");
    } else {
        let _ = writeln!(
            output,
            "  Recommended model is fixed. Change Model type to use a custom file."
        );
        let _ = writeln!(output, "  Enter on Host or Port: edit that value");
    }
    let _ = writeln!(
        output,
        "  Enter on Start: show a review card before anything runs"
    );
    if !state.managed {
        let _ = writeln!(
            output,
            "  Command-only mode does not launch here. Change Mode to keep it running in ROCm CLI."
        );
    }
    output.trim_end().to_owned()
}

fn model_recipe_fit_summary(recipe: &ModelRecipeRecord, total_vram_gib: Option<f64>) -> String {
    match (recipe.min_gpu_mem_gb, total_vram_gib) {
        (None, _) => "This recipe does not require GPU memory.".to_owned(),
        (Some(required), Some(available)) if available >= (required as f64 + 2.0) => {
            format!(
                "Good fit: {} GPU memory available; recipe asks for {}.",
                format_gib_for_tui(available),
                format_gib_for_tui(required as f64)
            )
        }
        (Some(required), Some(available)) if available >= required as f64 => {
            format!(
                "Tight but usable: {} GPU memory available; recipe asks for {}.",
                format_gib_for_tui(available),
                format_gib_for_tui(required as f64)
            )
        }
        (Some(required), Some(available)) => format!(
            "Likely not enough GPU memory: {} available; recipe asks for {}.",
            format_gib_for_tui(available),
            format_gib_for_tui(required as f64)
        ),
        (Some(required), None) => format!(
            "GPU memory is unknown; recipe asks for {}. Start may fail if this APU has too little shared memory.",
            format_gib_for_tui(required as f64)
        ),
    }
}

fn model_device_policy_label(policy: &str) -> &'static str {
    match policy {
        "gpu_required" => "GPU required",
        "gpu_preferred" => "GPU required",
        "cpu_only" => "not shown here",
        "cpu_supported" => "not shown here",
        _ => "See recipe details",
    }
}

fn format_gib_for_tui(value: f64) -> String {
    if (value.fract()).abs() < f64::EPSILON {
        format!("{value:.0} GB")
    } else {
        format!("{value:.1} GB")
    }
}

fn format_bytes_for_tui(bytes: u64) -> String {
    const KIB: u64 = 1024;
    const MIB: u64 = KIB * 1024;
    const GIB: u64 = MIB * 1024;
    let unit_text = if bytes >= GIB {
        format_gib_for_tui(bytes as f64 / GIB as f64)
    } else if bytes >= MIB {
        format!("{:.1} MB", bytes as f64 / MIB as f64)
    } else if bytes >= KIB {
        format!("{:.1} KB", bytes as f64 / KIB as f64)
    } else if bytes == 1 {
        "1 byte".to_owned()
    } else {
        format!("{bytes} bytes")
    };
    if bytes >= KIB {
        format!("{unit_text} ({bytes} bytes)")
    } else {
        unit_text
    }
}

fn runtime_manager_detail_text(app: &App) -> String {
    if let Some(job) = app.running_job.as_ref()
        && app.active_screen_handles_command_output(&job.title)
    {
        return runtime_manager_running_text(app, &job.title);
    }

    let Some(state) = app.runtime_manager.as_ref() else {
        return String::new();
    };
    match &state.screen {
        RuntimeManagerScreen::Advanced { .. } => {
            return runtime_advanced_detail_text(state);
        }
        RuntimeManagerScreen::ImportManifest { .. } => {
            return runtime_import_detail_text(state);
        }
        RuntimeManagerScreen::AdoptExisting { .. } => {
            return runtime_adopt_detail_text(state);
        }
        RuntimeManagerScreen::List => {}
    }

    let selected_action = app.selected_runtime_manager_action();
    if let Some(message) = state.message.as_deref()
        && let Some(action) = selected_action
    {
        return format!("{message}\n\n{}", runtime_action_detail_text(app, action));
    }

    if let Some(action) = selected_action {
        return runtime_action_detail_text(app, action);
    }

    let Some(item) = state
        .items
        .get(state.selected)
        .or_else(|| state.items.first())
    else {
        return runtime_action_detail_text(app, RuntimeManagerAction::Install);
    };
    let mut output = String::new();
    if let Some(message) = state.message.as_deref() {
        let _ = writeln!(output, "Note");
        for line in message.lines().take(8) {
            let _ = writeln!(output, "  {line}");
        }
        let _ = writeln!(output);
    }
    let _ = writeln!(output, "ROCm install");
    let _ = writeln!(
        output,
        "  state: {}",
        if item.active { "active" } else { "available" }
    );
    let _ = writeln!(
        output,
        "  health: {}",
        if item.status == "ready" {
            "ready"
        } else {
            "needs repair"
        }
    );
    if item.status != "ready" {
        let _ = writeln!(output, "  reason: {}", item.status);
        let _ = writeln!(
            output,
            "  fix: reinstall ROCm from Set Up ROCm, or uninstall this install"
        );
    }
    let _ = writeln!(
        output,
        "  version: {}",
        therock::runtime_version_display(&item.version)
    );
    let _ = writeln!(output, "  GPU package: {}", item.family);
    let _ = writeln!(output, "  folder: {}", item.install_root.display());
    if item.read_only || item.imported_from.is_some() {
        let _ = writeln!(
            output,
            "  source: existing folder; ROCm CLI will not change that folder"
        );
    } else {
        let _ = writeln!(output, "  source: managed by ROCm CLI");
    }
    let _ = writeln!(output);
    let _ = writeln!(output, "Actions");
    if item.active {
        let _ = writeln!(output, "  Enter: already default");
    } else if item.status == "ready" {
        let _ = writeln!(output, "  Enter: use this ROCm install");
    } else {
        let _ = writeln!(output, "  Enter: unavailable until reinstalled");
    }
    let _ = writeln!(
        output,
        "  Choose a row below the list to install, uninstall, or add an existing install."
    );
    if item.read_only || item.imported_from.is_some() {
        let _ = writeln!(output, "  Uninstall only forgets this external folder.");
    } else {
        let _ = writeln!(output, "  Uninstall removes the selected ROCm folder.");
    }
    output.trim_end().to_owned()
}

