fn render_screen_approval(app: &App, pending: &PendingApproval) -> String {
    let approve_marker = if pending.selected == 0 { ">" } else { " " };
    let cancel_marker = if pending.selected == 1 { ">" } else { " " };
    let is_proposal = matches!(pending.action, ApprovalAction::Proposal { .. });
    let cancel_label = if is_proposal {
        "N: reject"
    } else {
        "Esc or N: cancel"
    };
    let mut lines = vec![pending.title.clone(), String::new()];
    lines.extend(plain_approval_lines(app, pending).into_iter().map(|line| {
        if line.is_empty() {
            String::new()
        } else {
            format!("  {line}")
        }
    }));
    lines.extend([
        String::new(),
        format!("  {approve_marker} Enter or Y: approve"),
        format!("  {cancel_marker} {cancel_label}"),
    ]);
    if is_proposal {
        lines.push("  Esc: back without changing".to_owned());
    }
    lines.join("\n")
}

fn render_onboarding_approval(app: &App, pending: &PendingApproval) -> String {
    let approve_marker = if pending.selected == 0 { ">" } else { " " };
    let cancel_marker = if pending.selected == 1 { ">" } else { " " };
    let install_folder = setup_install_root(&app.paths, &app.config);
    let pip_cache_dir = setup_pip_cache_dir(&app.paths, &app.config);
    let mut output = String::new();
    if pending.title == "Uninstall" {
        let _ = writeln!(output, "Uninstall ROCm");
        let _ = writeln!(output);
        let _ = writeln!(output, "Folder");
        let _ = writeln!(output, "  {}", install_folder.display());
        let _ = writeln!(output);
        let _ = writeln!(output, "  ROCm CLI will uninstall this ROCm install.");
        let _ = writeln!(output, "  You can install ROCm again from this screen.");
    } else {
        let verb = if pending.title == "Reinstall" {
            "reinstall"
        } else {
            "install"
        };
        let _ = writeln!(
            output,
            "{} ROCm",
            if verb == "install" {
                "Install"
            } else {
                "Reinstall"
            }
        );
        let _ = writeln!(output);
        let _ = writeln!(output, "Folder");
        let _ = writeln!(output, "  {}", install_folder.display());
        let _ = writeln!(output);
        let _ = writeln!(output, "  ROCm CLI will {verb} ROCm into this folder.");
        let _ = writeln!(
            output,
            "  {}",
            onboarding_gpu_install_sentence(&app.host_gpu_summary)
        );
        let _ = writeln!(output, "  It will add the local AI pieces ROCm CLI needs.");
        let _ = writeln!(
            output,
            "  Downloaded files: {}",
            display_runtime_folder_path(&pip_cache_dir)
        );
    }
    let _ = writeln!(output);
    if pending.title == "Uninstall" {
        let _ = writeln!(output, "  {approve_marker} Enter or Y: uninstall ROCm");
    } else {
        let _ = writeln!(output, "  {approve_marker} Enter or Y: start setup");
    }
    let _ = writeln!(output, "  {cancel_marker} Esc or N: cancel");
    output.trim_end().to_owned()
}

fn plan_request_mentions_cpu_mode(request: &str) -> bool {
    request
        .split(|ch: char| !ch.is_ascii_alphanumeric())
        .any(|word| word.eq_ignore_ascii_case("cpu"))
}

fn plan_action_uses_cpu_device(action: &FreeformPlanAction) -> bool {
    action.args.windows(2).any(|pair| {
        pair.first().map(String::as_str) == Some("--device")
            && matches!(pair.get(1).map(String::as_str), Some("cpu" | "cpu_only"))
    })
}

