fn draw_onboarding(frame: &mut Frame<'_>, app: &App) {
    if app.onboarding_success_modal {
        frame.render_widget(
            Block::default().style(Style::default().bg(THEME_BG)),
            frame.area(),
        );
        draw_onboarding_success_modal(frame, app, frame.area());
        return;
    }
    if should_draw_running_job_modal(app) {
        frame.render_widget(
            Block::default().style(Style::default().bg(THEME_BG)),
            frame.area(),
        );
        draw_running_job_modal(frame, app, frame.area());
        return;
    }

    let action_height = if app.onboarding_success_modal {
        0
    } else if app.onboarding_path_editing || app.running_job.is_some() {
        3
    } else {
        let row_count = onboarding_menu_choices(app).len();
        row_count as u16 + 2
    };
    let layout = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Min(8),
            Constraint::Length(action_height),
            Constraint::Length(1),
        ])
        .split(frame.area());

    let install_log_limit = onboarding_install_log_limit(layout[0].height);
    let body = Paragraph::new(render_onboarding_screen_text_with_log_limit(
        app,
        install_log_limit,
    ))
    .block(surface_block(
        "Set Up ROCm",
        if setup_venv_ready(&app.paths, &app.config) {
            THEME_GOOD
        } else if app.onboarding_install_failure.is_some() || app.onboarding_setup_error.is_some() {
            THEME_DANGER
        } else if app.running_job.is_some() {
            THEME_ACCENT
        } else {
            THEME_WARN
        },
    ))
    .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
    .wrap(Wrap { trim: false });
    frame.render_widget(body, layout[0]);

    let action_area = layout[1];
    let action_inner_width = action_area.width.saturating_sub(2);
    let cursor_column = if app.onboarding_path_editing {
        let (visible, cursor) = input_viewport(&app.input, app.input_cursor, action_inner_width);
        let action = Paragraph::new(visible)
            .block(surface_block("Folder", THEME_ACCENT))
            .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
            .wrap(Wrap { trim: false });
        frame.render_widget(action, action_area);
        Some(cursor)
    } else if app.running_job.is_some() {
        let action = Paragraph::new(onboarding_primary_label(app))
            .block(surface_block("Setup", THEME_ACCENT))
            .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL))
            .wrap(Wrap { trim: false });
        frame.render_widget(action, action_area);
        None
    } else if app.pending_approval.is_some() {
        let action = Paragraph::new("Review is open.")
            .block(surface_block("Choose", THEME_BORDER))
            .style(Style::default().fg(THEME_MUTED).bg(THEME_PANEL))
            .wrap(Wrap { trim: false });
        frame.render_widget(action, action_area);
        None
    } else {
        let choices = onboarding_menu_choices(app);
        let items = choices
            .iter()
            .map(|choice| ListItem::new(onboarding_menu_label(app, *choice)))
            .collect::<Vec<_>>();
        let mut state = ListState::default();
        state.select(Some(
            app.onboarding_selection
                .min(choices.len().saturating_sub(1)),
        ));
        let menu = List::new(items)
            .block(surface_block("Choose", THEME_ACCENT))
            .highlight_symbol("> ")
            .highlight_style(selection_style());
        frame.render_stateful_widget(menu, action_area, &mut state);
        None
    };

    let footer_text = if app.folder_browser.is_some() {
        "Enter open/use | Wheel/Page scroll | Esc"
    } else if app.overlay_card.is_some() {
        overlay_card_key_hint(app)
    } else if app.onboarding_cancel_install_confirm {
        "Up/Down choose | Enter select | Y stop | N/Esc keep waiting"
    } else if app.pending_approval.is_some() {
        "Up/Down choose | Enter/Y approve | N/Esc cancel"
    } else if app.onboarding_path_editing {
        "Enter use folder | Esc cancel | Ctrl-C review quit"
    } else if app.onboarding_install_running() {
        "PageUp/PageDown log | Ctrl-C stop install"
    } else if app.running_job.is_some() {
        "PageUp/PageDown log | Ctrl-C quit"
    } else if onboarding_can_return(app) && onboarding_should_show_log_controls(app) {
        "Up/Down choose | PageUp/PageDown log | Enter select | Esc back"
    } else if onboarding_can_return(app) {
        "Up/Down choose | Enter select | Esc back"
    } else if onboarding_should_show_log_controls(app) {
        "Up/Down choose | Left/Right folder | PageUp/PageDown log | Enter select | Esc quit"
    } else {
        "Up/Down choose | Left/Right folder | Enter select | Esc quit"
    };
    let footer = Paragraph::new(footer_line(&app.status, footer_text, layout[2].width)).style(
        Style::default()
            .fg(Color::DarkGray)
            .bg(THEME_BG)
            .add_modifier(Modifier::DIM),
    );
    frame.render_widget(footer, layout[2]);

    if let Some(cursor_column) = cursor_column.filter(|_| {
        app.overlay_card.is_none()
            && app.pending_approval.is_none()
            && app.folder_browser.is_none()
            && !app.onboarding_cancel_install_confirm
            && !should_draw_running_job_modal(app)
    }) {
        frame.set_cursor_position((
            action_area
                .x
                .saturating_add(1)
                .saturating_add(cursor_column)
                .min(action_area.right().saturating_sub(2)),
            action_area.y.saturating_add(1),
        ));
    }

    if app.pending_approval.is_some() {
        draw_pending_approval_modal(frame, app, frame.area());
    }
    if app.onboarding_cancel_install_confirm {
        draw_onboarding_cancel_install_modal(frame, app, frame.area());
    }
    if app.overlay_card.is_some() {
        draw_overlay_card(frame, app, frame.area());
    }
    if app.folder_browser.is_some() {
        draw_folder_browser_modal(frame, app, frame.area());
    }
}

fn draw_onboarding_success_modal(frame: &mut Frame<'_>, _app: &App, area: Rect) {
    let modal = centered_rect(58, 36, area);
    draw_modal_clear(frame, modal, area);
    let block = surface_block(" Installed ", THEME_GOOD);
    let inner = block.inner(modal);
    frame.render_widget(block, modal);
    let text = "ROCm installed successfully.\n\nPress any key to continue to ROCm CLI.";
    let details = Paragraph::new(text)
        .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3))
        .wrap(Wrap { trim: false });
    frame.render_widget(details, inner);
}

fn draw_onboarding_cancel_install_modal(frame: &mut Frame<'_>, app: &App, area: Rect) {
    let modal = centered_rect(64, 46, area);
    draw_modal_clear(frame, modal, area);
    let block = surface_block(" Stop ROCm Install? ", THEME_WARN);
    let inner = block.inner(modal);
    frame.render_widget(block, modal);
    let chunks = Layout::default()
        .direction(Direction::Vertical)
        .constraints([
            Constraint::Min(6),
            Constraint::Length(onboarding_cancel_install_choices().len() as u16 + 2),
        ])
        .split(inner);
    let details = Paragraph::new(
        "ROCm is still installing.\n\nKeep waiting leaves the installer alone.\nStop install asks the running command to stop.",
    )
    .style(Style::default().fg(THEME_TEXT).bg(THEME_PANEL_3))
    .wrap(Wrap { trim: false });
    frame.render_widget(details, chunks[0]);

    let choices = onboarding_cancel_install_choices();
    let items = choices
        .iter()
        .map(|choice| ListItem::new(*choice))
        .collect::<Vec<_>>();
    let mut state = ListState::default();
    state.select(Some(
        app.onboarding_cancel_install_selection
            .min(choices.len().saturating_sub(1)),
    ));
    let list = List::new(items)
        .block(surface_block("Choose", THEME_ACCENT))
        .highlight_symbol("> ")
        .highlight_style(selection_style());
    frame.render_stateful_widget(list, chunks[1], &mut state);
}

fn run_cli_command_streaming(
    paths: &AppPaths,
    args: &[String],
    display_command: Option<&str>,
    sender: mpsc::Sender<RunningJobEvent>,
    cancel_requested: Arc<AtomicBool>,
) -> Result<CommandOutput> {
    let current_exe =
        current_executable_path().context("failed to resolve current rocm executable path")?;
    let output = run_process_streaming(&current_exe, args, sender, cancel_requested, Some(paths))
        .with_context(|| {
        format!(
            "failed to execute `{}`",
            format_command_for_display(current_exe.as_os_str().to_string_lossy().as_ref(), args)
        )
    })?;
    render_command_output("rocm", args, output, display_command)
}

fn run_rocmd_command_streaming(
    paths: &AppPaths,
    args: &[String],
    sender: mpsc::Sender<RunningJobEvent>,
    cancel_requested: Arc<AtomicBool>,
) -> Result<CommandOutput> {
    let rocmd_binary = daemon_binary_path()?;
    let output = run_process_streaming(&rocmd_binary, args, sender, cancel_requested, Some(paths))
        .with_context(|| {
            format!(
                "failed to execute `{}`",
                format_command_for_display(
                    rocmd_binary.as_os_str().to_string_lossy().as_ref(),
                    args
                )
            )
        })?;
    render_command_output("rocmd", args, output, None)
}

fn run_provider_chat_stream(
    paths: &AppPaths,
    provider: &str,
    request: &ChatRequest,
    sender: &mpsc::Sender<RunningJobEvent>,
) -> Result<CommandOutput> {
    if request.rocm_tools {
        let prompt = request
            .messages
            .iter()
            .rev()
            .find(|message| message.role == "user")
            .map(|message| message.content.as_str())
            .unwrap_or_default();
        let mut progress = |line: String| {
            let _ = sender.send(RunningJobEvent::Stream {
                stream: CommandOutputStream::Stdout,
                line,
            });
        };
        let result = crate::render_chat_prompt_result_with_progress(
            paths,
            provider,
            request.model.as_deref(),
            prompt,
            true,
            Some(&mut progress),
        )?;
        return Ok(CommandOutput {
            ok: true,
            rendered: result.rendered,
            chat_approval: result.approval,
        });
    }
    let mut emitted = 0_usize;
    providers::provider_stream_chat_with_callback(paths, provider, request, &mut |event| {
        if !event.content.is_empty() {
            emitted = emitted.saturating_add(1);
            let _ = sender.send(RunningJobEvent::ChatDelta {
                content: event.content,
            });
        }
        Ok(())
    })?;
    Ok(CommandOutput {
        ok: true,
        rendered: format!("provider: {provider}\nstreamed_chat: {emitted} event(s) shown in chat"),
        chat_approval: None,
    })
}

