    #[derive(Default)]
    struct TestProviderKeyStore {
        secrets: Mutex<BTreeMap<String, Vec<u8>>>,
        fail: Option<&'static str>,
    }

    impl TestProviderKeyStore {
        fn failing(message: &'static str) -> Self {
            Self {
                secrets: Mutex::new(BTreeMap::new()),
                fail: Some(message),
            }
        }

        fn with_secret(provider: &str, secret: &[u8]) -> Self {
            let mut secrets = BTreeMap::new();
            secrets.insert(provider.to_owned(), secret.to_vec());
            Self {
                secrets: Mutex::new(secrets),
                fail: None,
            }
        }

        fn secret(&self, provider: &str) -> Option<Vec<u8>> {
            self.secrets.lock().unwrap().get(provider).cloned()
        }
    }

    impl crate::provider_keys::ProviderKeyStore for TestProviderKeyStore {
        fn label(&self) -> &'static str {
            "test keychain"
        }

        fn get_secret(&self, provider: &str) -> anyhow::Result<Option<Vec<u8>>> {
            if let Some(message) = self.fail {
                anyhow::bail!("{message}");
            }
            Ok(self.secrets.lock().unwrap().get(provider).cloned())
        }

        fn set_secret(&self, provider: &str, secret: &[u8]) -> anyhow::Result<()> {
            if let Some(message) = self.fail {
                anyhow::bail!("{message}");
            }
            self.secrets
                .lock()
                .unwrap()
                .insert(provider.to_owned(), secret.to_vec());
            Ok(())
        }

        fn clear_secret(&self, provider: &str) -> anyhow::Result<()> {
            if let Some(message) = self.fail {
                anyhow::bail!("{message}");
            }
            self.secrets.lock().unwrap().remove(provider);
            Ok(())
        }
    }

    #[test]
