    #[test]
    fn activity_log_keeps_recent_bounded_events() {
        let mut app = test_app();
        for index in 0..(super::MAX_ACTIVITY_LOG_ITEMS + 2) {
            app.record_activity(format!("event-{index}"));
        }

        let rendered = app.activity_text();

        assert!(!rendered.contains("event-0"));
        assert!(!rendered.contains("event-1"));
        assert!(rendered.contains("event-2"));
        assert!(rendered.contains(&format!("event-{}", super::MAX_ACTIVITY_LOG_ITEMS + 1)));
        let newest = format!("event-{}", super::MAX_ACTIVITY_LOG_ITEMS + 1);
        assert_eq!(rendered.lines().next(), Some(newest.as_str()));
        assert_eq!(app.activity_log.len(), super::MAX_ACTIVITY_LOG_ITEMS);
    }

