    #[test]
    fn initial_activity_log_loads_recent_lifecycle_lines() -> anyhow::Result<()> {
        let (root, paths) = test_paths("activity-lifecycle");
        let logs_dir = paths.data_dir.join("logs");
        fs::create_dir_all(&logs_dir)?;
        fs::write(
            logs_dir.join("cli-lifecycle.log"),
            "1 level=info category=a action=one message=first\n2 level=info category=b action=two message=second\n3 level=info category=c action=three message=third\n",
        )?;

        let log = super::initial_activity_log(&paths);
        let rendered = log.iter().cloned().collect::<Vec<_>>().join("\n");
        let display = {
            let mut app = test_app();
            app.activity_log = log.clone();
            app.activity_text()
        };

        assert!(rendered.contains("log: two - second"));
        assert!(rendered.contains("log: three - third"));
        assert!(rendered.contains("TUI ready."));
        assert!(!rendered.contains("log: one"));
        assert_eq!(display.lines().next(), Some("TUI ready."));
        fs::remove_dir_all(root).ok();
        Ok(())
    }

