    #[test]
    fn logs_completion_suggests_service_flag_before_service_ids() -> anyhow::Result<()> {
        let mut app = test_app();
        app.paths.ensure()?;
        let record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen",
            "pytorch",
            "qwen",
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
            "127.0.0.1",
            11435,
            "managed",
            std::process::id(),
            None,
            None,
            None,
        );
        record.write()?;

        app.set_input("/logs ".to_owned());
        let menu = app
            .slash_completion_menu()
            .expect("logs command should suggest flags and services");

        assert_eq!(menu.items.first().map(String::as_str), Some("--service"));
        assert!(menu.items.iter().any(|item| item == "--search"));
        assert!(menu.items.iter().any(|item| item == "next"));
        assert!(menu.items.iter().any(|item| item == "prev"));
        assert!(menu.items.iter().any(|item| item == "refresh"));
        assert!(menu.items.iter().any(|item| item == "svc-qwen"));

        app.set_input("/logs --service ".to_owned());
        let menu = app
            .slash_completion_menu()
            .expect("service flag should suggest service ids");
        assert_eq!(menu.items, vec!["svc-qwen".to_owned()]);
        Ok(())
    }

    #[test]
    fn slash_completion_scrolls_through_full_suggestion_set() {
        let mut app = test_app();
        app.set_input("/".to_owned());

        for _ in 0..super::MAX_COMPLETION_MENU_ITEMS {
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }

        let menu = app
            .slash_completion_menu()
            .expect("slash input should still render suggestions");
        let (start, end) = super::completion_visible_range(&menu);

        assert!(menu.items.len() > super::MAX_COMPLETION_MENU_ITEMS);
        assert_eq!(menu.selected, super::MAX_COMPLETION_MENU_ITEMS);
        assert!(start > 0);
        assert_eq!(end - start, super::MAX_COMPLETION_MENU_ITEMS);
        assert!(menu.selected > start);
        assert!(menu.selected < end - 1);
        assert!(
            !menu.items[start..end]
                .iter()
                .any(|item| item.contains("more"))
        );
    }

