    #[test]
    fn slash_actions_stream_inside_active_surface_without_transcript_dump() {
        for (command, title) in [
            ("runtimes", "Runtimes"),
            ("install", "Install"),
            ("engine", "Engine"),
            ("serve", "Serve"),
            ("update", "Update"),
            ("automations", "Automations"),
            ("services", "Services"),
            ("chat hello", "Serve"),
            ("plan serve a model", "Plan"),
            ("uninstall", "Uninstall"),
        ] {
            let mut app = test_app();
            assert!(app.handle_command(command), "{command}");
            let before = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{command} should open a selected surface"));

            let (sender, receiver) = mpsc::channel();
            app.running_job = Some(super::RunningJob {
                title: title.to_owned(),
                kind: super::RunningJobKind::Cli,
                receiver,
                started_at: Instant::now(),
                streamed_lines: 0,
                streamed_stdout_lines: 0,
                streamed_stderr_lines: 0,
            });
            sender
                .send(super::RunningJobEvent::Stream {
                    stream: super::CommandOutputStream::Stdout,
                    line: "progress shown live".to_owned(),
                })
                .unwrap();
            sender
                .send(super::RunningJobEvent::Finished(Ok(super::CommandOutput {
                    ok: true,
                    rendered: format!(
                        "command: rocm {command}\nstatus: ok\n\nstdout:\nfinished {command}"
                    ),
                    chat_approval: None,
                })))
                .unwrap();

            app.poll_running_job();

            let after = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{command} should keep its active surface"));
            assert_eq!(after.surface, before.surface, "{command}");
            assert_eq!(active_tui_surface_count(&app), 1, "{command}");
            assert!(app.transcript.is_empty(), "{command}");
            let rendered = render_test_terminal(&app, 140, 32);
            assert!(
                !rendered.contains("command: rocm") && !rendered.contains("status: ok"),
                "{command} should hide raw command labels\n{rendered}"
            );
            assert!(
                !rendered.contains("Live output") && !rendered.contains("Recent output"),
                "{command} should stay terse after completion\n{rendered}"
            );
        }
    }

