    #[test]
    fn clear_and_quit_do_not_steal_running_install_screen() {
        for command in ["clear", "quit", "exit"] {
            let mut app = test_app();
            assert!(app.handle_command("install"));
            let (sender, receiver) = mpsc::channel();
            app.running_job = Some(super::RunningJob {
                title: "Install".to_owned(),
                kind: super::RunningJobKind::Cli,
                receiver,
                started_at: Instant::now(),
                streamed_lines: 0,
                streamed_stdout_lines: 0,
                streamed_stderr_lines: 0,
            });

            assert!(app.handle_command(command), "{command}");

            assert!(app.install_manager.is_some(), "{command}");
            assert!(app.command_screen.is_none(), "{command}");
            assert!(!app.should_quit, "{command}");
            assert!(
                app.status
                    .contains("Install is still running. Wait for it to finish"),
                "{command}: {}",
                app.status
            );

            sender
                .send(super::RunningJobEvent::Stream {
                    stream: super::CommandOutputStream::Stdout,
                    line: format!("{command} did not steal the install screen"),
                })
                .unwrap();
            app.poll_running_job();

            let rendered = render_test_terminal(&app, 120, 28);
            assert!(rendered.contains("Install is working."), "{command}");
            assert!(
                rendered.contains(&format!("{command} did not steal the install screen")),
                "{command}"
            );
            assert!(
                app.install_manager
                    .as_ref()
                    .and_then(|state| state.message.as_deref())
                    .is_some_and(|message| message
                        .contains(&format!("{command} did not steal the install screen"))),
                "{command}"
            );
            assert!(app.transcript.is_empty(), "{command}");
        }
    }

