    #[test]
    fn advertised_slash_commands_accept_tab_home_and_end_navigation_on_opened_surface() {
        for command in super::SLASH_COMMANDS {
            let mut app = test_app();

            assert!(app.handle_command(command.name), "{}", command.name);

            let before = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{} should have a selected row", command.name));

            handle_key(&mut app, key_event(KeyCode::Tab, KeyModifiers::NONE));
            let after_tab = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{} should keep focus after Tab", command.name));
            assert_eq!(after_tab.surface, before.surface, "{}", command.name);
            if before.row_count > 1 {
                assert_ne!(
                    after_tab.selected, before.selected,
                    "{} should move the highlighted row with Tab",
                    command.name
                );
            }

            handle_key(&mut app, key_event(KeyCode::Home, KeyModifiers::NONE));
            let after_home = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{} should keep focus after Home", command.name));
            assert_eq!(after_home.surface, before.surface, "{}", command.name);
            if before.row_count > 0 {
                assert_eq!(
                    after_home.selected, 0,
                    "{} should move to the first row with Home",
                    command.name
                );
            }

            handle_key(&mut app, key_event(KeyCode::End, KeyModifiers::NONE));
            let after_end = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{} should keep focus after End", command.name));
            assert_eq!(after_end.surface, before.surface, "{}", command.name);
            if before.row_count > 0 {
                assert_eq!(
                    after_end.selected,
                    before.row_count.saturating_sub(1),
                    "{} should move to the last row with End",
                    command.name
                );
            }

            assert!(app.input.is_empty(), "{}", command.name);
            assert!(app.transcript.is_empty(), "{}", command.name);
        }
    }

    #[test]
    fn advertised_slash_commands_keep_arrow_focus_after_accidental_typing() {
        for command in super::SLASH_COMMANDS {
            let mut app = test_app();

            assert!(app.handle_command(command.name), "{}", command.name);

            let before = active_surface_selection(&app)
                .unwrap_or_else(|| panic!("{} should have a selected row", command.name));

            handle_key(&mut app, key_event(KeyCode::Char('z'), KeyModifiers::NONE));
            let prompt_visible = super::should_draw_prompt_box(&app);
            if prompt_visible {
                assert_eq!(app.input, "z", "{}", command.name);
            } else {
                assert!(app.input.is_empty(), "{}", command.name);
            }
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));

            let after = active_surface_selection(&app).unwrap_or_else(|| {
                panic!("{} should keep a selected row after Down", command.name)
            });
            assert_eq!(
                before.surface, after.surface,
                "{} should keep the visible screen focused",
                command.name
            );
            if before.row_count > 1 {
                if command.name == "home" {
                    assert_ne!(
                        before.selected, after.selected,
                        "home should keep arrow focus because no prompt is visible"
                    );
                } else {
                    assert_ne!(
                        before.selected, after.selected,
                        "{} should move the screen highlight even after accidental typing",
                        command.name
                    );
                }
            }
            if prompt_visible {
                assert_eq!(app.input, "z", "{}", command.name);
            } else {
                assert!(app.input.is_empty(), "{}", command.name);
            }
            assert!(app.transcript.is_empty(), "{}", command.name);

            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

            if command.name == "setup" {
                if app.folder_browser.is_some() {
                    assert!(
                        !app.onboarding_path_editing,
                        "{} should use the folder picker before manual typing",
                        command.name
                    );
                } else {
                    assert_eq!(
                        active_surface_selection(&app).unwrap().surface,
                        "overlay",
                        "{} should keep setup inside a focused confirmation card",
                        command.name
                    );
                }
            } else {
                assert!(
                    app.input.is_empty(),
                    "{} should clear accidental prompt text before screen action",
                    command.name
                );
            }
            assert!(app.transcript.is_empty(), "{}", command.name);
        }
    }

    #[test]
    fn advertised_slash_commands_escape_once_after_accidental_typing_returns_home() {
        for command in super::SLASH_COMMANDS {
            let mut app = test_app();

            assert!(app.handle_command(command.name), "{}", command.name);

            handle_key(&mut app, key_event(KeyCode::Char('z'), KeyModifiers::NONE));
            handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));

            if command.name == "setup" {
                assert!(app.onboarding_active, "{}", command.name);
                assert!(
                    app.status.contains("Quit setup selected"),
                    "setup should select the visible Quit setup row before ROCm is ready"
                );
            } else if command.name == "home" {
                assert_eq!(active_tui_surface_count(&app), 1, "{}", command.name);
                assert_eq!(
                    active_surface_selection(&app).unwrap().surface,
                    "overlay",
                    "{} should focus the quit card",
                    command.name
                );
            } else {
                assert!(app.input.is_empty(), "{}", command.name);
                assert_eq!(active_tui_surface_count(&app), 1, "{}", command.name);
                assert_eq!(
                    active_surface_selection(&app).unwrap().surface,
                    "home",
                    "{} should land on Home after one Esc",
                    command.name
                );
            }
            assert!(app.transcript.is_empty(), "{}", command.name);
        }
    }

