    #[test]
    fn config_clear_provider_key_requires_arrow_key_confirmation() {
        let store = Arc::new(TestProviderKeyStore::with_secret("openai", b"sk-test"));
        let mut app = test_app();
        app.provider_key_store = store.clone();

        assert!(app.handle_command("config clear-provider-key openai"));

        assert!(!app.config_manager_confirming_provider_clear());
        assert!(app.overlay_card.is_some());
        assert_eq!(store.secret("openai"), Some(b"sk-test".to_vec()));
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Clear API Key"));
        assert!(rendered.contains("Clear the saved OpenAI API key?"));
        assert!(rendered.contains("Clear API key"));
        assert!(rendered.contains("Keep key"));
        assert!(app.transcript.is_empty());

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(!app.config_manager_confirming_provider_clear());
        assert!(app.overlay_card.is_none());
        assert_eq!(store.secret("openai"), Some(b"sk-test".to_vec()));
        assert!(app.status.contains("kept"));

        assert!(app.handle_command("config clear-provider-key openai"));
        assert!(app.overlay_card.is_some());
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert_eq!(store.secret("openai"), None);
        assert!(app.overlay_card.is_none());
        assert!(!app.config_manager_confirming_provider_clear());
        assert!(app.status.contains("cleared"));
        let message = app
            .config_manager
            .as_ref()
            .and_then(|state| state.message.as_deref())
            .expect("settings message");
        assert!(message.contains("OpenAI API key cleared"));
        assert!(app.transcript.is_empty());
    }

