    #[test]
    fn config_manager_show_setup_again_requires_confirmation_and_defaults_to_keep()
    -> anyhow::Result<()> {
        let mut app = test_app();
        app.config.onboarding_dismissed = true;
        app.config.setup.completed = true;
        app.config.save(&app.paths)?;

        assert!(app.handle_command("config"));
        let setup_index = super::config_menu_choices()
            .iter()
            .position(|choice| *choice == super::ConfigMenuChoice::ShowSetupAgain)
            .expect("setup reset row should exist");
        for _ in 0..setup_index {
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }

        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Show setup again"));
        assert!(rendered.contains("This does not uninstall ROCm"));
        assert!(rendered.contains("API keys stay saved"));
        assert!(rendered.contains("Provider settings stay saved"));

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(app.overlay_card.is_some());
        assert_eq!(
            app.overlay_card.as_ref().map(|state| state.title.as_str()),
            Some("First-time Setup")
        );
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Keep settings"));
        assert!(rendered.contains("Show setup again"));
        assert!(rendered.contains("ROCm installs stay on this computer"));
        assert!(app.config_manager.is_some());
        assert!(app.transcript.is_empty());

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(app.overlay_card.is_none());
        assert!(app.config_manager.is_some());
        assert!(!app.onboarding_active);
        assert!(RocmCliConfig::load(&app.paths)?.onboarding_dismissed);
        assert_eq!(app.status, "Setup settings were kept.");

        app.select_config_menu_choice(super::ConfigMenuChoice::ShowSetupAgain);
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.overlay_card.is_some());
        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));

        assert!(app.overlay_card.is_none());
        assert!(app.config_manager.is_some());
        assert!(!app.onboarding_active);
        assert!(RocmCliConfig::load(&app.paths)?.onboarding_dismissed);
        assert_eq!(app.status, "Setup settings were kept.");
        Ok(())
    }

