    #[test]
    fn services_manager_hides_failed_service_but_direct_logs_still_work() -> anyhow::Result<()> {
        let mut app = test_app();
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen",
            "pytorch",
            "qwen",
            "Qwen/Qwen3.5",
            "127.0.0.1",
            11435,
            "managed",
            std::process::id(),
            None,
            None,
            None,
        );
        record.status = "failed".to_owned();
        record.write()?;
        fs::write(&record.log_path, "service ready\n")?;
        assert!(app.handle_command("services"));

        let state = app.services_manager.as_ref().expect("services screen");
        assert!(state.items.is_empty());
        let rendered = render_test_terminal(&app, 120, 24);
        assert!(!rendered.contains("svc-qwen"), "{rendered}");

        app.open_service_logs_browser(record.service_id.clone());
        assert!(app.logs_view.is_some());
        assert!(app.services_manager.is_none());
        assert!(app.transcript.is_empty());
        let rendered = render_test_terminal(&app, 120, 24);
        assert!(rendered.contains("Service Log"));
        assert!(rendered.contains("service ready"));
        assert!(rendered.contains("Show file locations"));
        assert!(!rendered.contains("service_id:"));
        assert!(!rendered.contains("manifest:"));
        assert!(!rendered.contains("log:"));
        assert!(!rendered.contains(&record.manifest_path.display().to_string()));
        assert!(!rendered.contains(&record.log_path.display().to_string()));

        let file_locations_index = super::logs_view_actions()
            .iter()
            .position(|action| *action == super::LogsViewAction::ToggleFileLocations)
            .expect("file locations action should exist");
        let current_index = app
            .logs_view
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        let steps = (file_locations_index + super::logs_view_actions().len() - current_index)
            % super::logs_view_actions().len();
        for _ in 0..steps {
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let rendered = render_test_terminal(&app, 120, 24);
        assert!(rendered.contains("File Locations"), "{rendered}");
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert!(state.show_file_locations);
        let selected_before = state.selected;
        let modal = state
            .detail_modal
            .as_ref()
            .expect("file locations should open a modal card");
        assert!(
            modal
                .detail
                .contains(&record.log_path.display().to_string())
        );
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert_eq!(state.selected, selected_before);
        assert!(
            state
                .detail_modal
                .as_ref()
                .is_some_and(|modal| modal.scroll > 0)
        );
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert_eq!(state.selected, selected_before);
        assert!(state.detail_modal.is_some());
        for key in [
            key_event(KeyCode::Char('r'), KeyModifiers::NONE),
            key_event(KeyCode::Char('f'), KeyModifiers::NONE),
            key_event(KeyCode::Char('s'), KeyModifiers::NONE),
            key_event(KeyCode::Char('?'), KeyModifiers::NONE),
            key_event(KeyCode::Char('l'), KeyModifiers::CONTROL),
            key_event(KeyCode::Char('x'), KeyModifiers::NONE),
        ] {
            handle_key(&mut app, key);
            let state = app.logs_view.as_ref().expect("logs view should stay open");
            assert_eq!(state.selected, selected_before);
            assert!(state.detail_modal.is_some());
            assert!(!state.follow);
            assert!(app.overlay_card.is_none());
            assert!(app.input.is_empty());
        }
        handle_key(&mut app, key_event(KeyCode::PageDown, KeyModifiers::NONE));
        assert!(
            app.logs_view
                .as_ref()
                .and_then(|state| state.detail_modal.as_ref())
                .is_some_and(|modal| modal.scroll > 0)
        );
        assert!(
            !app.logs_view
                .as_ref()
                .expect("logs view should stay open")
                .last_rendered
                .contains(&record.log_path.display().to_string())
        );
        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        let rendered = render_test_terminal(&app, 120, 24);
        assert!(rendered.contains("Show file locations"), "{rendered}");
        assert!(!rendered.contains(&record.log_path.display().to_string()));
        assert!(
            app.logs_view
                .as_ref()
                .expect("logs view should stay open")
                .detail_modal
                .is_none()
        );
        Ok(())
    }

