    #[test]
    fn served_model_chat_accepts_typed_messages_and_uses_selected_model() -> anyhow::Result<()> {
        let mut app = test_app();
        let (port, request_receiver) =
            spawn_fake_local_chat_server_repeated("ROCm is ready for local work.", 2)?;
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen",
            "pytorch",
            "qwen",
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
            "127.0.0.1",
            port,
            "managed",
            123,
            None,
            None,
            None,
        );
        record.status = "ready".to_owned();
        record.write()?;
        assert!(app.handle_command("services"));

        let chat_index = app
            .services_manager
            .as_ref()
            .and_then(|state| {
                super::services_manager_actions(state)
                    .iter()
                    .position(|action| *action == super::ServicesManagerAction::Chat)
                    .map(|index| state.items.len() + index)
            })
            .expect("chat action row should exist");
        for _ in 0..chat_index {
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(app.command_screen_is_chat_session(), "{rendered}");
        assert!(
            app.command_screen
                .as_ref()
                .and_then(|state| state.detail_modal.as_ref())
                .is_none(),
            "empty Enter should keep focus in the chat prompt"
        );
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Type your message below"));
        assert!(rendered.contains("Assistant"));
        assert!(!rendered.contains("> Send message"));
        assert!(!rendered.contains("Connection Details"));

        app.set_input("Is ROCm installed?".to_owned());
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Enter sends | PageUp/PageDown scroll chat"));
        assert!(!rendered.contains("Up/Down choose"));
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        assert_eq!(app.input, "Is ROCm installed?");
        assert_ne!(app.status, "Option selected. Press Enter to continue.");
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("You"));
        assert!(rendered.contains("Is ROCm installed?"));
        assert!(rendered.contains("Assistant is thinking."));
        assert!(!rendered.contains("Live progress"));

        let request = request_receiver.recv_timeout(Duration::from_secs(5))?;
        assert_eq!(
            request.get("model").and_then(Value::as_str),
            Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL)
        );
        assert_eq!(
            request.get("tool_choice").and_then(Value::as_str),
            Some("auto")
        );
        let messages = request
            .get("messages")
            .and_then(Value::as_array)
            .expect("chat request should include messages");
        assert!(messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message
                    .get("content")
                    .and_then(Value::as_str)
                    .is_some_and(|content| content.contains("Is ROCm installed?"))
        }));

        poll_app_until_idle(&mut app);
        assert!(app.running_job.is_none());
        let session = app
            .command_screen
            .as_ref()
            .and_then(|state| state.chat_session.as_ref())
            .expect("chat session should stay open");
        assert!(session.turns.iter().any(|turn| {
            turn.role == super::ChatSessionRole::User && turn.content.contains("Is ROCm installed?")
        }));
        let assistant_content = session
            .turns
            .iter()
            .find(|turn| turn.role == super::ChatSessionRole::Assistant)
            .map(|turn| turn.content.as_str())
            .unwrap_or("<missing>");
        assert!(
            assistant_content.contains("Here is what I found on this computer.")
                && (assistant_content.contains("GPU:")
                    || assistant_content.contains("WSL DXCore and ROCDXG plumbing detected"))
                && assistant_content.contains("ROCm/TheRock:"),
            "{assistant_content}"
        );
        let assistant = session
            .turns
            .iter()
            .find(|turn| turn.role == super::ChatSessionRole::Assistant)
            .expect("assistant turn should be stored");
        assert!(!assistant.content.contains("chat response"));
        assert!(!assistant.content.contains("provider:"));
        assert!(!assistant.content.contains("ROCm checks used"));
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("You"));
        assert!(rendered.contains("Is ROCm installed?"));
        assert!(rendered.contains("Assistant"));
        assert!(rendered.contains("Here is what I found on this computer."));
        assert!(
            rendered.contains("GPU:")
                || rendered.contains("WSL DXCore and ROCDXG plumbing detected")
        );
        assert!(!rendered.contains("Live progress"));
        assert!(app.transcript.is_empty());

        app.set_input("What local models are running?".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(app.command_screen_is_chat_session());
        assert!(app.serve_wizard.is_none());
        assert!(app.running_job.is_some());
        let followup_request = request_receiver.recv_timeout(Duration::from_secs(5))?;
        assert_eq!(
            followup_request.get("model").and_then(Value::as_str),
            Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL)
        );
        let followup_messages = followup_request
            .get("messages")
            .and_then(Value::as_array)
            .expect("follow-up request should include messages");
        assert!(followup_messages.iter().any(|message| {
            message.get("role").and_then(Value::as_str) == Some("user")
                && message
                    .get("content")
                    .and_then(Value::as_str)
                    .is_some_and(|content| {
                        content.contains("Conversation so far:")
                            && content.contains("What local models are running?")
                    })
        }));
        poll_app_until_idle(&mut app);
        assert!(app.command_screen_is_chat_session());
        assert!(app.serve_wizard.is_none());
        assert!(app.transcript.is_empty());
        Ok(())
    }

