    #[test]
    fn chat_install_prompt_waits_for_folder_then_opens_review_without_model_guess()
    -> anyhow::Result<()> {
        let mut app = test_app();
        let (port, request_receiver) =
            spawn_fake_local_chat_server("This model response should not be used.")?;
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen25",
            "pytorch",
            "qwen",
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
            "127.0.0.1",
            port,
            "managed",
            123,
            None,
            None,
            None,
        );
        record.status = "ready".to_owned();
        record.write()?;
        app.open_local_rocm_tools_chat_session(Some(record));

        app.set_input("how do I get it to install therock?".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(
            request_receiver
                .recv_timeout(Duration::from_millis(150))
                .is_err()
        );
        assert!(app.command_screen_is_chat_session());
        assert!(app.running_job.is_none());
        assert!(app.pending_approval.is_none());
        assert!(app.folder_browser.is_some());
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Choose ROCm Folder"), "{rendered}");
        assert!(rendered.contains("Use current folder"), "{rendered}");
        assert!(!rendered.contains("I checked ROCm"), "{rendered}");

        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        app.set_input("use D:\\jam\\temp\\therock_venvs".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(
            request_receiver
                .recv_timeout(Duration::from_millis(150))
                .is_err()
        );
        assert!(app.command_screen_is_chat_session());
        assert!(app.running_job.is_none());
        let pending = app
            .pending_approval
            .as_ref()
            .expect("folder reply should open review card");
        assert_eq!(pending.title, "Install ROCm");
        assert!(
            matches!(
                &pending.action,
                super::ApprovalAction::CliCommand {
                    args,
                    display_command: Some(display),
                    ..
                } if args.windows(2).any(|pair| {
                    pair[0] == "--prefix" && pair[1] == "D:\\jam\\temp\\therock_venvs"
                })
                    && display.contains("D:\\jam\\temp\\therock_venvs")
            ),
            "{pending:#?}"
        );
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Install ROCm"), "{rendered}");
        assert!(!rendered.contains("Review this change"), "{rendered}");
        assert!(!rendered.contains("What will happen"), "{rendered}");
        assert!(
            rendered.contains("D:\\jam\\temp\\therock_venvs"),
            "{rendered}"
        );
        assert!(!rendered.contains("I checked ROCm"), "{rendered}");
        Ok(())
    }

    #[test]
    fn assistant_tui_support_prompts_reach_validated_local_model() -> anyhow::Result<()> {
        for prompt in [
            "is therock setup on my machine",
            "which gpu is on my machine",
            "how do i setup comfyui",
            "which llms can my machine support",
        ] {
            let mut app = test_app();
            let (port, request_receiver) = spawn_fake_local_chat_server_repeated(
                "I can help with that from inside ROCm CLI.",
                2,
            )?;
            let mut record = ManagedServiceRecord::new(
                &app.paths,
                "svc-qwen25",
                "pytorch",
                "qwen",
                super::VALIDATED_LOCAL_ASSISTANT_MODEL,
                "127.0.0.1",
                port,
                "managed",
                123,
                None,
                None,
                None,
            );
            record.status = "ready".to_owned();
            record.write()?;
            app.open_local_rocm_tools_chat_session(Some(record));

            app.set_input(prompt.to_owned());
            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

            let request = request_receiver
                .recv_timeout(Duration::from_secs(5))
                .map_err(|error| {
                    anyhow::anyhow!("expected model request for prompt `{prompt}`: {error}")
                })?;
            assert_eq!(
                request.get("model").and_then(Value::as_str),
                Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL),
                "{prompt}"
            );
            assert_eq!(
                request.get("tool_choice").and_then(Value::as_str),
                Some("auto"),
                "{prompt}"
            );
            let messages = request
                .get("messages")
                .and_then(Value::as_array)
                .expect("chat request should include messages");
            assert!(
                !messages
                    .iter()
                    .any(|message| message.get("role").and_then(Value::as_str) == Some("system")),
                "local server request should fold system guidance into user content for {prompt}"
            );
            assert!(
                messages.iter().any(|message| {
                    message.get("role").and_then(Value::as_str) == Some("user")
                        && message
                            .get("content")
                            .and_then(Value::as_str)
                            .is_some_and(|content| {
                                content.contains("ROCm CLI guidance")
                                    && content.contains("which GPU is on this machine")
                                    && content.contains("Qwen3-4B-Instruct-2507-GGUF")
                                    && content.contains("ComfyUI")
                                    && content.contains(prompt)
                            })
                }),
                "user prompt and ROCm guidance should be sent in one local-compatible message for {prompt}"
            );

            poll_app_until_idle(&mut app);
            assert!(app.running_job.is_none(), "{prompt}");
            let session = app
                .command_screen
                .as_ref()
                .and_then(|state| state.chat_session.as_ref())
                .expect("chat session should stay open");
            assert_eq!(
                session.model.as_deref(),
                Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL)
            );
            assert!(session.turns.iter().any(|turn| {
                turn.role == super::ChatSessionRole::User && turn.content == prompt
            }));
            let assistant_turn = session
                .turns
                .iter()
                .find(|turn| turn.role == super::ChatSessionRole::Assistant)
                .expect("assistant turn should be stored");
            assert!(
                !assistant_turn.content.contains("I checked ROCm"),
                "{prompt}: {}",
                assistant_turn.content
            );
            if prompt == "how do i setup comfyui" {
                assert!(
                    assistant_turn
                        .content
                        .contains("I can help with that from inside ROCm CLI.")
                        || assistant_turn.content.contains("ComfyUI"),
                    "{prompt}: {}",
                    assistant_turn.content
                );
            } else {
                assert!(
                    assistant_turn
                        .content
                        .contains("Here is what I found on this computer.")
                        || assistant_turn
                            .content
                            .contains("I can help with that from inside ROCm CLI."),
                    "{prompt}: {}",
                    assistant_turn.content
                );
            }
            assert!(app.transcript.is_empty());
        }
        Ok(())
    }

    #[test]
    fn assistant_support_prompts_from_home_route_to_chat_or_guided_start() -> anyhow::Result<()> {
        for prompt in [
            "is therock setup on my machine",
            "which gpu is on my machine",
            "how do i setup comfyui",
            "can you setup comfyui for me",
            "can you setup and serve an llm for me",
            "which llms can my machine support",
        ] {
            let mut app = test_app();
            let (port, request_receiver) =
                spawn_fake_local_chat_server("I can help with ROCm CLI for you.")?;
            let mut record = ManagedServiceRecord::new(
                &app.paths,
                "svc-qwen15",
                "pytorch",
                "qwen",
                super::VALIDATED_LOCAL_ASSISTANT_MODEL,
                "127.0.0.1",
                port,
                "managed",
                123,
                None,
                None,
                None,
            );
            record.status = "ready".to_owned();
            record.write()?;

            app.set_input(prompt.to_owned());
            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

            match request_receiver.recv_timeout(Duration::from_millis(300)) {
                Ok(request) => {
                    assert_eq!(
                        request.get("model").and_then(Value::as_str),
                        Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL),
                        "{prompt}"
                    );
                    assert!(app.command_screen_is_chat_session(), "{prompt}");
                    assert!(app.transcript.is_empty(), "{prompt}");
                    assert!(app.services_manager.is_none(), "{prompt}");
                    assert!(app.doctor_manager.is_none(), "{prompt}");
                    assert!(app.install_manager.is_none(), "{prompt}");
                    poll_app_until_idle(&mut app);
                }
                Err(_) => {
                    let rendered = render_test_terminal(&app, 140, 32);
                    assert!(
                        app.pending_approval.is_some()
                            || app.install_manager.is_some()
                            || app.serve_wizard.is_some(),
                        "{prompt}: {rendered}"
                    );
                    assert!(app.transcript.is_empty(), "{prompt}: {rendered}");
                    assert!(!rendered.contains("I checked ROCm"), "{prompt}: {rendered}");
                    assert!(
                        !rendered.contains("ROCm CLI summary"),
                        "{prompt}: {rendered}"
                    );
                }
            }
        }

        let mut app = test_app();
        app.set_input("which gpu is on my machine".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.serve_wizard.is_some());
        assert!(app.command_screen.is_none());
        assert!(app.transcript.is_empty());
        assert!(
            app.serve_wizard
                .as_ref()
                .and_then(|state| state.message.as_deref())
                .is_some_and(|message| message.contains("local model before I can chat"))
        );

        let mut app = test_app();
        let (port, request_receiver) = spawn_fake_local_chat_server_for_model(
            "This non-assistant model should not be used.",
            "Qwen/Qwen3.5",
        )?;
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-other-ready",
            "pytorch",
            "other",
            "Qwen/Qwen3.5",
            "127.0.0.1",
            port,
            "managed",
            123,
            None,
            None,
            None,
        );
        record.status = "ready".to_owned();
        record.write()?;
        app.set_input("which gpu is on my machine".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.serve_wizard.is_some());
        assert!(app.command_screen.is_none());
        assert!(
            request_receiver
                .recv_timeout(Duration::from_millis(150))
                .is_err()
        );
        Ok(())
    }

