    fn home_non_standard_prompt_routes_to_ready_local_assistant() -> anyhow::Result<()> {
        let mut app = test_app();
        let prompt = "write a tiny poem about GPU fans";
        let (port, request_receiver) = spawn_fake_local_chat_server("Sure, here is a tiny poem.")?;
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen15",
            "pytorch",
            "qwen",
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
            "127.0.0.1",
            port,
            "managed",
            123,
            None,
            None,
            None,
        );
        record.status = "ready".to_owned();
        record.write()?;

        app.set_input(prompt.to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let request = request_receiver.recv_timeout(Duration::from_secs(5))?;
        assert_eq!(
            request.get("model").and_then(Value::as_str),
            Some(super::VALIDATED_LOCAL_ASSISTANT_MODEL)
        );
        assert!(app.command_screen_is_chat_session());
        assert!(app.transcript.is_empty());
        assert!(
            request
                .get("messages")
                .and_then(Value::as_array)
                .is_some_and(|messages| messages.iter().any(|message| {
                    message.get("role").and_then(Value::as_str) == Some("user")
                        && message
                            .get("content")
                            .and_then(Value::as_str)
                            .is_some_and(|content| content.contains(prompt))
                }))
        );
        poll_app_until_idle(&mut app);
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(
            rendered.contains("Sure, here is a tiny poem."),
            "{rendered}"
        );
        Ok(())
    }

