    #[test]
    fn assistant_tui_install_words_open_folder_picker_without_rocm_check() -> anyhow::Result<()> {
        for prompt in [
            "i need to install rocm",
            "install therock",
            "How do I get it to install therock?",
            "How do I setup TheRock?",
            "rocm please",
            "make my AMD GPU ready",
        ] {
            let mut app = test_app();
            let (port, request_receiver) =
                spawn_fake_local_chat_server("This should not be called.")?;
            let mut record = ManagedServiceRecord::new(
                &app.paths,
                "svc-qwen25",
                "pytorch",
                "qwen",
                super::VALIDATED_LOCAL_ASSISTANT_MODEL,
                "127.0.0.1",
                port,
                "managed",
                123,
                None,
                None,
                None,
            );
            record.status = "ready".to_owned();
            record.write()?;
            app.open_local_rocm_tools_chat_session(Some(record));
            app.push_chat_session_turn(
                super::ChatSessionRole::Assistant,
                "Use /doctor to refresh actual GPU memory fit before starting anything large.\nNative Windows note: Qwen/Qwen3.5-4B uses WSL/Linux through Windows.",
            );

            app.set_input(prompt.to_owned());
            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
            poll_app_until_idle(&mut app);

            assert!(
                request_receiver
                    .recv_timeout(Duration::from_millis(150))
                    .is_err(),
                "{prompt}"
            );
            assert!(app.pending_approval.is_none(), "{prompt}");
            assert!(app.command_screen_is_chat_session(), "{prompt}");
            assert!(app.install_manager.is_none(), "{prompt}");
            assert!(app.folder_browser.is_some(), "{prompt}");
            let rendered = render_test_terminal(&app, 140, 32);
            assert!(rendered.contains("Choose ROCm Folder"), "{rendered}");
            assert!(rendered.contains("Use current folder"), "{rendered}");
            assert!(!rendered.contains("I checked ROCm"), "{rendered}");
            assert!(!rendered.contains("ROCm CLI summary"), "{rendered}");
            assert!(!rendered.contains("Example"), "{rendered}");

            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

            assert!(app.pending_approval.is_some(), "{prompt}");
            assert!(app.folder_browser.is_none(), "{prompt}");
            assert!(app.command_screen_is_chat_session(), "{prompt}");
            let rendered = render_test_terminal(&app, 140, 32);
            assert!(rendered.contains("Install ROCm"), "{rendered}");
            assert!(!rendered.contains("Review this change"), "{rendered}");
            assert!(!rendered.contains("What will happen"), "{rendered}");
        }
        Ok(())
    }

    #[test]
    fn pending_install_folder_answers_status_questions_without_losing_picker() -> anyhow::Result<()>
    {
        let mut app = test_app();
        app.open_local_rocm_tools_chat_session(None);

        app.set_input("install therock".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.folder_browser.is_some());
        assert!(app.pending_approval.is_none());

        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        assert!(app.folder_browser.is_none());
        app.set_input("did you install rocm?".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(app.pending_approval.is_none());
        assert!(app.command_screen_is_chat_session());
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Not yet"), "{rendered}");
        assert!(!rendered.contains("I checked ROCm"), "{rendered}");
        assert!(!rendered.contains("Choose ROCm result"), "{rendered}");

        app.set_input("let me choose".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(app.pending_approval.is_none());
        assert!(app.folder_browser.is_some());
        assert!(app.command_screen_is_chat_session());
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Choose ROCm Folder"), "{rendered}");
        assert!(rendered.contains("Use current folder"), "{rendered}");
        Ok(())
    }

