    #[test]
    fn tool_enabled_chat_emits_progress_and_keeps_approval_reason() -> anyhow::Result<()> {
        let app = test_app();
        let (port, _request_receiver) = spawn_fake_local_chat_server_with_response(
            serde_json::json!({
                "choices": [{
                    "message": {
                        "role": "assistant",
                        "content": "ROCm is not installed yet, so I need to install TheRock first.",
                        "tool_calls": [{
                            "id": "call-1",
                            "type": "function",
                            "function": {
                                "name": "install_sdk",
                                "arguments": "{\"channel\":\"release\",\"format\":\"pip\",\"prefix\":\"D:\\\\jam\\\\temp\\\\therock_venvs\"}"
                            }
                        }]
                    }
                }]
            }),
        )?;
        let mut record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen",
            "pytorch",
            "qwen",
            "Qwen/Qwen3.5",
            "127.0.0.1",
            port,
            "managed",
            123,
            None,
            None,
            None,
        );
        record.status = "ready".to_owned();
        record.write()?;
        let request = crate::providers::ChatRequest {
            model: Some("Qwen/Qwen3.5".to_owned()),
            messages: vec![crate::providers::ChatMessage {
                role: "user".to_owned(),
                content: "help me install ROCm in D:\\jam\\temp\\therock_venvs".to_owned(),
            }],
            max_tokens: None,
            rocm_tools: true,
        };
        let (sender, receiver) = mpsc::channel();

        let output = super::run_provider_chat_stream(&app.paths, "local", &request, &sender)?;

        let progress = receiver
            .try_iter()
            .filter_map(|event| match event {
                super::RunningJobEvent::Stream { line, .. } => Some(line),
                _ => None,
            })
            .collect::<Vec<_>>();
        assert!(
            progress
                .iter()
                .any(|line| line.contains("Preparing a review card")),
            "{progress:#?}"
        );
        assert!(
            progress
                .iter()
                .any(|line| line.contains("Review needed: rocm command"))
        );
        let approval = output
            .chat_approval
            .expect("mutating tool call should request approval");
        assert_eq!(
            approval.explanation.as_deref(),
            Some(
                "I can install ROCm/TheRock into the folder you chose. Review the card before anything downloads or changes."
            )
        );
        Ok(())
    }

    #[test]
    fn chat_session_running_tool_chat_keeps_logs_out_of_conversation() -> anyhow::Result<()> {
        let mut app = test_app();
        let record = ManagedServiceRecord::new(
            &app.paths,
            "svc-qwen25",
            "pytorch",
            "qwen",
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
            "127.0.0.1",
            11435,
            "managed",
            std::process::id(),
            None,
            None,
            None,
        );
        app.open_local_rocm_tools_chat_session(Some(record));
        let sender = attach_running_job(
            &mut app,
            "Chat",
            super::RunningJobKind::Chat {
                provider: "local".to_owned(),
                rocm_tools: true,
            },
        );
        sender
            .send(super::RunningJobEvent::Stream {
                stream: super::CommandOutputStream::Stdout,
                line: "Asking the assistant what to check.".to_owned(),
            })
            .unwrap();
        sender
            .send(super::RunningJobEvent::Stream {
                stream: super::CommandOutputStream::Stdout,
                line: "Checked this computer: done".to_owned(),
            })
            .unwrap();

        app.poll_running_job();

        let detail = super::command_screen_detail_text(&app);
        assert!(detail.contains("Type your message below."));
        assert!(detail.contains("Assistant is thinking."));
        assert!(detail.contains("Changes still need your OK."));
        assert!(!detail.contains("Live progress"));
        assert!(!detail.contains("Output: Asking the assistant what to check."));
        assert!(!detail.contains("Output: Checked this computer: done"));
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Assistant is thinking."));
        assert!(rendered.contains("Changes still need your OK."));
        assert!(!rendered.contains("Live progress"));
        assert!(!rendered.contains("Checked this computer: done"));
        assert!(app.transcript.is_empty());
        Ok(())
    }

