    #[test]
    fn chat_session_cancelled_approval_is_remembered_for_next_prompt() {
        let mut app = test_app();
        app.open_local_rocm_tools_chat_session(None);
        app.request_screen_cli_approval_with_explanation(
            "Install ROCm",
            "Install",
            vec![
                "install".to_owned(),
                "sdk".to_owned(),
                "--channel".to_owned(),
                "release".to_owned(),
                "--format".to_owned(),
                "wheel".to_owned(),
            ],
            Some("rocm install sdk --channel release --format wheel".to_owned()),
            Some("The assistant thinks ROCm needs to be installed.".to_owned()),
        );

        app.cancel_focused_action();

        let session = app
            .command_screen
            .as_ref()
            .and_then(|state| state.chat_session.as_ref())
            .expect("chat session should stay open");
        assert!(session.turns.iter().any(|turn| {
            turn.role == super::ChatSessionRole::Tool
                && turn.content.contains("User cancelled Install ROCm")
                && turn.content.contains("Nothing changed")
        }));
        assert!(app.transcript.is_empty());
        assert_eq!(app.status, "Approval cancelled. You can keep chatting.");

        let prompt = app.chat_session_request_prompt("what now?");
        assert!(prompt.contains("ROCm command result: User cancelled Install ROCm."));
        assert!(prompt.contains("Nothing changed."));
        assert!(prompt.contains("what now?"));
    }

