    #[test]
    fn chat_prompt_streams_inside_command_screen() {
        let mut app = test_app();
        app.provider = "openai".to_owned();
        assert!(app.handle_command("chat hello"));

        assert!(app.running_job.is_none());
        assert!(app.command_screen.is_some());
        assert_eq!(
            app.command_screen
                .as_ref()
                .and_then(|state| state.chat_prompt.as_deref()),
            Some("hello")
        );
        let rendered = render_test_terminal(&app, 120, 24);
        assert!(rendered.contains("Send"));
        assert!(rendered.contains("Edit prompt"));
        assert!(rendered.contains("hello"));
        assert!(app.transcript.is_empty());

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(matches!(
            app.running_job.as_ref().map(|job| &job.kind),
            Some(super::RunningJobKind::Chat { .. })
        ));
        assert!(app.command_screen.is_some());
        assert!(app.transcript.is_empty());

        app.push_chat_delta("hi there");

        assert!(app.transcript.is_empty());
        assert!(
            app.command_screen
                .as_ref()
                .and_then(|state| state.message.as_deref())
                .is_some_and(|message| message.contains("hi there"))
        );
        let rendered = render_test_terminal(&app, 80, 24);
        assert!(rendered.contains("hi there"), "{rendered}");

        for index in 0..80 {
            app.push_chat_delta(&format!("\nstream chunk {index}"));
        }
        let rendered = render_test_terminal(&app, 80, 24);
        assert!(rendered.contains("stream chunk 79"), "{rendered}");
    }

