    #[test]
    fn setup_reset_persists_first_time_setup_prompt_without_deleting_installs() -> anyhow::Result<()>
    {
        let mut app = test_app();
        let runtime_key = "release-pip-gfx120x-all-7-14-0-reset-setup";
        write_test_runtime_with_key(&app.paths, runtime_key, "therock-release:gfx120X-all", 20)?;
        let install_root = app
            .paths
            .data_dir
            .join("runtimes")
            .join("wheel")
            .join(runtime_key);
        app.config.onboarding_dismissed = true;
        app.config.setup.completed = true;
        app.config.setup.therock_venv = Some(install_root.clone());
        app.config.provider_config_mut("openai").enabled = true;
        app.config.save(&app.paths)?;

        assert!(app.handle_command("setup reset"));

        assert!(app.onboarding_active);
        assert!(app.pending_approval.is_none());
        assert!(app.running_job.is_none());
        assert!(app.transcript.is_empty());
        assert!(install_root.join(".rocm-cli-runtime.json").is_file());
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::Primary
        );
        assert!(!app.config.onboarding_dismissed);
        assert!(!app.config.setup.completed);
        assert!(app.config.provider_enabled("openai"));
        let saved = RocmCliConfig::load(&app.paths)?;
        assert!(!saved.onboarding_dismissed);
        assert!(!saved.setup.completed);
        assert!(saved.provider_enabled("openai"));
        assert_eq!(
            app.status,
            "Setup will show again. ROCm installs were not deleted."
        );
        let body = super::render_onboarding_screen_text_with_log_limit(&app, 8);
        let rendered = render_test_terminal(&app, 120, 36);
        assert!(rendered.contains("Set Up ROCm"));
        assert!(body.contains("Up/Down chooses, Enter selects."));
        assert!(!rendered.contains("Review: Uninstall"));

        let restarted = App::new(app.paths.clone(), None);
        assert!(restarted.onboarding_active);
        Ok(())
    }

