    #[test]
    fn setup_show_log_file_toggles_path_on_ready_screen() -> anyhow::Result<()> {
        let mut app = test_app();
        let runtime_key = "release-pip-gfx120x-all-7-14-0a20260601-ready-setup";
        write_test_runtime_with_key(&app.paths, runtime_key, "therock-release:gfx120X-all", 20)?;
        set_test_runtime_version(&app.paths, runtime_key, "7.14.0a20260601")?;
        let install_root = app
            .paths
            .data_dir
            .join("runtimes")
            .join("wheel")
            .join(runtime_key);
        let log_path = app
            .paths
            .data_dir
            .join("logs")
            .join("setup")
            .join("install.log");
        fs::create_dir_all(log_path.parent().expect("log path should have a parent"))?;
        fs::write(
            &log_path,
            "Looking in indexes: https://example.invalid/simple\nSuccessfully installed torch rocm\n",
        )?;
        app.config.setup.therock_venv = Some(install_root);
        app.onboarding_install_full_log = Some(log_path.clone());
        app.push_onboarding_install_log("old installer output kept in memory");
        app.config.save(&app.paths)?;

        assert!(app.handle_command("setup"));

        let hidden_body = super::render_onboarding_screen_text_with_log_limit(&app, 8);
        let hidden = render_test_terminal(&app, 140, 32);
        assert!(hidden_body.contains("version: 7.14.0a20260601 (build 2026-06-01)"));
        assert!(hidden_body.contains("Saved setup log: choose Show install log below to read it."));
        assert!(hidden.contains("Show install log"));
        assert!(!hidden.contains(&log_path.display().to_string()));
        assert!(!hidden.contains("Successfully installed torch rocm"));
        assert!(!hidden.contains("old installer output kept in memory"));
        assert!(!hidden.contains("PageUp/PageDown log"));

        app.select_onboarding_choice(super::OnboardingMenuChoice::ShowLog);
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::ShowLog
        );
        super::handle_onboarding_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let shown = render_test_terminal(&app, 140, 32);
        assert!(shown.contains("Saved Setup Log"));
        assert!(shown.contains("install.log"));
        assert!(shown.contains("Successfully installed torch rocm"));
        assert!(!shown.contains("old installer output kept in memory"));
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::ShowLog
        );
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::ShowLog
        );
        assert!(app.overlay_card.is_some());
        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        assert!(app.overlay_card.is_none());
        let hidden_again = render_test_terminal(&app, 140, 32);
        assert!(hidden_again.contains("Show install log"));
        assert!(!hidden_again.contains(&log_path.display().to_string()));
        Ok(())
    }

