    fn onboarding_folder_row_cycles_presets_with_arrow_keys() -> anyhow::Result<()> {
        let mut app = test_app();
        app.onboarding_active = true;
        app.reset_onboarding_selection();
        let original = super::setup_install_root(&app.paths, &app.config);

        super::handle_onboarding_key(&mut app, key_event(KeyCode::Up, KeyModifiers::NONE));
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::Folder
        );
        super::handle_onboarding_key(&mut app, key_event(KeyCode::Right, KeyModifiers::NONE));

        let changed = super::setup_install_root(&app.paths, &app.config);
        assert_ne!(changed, original);
        assert!(!app.onboarding_path_editing);
        assert!(app.pending_approval.is_none());
        assert!(app.transcript.is_empty());
        assert!(app.status.contains("Install folder changed"));
        let saved = RocmCliConfig::load(&app.paths)?;
        assert_eq!(saved.setup.therock_venv.as_deref(), Some(changed.as_path()));
        Ok(())
    }

