    #[test]
    fn onboarding_path_edit_ctrl_c_opens_quit_overlay_and_preserves_input() {
        let mut app = test_app();
        app.onboarding_active = true;
        app.reset_onboarding_selection();
        let folder = app
            .paths
            .data_dir
            .join("custom-folder-while-reviewing-quit");

        handle_key(&mut app, key_event(KeyCode::Up, KeyModifiers::NONE));
        handle_key(&mut app, key_event(KeyCode::Char('t'), KeyModifiers::NONE));
        assert!(app.onboarding_path_editing);
        app.set_input(folder.display().to_string());
        let editing_rendered = render_test_terminal(&app, 120, 30);
        assert!(editing_rendered.contains("Ctrl-C review quit"));

        handle_key(
            &mut app,
            key_event(KeyCode::Char('c'), KeyModifiers::CONTROL),
        );

        assert!(!app.should_quit);
        assert!(app.onboarding_path_editing);
        assert_eq!(app.input, folder.display().to_string());
        assert_eq!(
            app.overlay_card.as_ref().map(|state| state.title.as_str()),
            Some("Quit")
        );
        let rendered = render_test_terminal(&app, 120, 30);
        assert!(rendered.contains("Quit"));
        assert!(rendered.contains("Stay in ROCm CLI"));

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(!app.should_quit);
        assert!(app.overlay_card.is_none());
        assert!(app.onboarding_path_editing);
        assert_eq!(app.input, folder.display().to_string());
    }

