    #[test]
    fn onboarding_ctrl_c_during_install_confirms_before_cancelling() {
        let mut app = test_app();
        let (_sender, receiver) = mpsc::channel();
        let cancel_requested = Arc::new(AtomicBool::new(false));
        app.onboarding_active = true;
        app.running_job_cancel_requested = Some(Arc::clone(&cancel_requested));
        app.running_job = Some(super::RunningJob {
            title: "Install".to_owned(),
            kind: super::RunningJobKind::Cli,
            receiver,
            started_at: Instant::now(),
            streamed_lines: 0,
            streamed_stdout_lines: 0,
            streamed_stderr_lines: 0,
        });
        app.onboarding_install_log
            .push_back("installer is downloading packages".to_owned());

        super::handle_onboarding_key(
            &mut app,
            key_event(KeyCode::Char('c'), KeyModifiers::CONTROL),
        );

        assert!(!app.should_quit);
        assert!(app.onboarding_cancel_install_confirm);
        assert!(!cancel_requested.load(Ordering::SeqCst));
        let setup_body = super::render_onboarding_screen_text_with_log_limit(&app, 8);
        assert!(setup_body.contains("Setup is running."));
        assert!(!setup_body.contains("installer is downloading packages"));
        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Stop ROCm Install?"));
        assert!(rendered.contains("Installing ROCm"));
        assert!(rendered.contains("> Keep waiting"));
        assert!(rendered.contains("  Stop install"));

        super::handle_onboarding_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        assert!(!app.onboarding_cancel_install_confirm);
        assert!(!cancel_requested.load(Ordering::SeqCst));

        super::handle_onboarding_key(
            &mut app,
            key_event(KeyCode::Char('c'), KeyModifiers::CONTROL),
        );
        super::handle_onboarding_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));

        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("  Keep waiting"));
        assert!(rendered.contains("> Stop install"));

        super::handle_onboarding_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(cancel_requested.load(Ordering::SeqCst));
        assert!(!app.onboarding_cancel_install_confirm);
        assert_eq!(app.onboarding_cancel_install_selection, 0);
        assert!(
            app.onboarding_install_log
                .iter()
                .any(|line| line.contains("Stopping installer"))
        );
        assert!(app.transcript.is_empty());
    }

    #[test]
    fn provider_assisted_plan_runs_as_background_job() {
        let mut app = test_app();
        app.config.planner_provider = Some("local".to_owned());
        app.config
            .save(&app.paths)
            .expect("planner config should save");

        app.push_freeform_plan("Plan", "make my ROCm setup better");

        assert!(matches!(
            app.running_job.as_ref().map(|job| &job.kind),
            Some(super::RunningJobKind::Planner { title, .. }) if title == "Plan"
        ));
        assert!(app.command_screen.is_some());
        assert!(app.transcript.is_empty());
        assert!(
            app.command_screen
                .as_ref()
                .expect("plan screen")
                .detail
                .contains("Planning request")
        );
        assert_eq!(
            app.status,
            "Planning with provider. This may take a moment."
        );
        let rendered = render_test_terminal(&app, 120, 30);
        assert!(rendered.contains("Planning with local."), "{rendered}");
        assert!(rendered.contains("Progress"), "{rendered}");
        assert!(rendered.contains("Request"), "{rendered}");
        let selected_before = app.command_screen.as_ref().unwrap().selected;
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        assert_eq!(
            app.command_screen.as_ref().unwrap().selected,
            selected_before
        );
        assert_eq!(
            app.status,
            "This work is still running. Choices are paused for now."
        );
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert_eq!(
            app.command_screen.as_ref().unwrap().selected,
            selected_before
        );
        assert_eq!(
            app.status,
            "Wait for the running work to finish before choosing another action."
        );

        for _ in 0..20 {
            app.poll_running_job();
            if app.running_job.is_none() {
                break;
            }
            std::thread::sleep(Duration::from_millis(10));
        }

        assert!(app.running_job.is_none());
        let state = app.command_screen.as_ref().expect("plan screen stays open");
        assert!(state.detail.contains("Plan"));
        assert!(state.detail.contains("Edit request"));
        assert!(!state.detail.contains("tool_call:"));
        assert!(!state.detail.contains("intent:"));
        assert!(app.transcript.is_empty());
    }

    #[cfg(unix)]
    #[test]
    fn cancelled_process_streaming_kills_unix_process_group() -> anyhow::Result<()> {
        use std::os::unix::fs::PermissionsExt;

        let root = workspace_test_artifact_dir().join(format!(
            "rocm-cli-cancel-test-{}",
            SystemTime::now().duration_since(UNIX_EPOCH)?.as_nanos()
        ));
        fs::create_dir_all(&root)?;
        let marker = root.join("child-alive");
        let script = root.join("spawn-child.sh");
        fs::write(
            &script,
            format!(
                "#!/bin/sh\n(sleep 30; echo alive > '{}') &\nwait\n",
                marker.display()
            ),
        )?;
        let mut permissions = fs::metadata(&script)?.permissions();
        permissions.set_mode(0o755);
        fs::set_permissions(&script, permissions)?;
        let (sender, _receiver) = mpsc::channel();
        let cancel = Arc::new(AtomicBool::new(false));
        let cancel_for_thread = Arc::clone(&cancel);
        std::thread::spawn(move || {
            std::thread::sleep(Duration::from_millis(100));
            cancel_for_thread.store(true, Ordering::SeqCst);
        });

        let error = super::run_process_streaming(&script, &[], sender, cancel, None)
            .unwrap_err()
            .to_string();
        std::thread::sleep(Duration::from_millis(1500));

        assert!(
            error.contains("command cancelled"),
            "unexpected cancellation error: {error}"
        );
        assert!(!marker.exists());
        fs::remove_dir_all(root).ok();
        Ok(())
    }

