    #[test]
    fn onboarding_failure_render_keeps_raw_errors_below_plain_reason() {
        let cases = [
            (
                "Temporary failure in name resolution",
                "could not reach the download server",
            ),
            (
                "SSL certificate verify failed",
                "secure download check failed",
            ),
            (
                "OSError: [Errno 28] No space left on device",
                "out of space",
            ),
            (
                "Python archive extract failed",
                "could not set up its local Python",
            ),
        ];

        for (raw_error, expected_reason) in cases {
            let mut app = test_app();
            app.onboarding_active = true;
            let command_output = super::render_command_output(
                "rocm",
                &["install".to_owned(), "sdk".to_owned()],
                std::process::Output {
                    status: failed_exit_status(),
                    stdout: Vec::new(),
                    stderr: raw_error.as_bytes().to_vec(),
                },
                None,
            )
            .expect("command output should render");

            app.complete_running_job(
                "Install".to_owned(),
                super::RunningJobKind::Cli,
                Ok(command_output),
                super::StreamedOutputCounts::default(),
            );

            let rendered = render_test_terminal(&app, 160, 34);
            let primary = rendered
                .split("Installer output")
                .next()
                .expect("primary failure section should render");
            let log_path = app
                .onboarding_install_full_log
                .clone()
                .expect("full log path should be saved");
            let full_log = fs::read_to_string(&log_path).expect("full log should be readable");

            assert!(
                primary.contains(expected_reason),
                "primary section `{primary}` did not contain `{expected_reason}`"
            );
            assert!(
                !primary.contains(raw_error),
                "raw error leaked into primary section: {primary}"
            );
            assert!(rendered.contains("Installer output"));
            assert!(rendered.contains(raw_error));
            assert!(rendered.contains("Saved setup log"));
            assert!(!rendered.contains(&log_path.display().to_string()));
            assert!(full_log.contains(raw_error));
        }
    }

    #[test]
    fn onboarding_failed_install_hides_log_path_until_requested() {
        let mut app = test_app();
        app.onboarding_active = true;
        let mut stdout = String::new();
        for index in 1..=1_000 {
            stdout.push_str(&format!("pip progress line {index:04}\n"));
        }
        let command_output = super::render_command_output(
            "rocm",
            &["install".to_owned(), "sdk".to_owned()],
            std::process::Output {
                status: failed_exit_status(),
                stdout: stdout.into_bytes(),
                stderr: b"ERROR: wheel install failed\n".to_vec(),
            },
            None,
        )
        .expect("command output should render");

        app.complete_running_job(
            "Install".to_owned(),
            super::RunningJobKind::Cli,
            Ok(command_output),
            super::StreamedOutputCounts::default(),
        );

        let log_path = app
            .onboarding_install_full_log
            .clone()
            .expect("setup failure should save a full log path");
        let full_log = fs::read_to_string(&log_path).expect("full setup log should be readable");
        let rendered = render_test_terminal(&app, 180, 36);

        assert!(rendered.contains("Install failed"));
        assert!(rendered.contains("Saved setup log"));
        assert!(rendered.contains("Show install log"));
        assert!(!rendered.contains(&log_path.display().to_string()));
        assert!(rendered.contains("ERROR: wheel install failed"));
        assert!(!rendered.contains("showing lines"));
        assert!(full_log.contains("pip progress line 0001"));
        assert!(full_log.contains("pip progress line 1000"));
        assert!(full_log.contains("ERROR: wheel install failed"));
        assert!(!full_log.contains("truncated"));
        assert!(app.onboarding_install_log.len() <= 80);

        super::handle_onboarding_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        assert_eq!(
            app.selected_onboarding_choice(),
            super::OnboardingMenuChoice::ShowLog
        );
        super::handle_onboarding_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        let revealed = render_test_terminal(&app, 180, 36);
        assert!(revealed.contains("Saved Setup Log"));
        assert!(
            revealed.contains(
                log_path
                    .file_name()
                    .and_then(|name| name.to_str())
                    .expect("log path should have a file name")
            )
        );
        assert!(revealed.contains("pip progress line 1000"));

        handle_key(&mut app, key_event(KeyCode::PageDown, KeyModifiers::NONE));
        assert!(
            app.overlay_card
                .as_ref()
                .is_some_and(|card| card.detail_scroll > 0)
        );
        let earlier = render_test_terminal(&app, 180, 36);
        assert!(earlier.contains("pip progress line"));

        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        let hidden_again = render_test_terminal(&app, 180, 36);
        assert!(hidden_again.contains("Show install log"));
        assert!(!hidden_again.contains(&log_path.display().to_string()));
    }

