    #[test]
    fn setup_venv_ready_rejects_runtime_without_saved_install_id() -> anyhow::Result<()> {
        let (_root, paths) = test_paths("setup-runtime-missing-key");
        let runtime_key = "release-pip-gfx120x-all-missing-key";
        write_test_runtime_with_key(&paths, runtime_key, "therock-release:gfx120X-all", 20)?;
        let install_root = paths
            .data_dir
            .join("runtimes")
            .join("wheel")
            .join(runtime_key);
        let local_manifest_path = install_root.join(".rocm-cli-runtime.json");
        let mut manifest: Value = serde_json::from_slice(&fs::read(&local_manifest_path)?)?;
        manifest
            .as_object_mut()
            .expect("test manifest should be an object")
            .remove("runtime_key");
        fs::write(&local_manifest_path, serde_json::to_vec_pretty(&manifest)?)?;
        fs::remove_dir_all(paths.data_dir.join("runtimes").join("registry"))?;
        let mut config = RocmCliConfig::default();
        config.setup.therock_venv = Some(install_root);

        assert!(!super::setup_venv_ready(&paths, &config));
        assert_eq!(
            super::serve_runtime_preflight(&paths, &config)?,
            super::ServeRuntimePreflight::NeedsInstall
        );
        Ok(())
    }

    #[test]
    fn setup_runtime_ready_requires_therock_sdk_root_and_bin() -> anyhow::Result<()> {
        let (_root, paths) = test_paths("setup-runtime-missing-sdk");
        let registry = paths.data_dir.join("runtimes").join("registry");
        fs::create_dir_all(&registry)?;
        let runtime_key = "therock-release-gfx120X-all";
        let install_root = paths
            .data_dir
            .join("runtimes")
            .join("wheel")
            .join(runtime_key);
        let scripts_dir = install_root.join(if cfg!(windows) { "Scripts" } else { "bin" });
        fs::create_dir_all(&scripts_dir)?;
        fs::write(
            scripts_dir.join(if cfg!(windows) {
                "python.exe"
            } else {
                "python"
            }),
            "python",
        )?;
        let manifest = serde_json::json!({
            "runtime_key": runtime_key,
            "runtime_id": "therock-release:gfx120X-all",
            "install_root": install_root,
            "python_executable": scripts_dir.join(if cfg!(windows) { "python.exe" } else { "python" }),
            "rocm_sdk": {
                "import_ok": true,
                "root_path": paths.data_dir.join("missing-sdk-root"),
                "bin_path": paths.data_dir.join("missing-sdk-root").join("bin")
            },
            "installed_at_unix_ms": 1
        });
        fs::write(
            registry.join(format!("{runtime_key}.json")),
            serde_json::to_vec_pretty(&manifest)?,
        )?;

        let config = RocmCliConfig::default();

        assert!(!super::setup_venv_ready(&paths, &config));
        Ok(())
    }

