    #[test]
    fn slash_completion_covers_supported_aliases_and_settings() -> anyhow::Result<()> {
        let (_root, paths) = test_paths("slash-completion-supported-aliases");
        write_test_runtime_with_key(&paths, "runtime-a", "therock-release:gfx120X-all", 1)?;

        for (input, expected) in [
            (
                "/config ",
                vec![
                    "set-provider-key",
                    "clear-provider-key",
                    "set-default-runtime",
                ],
            ),
            ("/config set-provider-key ", vec!["openai", "anthropic"]),
            ("/config clear-provider-key ", vec!["openai", "anthropic"]),
            (
                "/config set-default-runtime ",
                vec!["therock-release:gfx120X-all"],
            ),
            ("/runtimes ", vec!["list", "remove"]),
            ("/setup ", vec!["status", "reset", "skip"]),
            ("/automations ", vec!["proposals"]),
            ("/services ", vec!["log"]),
            ("/logs ", vec!["--service", "prev", "follow"]),
            ("/install sdk ", vec!["--channel", "--format", "--prefix"]),
            ("/install sdk --channel ", vec!["release", "nightly"]),
            (
                "/install sdk --format ",
                vec!["Recommended Python install", "Advanced archive install"],
            ),
            ("/install driver ", vec!["--preview"]),
        ] {
            let menu = super::slash_argument_completion_menu(input, &paths, 0)
                .unwrap_or_else(|| panic!("{input} should have completions"));
            for item in expected {
                assert!(
                    menu.items.contains(&item.to_owned()),
                    "{input} should offer {item}; got {:?}",
                    menu.items
                );
            }
        }

        let menu = super::slash_argument_completion_menu("/install sdk --format ", &paths, 0)
            .expect("install type completions should be available");
        assert!(
            !menu
                .items
                .iter()
                .any(|item| item == "wheel" || item == "tarball")
        );
        assert_eq!(
            menu.replacements,
            vec![
                Some("/install sdk --format wheel ".to_owned()),
                Some("/install sdk --format tarball ".to_owned()),
            ]
        );

        for (input, hidden) in [
            ("/logs ", vec!["--service-id", "previous", "unfollow"]),
            (
                "/install driver ",
                vec!["--dkms", "--dry-run", "--yes", "--reconcile"],
            ),
            (
                "/runtimes adopt ",
                vec!["--root", "--runtime-id", "--runtime-key", "--replace"],
            ),
            (
                "/serve tiny.gguf ",
                vec!["--runtime-id", "--env-id", "--allow-public-bind"],
            ),
        ] {
            let menu = super::slash_argument_completion_menu(input, &paths, 0)
                .unwrap_or_else(|| panic!("{input} should have completions"));
            for item in hidden {
                assert!(
                    !menu.items.contains(&item.to_owned()),
                    "{input} should not advertise advanced option {item}; got {:?}",
                    menu.items
                );
            }
        }

        Ok(())
    }

