    #[test]
    fn logs_browser_supports_stateful_next_prev_refresh() -> anyhow::Result<()> {
        let mut app = test_app();
        let action_dir = app.paths.data_dir.join("logs").join("cli");
        fs::create_dir_all(&action_dir)?;
        for file_index in 0..3 {
            let mut body = String::new();
            for line_index in 0..12 {
                body.push_str(&format!("entry-{file_index}-{line_index}\n"));
            }
            fs::write(action_dir.join(format!("test-{file_index}.log")), body)?;
        }

        assert!(app.handle_command("logs"));
        assert_eq!(app.logs_view.as_ref().map(|state| state.page), Some(0));
        assert!(app.transcript.is_empty());
        assert!(
            app.logs_view
                .as_ref()
                .expect("logs should open")
                .last_rendered
                .contains("Page: 1 of 2")
        );

        assert!(app.handle_command("logs next"));
        assert_eq!(app.logs_view.as_ref().map(|state| state.page), Some(1));
        assert!(
            app.logs_view
                .as_ref()
                .expect("logs should stay open")
                .last_rendered
                .contains("Page: 2 of 2")
        );

        assert!(app.handle_command("logs prev"));
        assert_eq!(app.logs_view.as_ref().map(|state| state.page), Some(0));

        assert!(app.handle_command("logs refresh"));
        assert_eq!(app.logs_view.as_ref().map(|state| state.page), Some(0));
        Ok(())
    }

    #[test]
    fn logs_tui_hides_file_locations_until_user_reveals_them() -> anyhow::Result<()> {
        let mut app = test_app();
        fs::create_dir_all(app.paths.data_dir.join("logs"))?;
        fs::write(
            app.paths.data_dir.join("logs").join("cli-lifecycle.log"),
            "1 level=info category=service action=serve message=model ready\n",
        )?;
        let action_dir = app.paths.data_dir.join("logs").join("cli");
        fs::create_dir_all(&action_dir)?;
        fs::write(action_dir.join("service-serve.log"), "model ready\n")?;

        assert!(app.handle_command("logs"));

        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Recent activity"));
        assert!(rendered.contains("Search: none"));
        assert!(rendered.contains("Show file locations"));
        assert!(rendered.contains("PageUp/PageDown scroll"));
        assert!(rendered.contains("Left/Right page"));
        assert!(!rendered.contains("PageUp/PageDown page"));
        assert!(!rendered.contains("cli_lifecycle:"));
        assert!(!rendered.contains("cli_command_dir:"));
        assert!(!rendered.contains("audit_events:"));
        assert!(!rendered.contains("command log"));
        assert!(!rendered.contains("service-serve.log"));
        assert!(!rendered.contains(&app.paths.data_dir.display().to_string()));

        let file_locations_index = super::logs_view_actions()
            .iter()
            .position(|action| *action == super::LogsViewAction::ToggleFileLocations)
            .expect("file locations action should exist");
        let current_index = app
            .logs_view
            .as_ref()
            .map(|state| state.selected)
            .unwrap_or(0);
        let steps = (file_locations_index + super::logs_view_actions().len() - current_index)
            % super::logs_view_actions().len();
        for _ in 0..steps {
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("File Locations"));
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert!(state.show_file_locations);
        let selected_before = state.selected;
        let modal = state
            .detail_modal
            .as_ref()
            .expect("file locations should open a modal card");
        assert!(modal.detail.contains("service-serve.log"));
        assert!(
            modal
                .detail
                .contains(&app.paths.data_dir.join("logs").display().to_string())
        );
        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert_eq!(state.selected, selected_before);
        assert!(
            state
                .detail_modal
                .as_ref()
                .is_some_and(|modal| modal.scroll > 0)
        );
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        let state = app.logs_view.as_ref().expect("logs view should stay open");
        assert_eq!(state.selected, selected_before);
        assert!(state.detail_modal.is_some());
        assert!(
            !app.logs_view
                .as_ref()
                .expect("logs view should stay open")
                .last_rendered
                .contains(&app.paths.data_dir.join("logs").display().to_string())
        );
        assert!(
            !app.logs_view
                .as_ref()
                .expect("logs view should stay open")
                .last_rendered
                .contains("service-serve.log")
        );
        handle_key(&mut app, key_event(KeyCode::Esc, KeyModifiers::NONE));
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Show file locations"));
        assert!(!rendered.contains("service-serve.log"));
        assert!(
            app.logs_view
                .as_ref()
                .expect("logs view should stay open")
                .detail_modal
                .is_none()
        );
        Ok(())
    }

    #[test]
    fn logs_follow_refreshes_when_log_content_changes() -> anyhow::Result<()> {
        let mut app = test_app();
        let action_dir = app.paths.data_dir.join("logs").join("cli");
        fs::create_dir_all(&action_dir)?;
        let log_path = action_dir.join("follow-test.log");
        fs::write(&log_path, "first line\n")?;

        assert!(app.handle_command("logs follow"));
        assert_eq!(app.mode, TuiMode::Logs);
        assert_eq!(app.logs_view.as_ref().map(|state| state.follow), Some(true));
        assert!(app.transcript.is_empty());
        assert!(
            app.logs_view
                .as_ref()
                .expect("logs should open")
                .last_rendered
                .contains("first line")
        );

        fs::write(&log_path, "first line\nsecond line\n")?;
        app.logs_view
            .as_mut()
            .expect("follow state should be open")
            .last_refresh_at =
            Instant::now() - LOG_FOLLOW_REFRESH_INTERVAL - Duration::from_millis(1);
        app.refresh_following_logs();

        assert!(
            app.logs_view
                .as_ref()
                .expect("logs should stay open")
                .last_rendered
                .contains("second line")
        );
        assert!(app.status.contains("Following logs; refreshed"));
        Ok(())
    }

    #[test]
    fn logs_follow_can_be_stopped_or_paged() -> anyhow::Result<()> {
        let mut app = test_app();
        let action_dir = app.paths.data_dir.join("logs").join("cli");
        fs::create_dir_all(&action_dir)?;
        fs::write(action_dir.join("follow-test.log"), "line\n")?;

        assert!(app.handle_command("logs follow"));
        assert_eq!(app.logs_view.as_ref().map(|state| state.follow), Some(true));
        assert_eq!(
            app.selected_logs_view_action(),
            super::LogsViewAction::ToggleFollow
        );

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert_eq!(
            app.logs_view.as_ref().map(|state| state.follow),
            Some(false)
        );

        assert!(app.handle_command("logs next"));
        assert_eq!(
            app.logs_view.as_ref().map(|state| state.follow),
            Some(false)
        );

        assert!(app.handle_command("logs follow"));
        assert!(app.handle_command("logs stop"));
        assert_eq!(
            app.logs_view.as_ref().map(|state| state.follow),
            Some(false)
        );
        assert_eq!(app.status, "Log following stopped.");
        Ok(())
    }

