    #[test]
    fn poll_running_job_caps_stream_events_per_tick() {
        let mut app = test_app();
        let (sender, receiver) = mpsc::channel();
        app.running_job = Some(super::RunningJob {
            title: "Doctor".to_owned(),
            kind: super::RunningJobKind::Cli,
            receiver,
            started_at: Instant::now(),
            streamed_lines: 0,
            streamed_stdout_lines: 0,
            streamed_stderr_lines: 0,
        });

        for index in 0..(super::MAX_STREAM_EVENTS_PER_POLL + 5) {
            sender
                .send(super::RunningJobEvent::Stream {
                    stream: super::CommandOutputStream::Stdout,
                    line: format!("line-{index}"),
                })
                .unwrap();
        }
        sender
            .send(super::RunningJobEvent::Finished(Ok(super::CommandOutput {
                ok: true,
                rendered: "doctor ok".to_owned(),
                chat_approval: None,
            })))
            .unwrap();

        app.poll_running_job();

        assert!(app.running_job.is_some());
        assert_eq!(
            app.running_job_output
                .iter()
                .filter(|line| line.starts_with("line-"))
                .count(),
            super::MAX_STREAM_EVENTS_PER_POLL
        );
        assert_eq!(app.status, "Streaming output...");

        app.poll_running_job();

        assert!(app.running_job.is_none());
        assert!(app.transcript.iter().any(|line| line == "[Doctor]"));
    }

