    #[test]
    fn failed_streaming_command_keeps_stream_and_failed_status() {
        let mut app = test_app();
        let (sender, receiver) = mpsc::channel();
        app.running_job = Some(super::RunningJob {
            title: "Install".to_owned(),
            kind: super::RunningJobKind::Cli,
            receiver,
            started_at: Instant::now(),
            streamed_lines: 0,
            streamed_stdout_lines: 0,
            streamed_stderr_lines: 0,
        });

        sender
            .send(super::RunningJobEvent::Stream {
                stream: super::CommandOutputStream::Stdout,
                line: "starting install".to_owned(),
            })
            .unwrap();
        sender
            .send(super::RunningJobEvent::Finished(Ok(super::CommandOutput {
                ok: false,
                rendered: "command: rocm install sdk\nstatus: failed (1)\n\nstdout:\nstarting install\n\nstderr:\nbroken".to_owned(),
                chat_approval: None,
            })))
            .unwrap();

        app.poll_running_job();

        assert!(
            app.running_job_output
                .iter()
                .any(|line| line == "starting install")
        );
        assert!(
            app.transcript
                .iter()
                .any(|line| line == "status: failed (1)")
        );
        assert!(!app.transcript.iter().any(|line| line == "stdout:"));
        assert!(app.transcript.iter().any(|line| line == "stderr:"));
        assert!(app.transcript.iter().any(|line| line == "broken"));
        assert_eq!(app.status, "Install command failed.");
        assert!(app.activity_text().contains("failed: Install"));
    }

