    #[test]
    fn serve_wizard_start_recovers_setup_runtime_registry_from_local_manifest() -> anyhow::Result<()>
    {
        let mut app = test_app();
        let runtime_key = "release-pip-gfx120x-all-local-manifest";
        write_test_runtime_with_key(&app.paths, runtime_key, "therock-release:gfx120X-all", 20)?;
        let install_root = app
            .paths
            .data_dir
            .join("runtimes")
            .join("wheel")
            .join(runtime_key);
        app.config.setup.therock_venv = Some(install_root);
        app.config.save(&app.paths)?;
        app.rebase_paths_to_saved_setup_folder();
        let registry_dir = app.paths.data_dir.join("runtimes").join("registry");
        let _ = fs::remove_dir_all(&registry_dir);

        assert!(super::setup_venv_ready(&app.paths, &app.config));
        assert!(super::setup_runtime_ready_for_sidebar(
            &app.paths,
            &app.config
        ));
        assert!(app.handle_command("serve"));
        set_serve_wizard_engine(&mut app, "pytorch");
        move_serve_wizard_to_choice(&mut app, super::ServeWizardChoice::Review);

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(
            registry_dir.join(format!("{runtime_key}.json")).is_file(),
            "status: {}; serve: {}; install: {}; pending: {}",
            app.status,
            app.serve_wizard.is_some(),
            app.install_manager.is_some(),
            app.pending_approval.is_some()
        );
        assert!(app.serve_wizard.is_some());
        assert!(app.pending_approval.is_some());
        assert!(app.install_manager.is_none());
        assert!(app.running_job.is_none());
        assert!(matches!(
            app.pending_approval.as_ref().map(|pending| &pending.action),
            Some(super::ApprovalAction::CliCommand { args, .. })
                if args.windows(2).any(|pair| pair == ["--runtime-id", runtime_key])
        ));
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("ROCm install: release-pip-gfx120x-all-local-manifest"));
        assert!(!rendered.contains("Set up ROCm first"));
        assert!(!rendered.contains("Serve failed"));
        Ok(())
    }

