    #[test]
    fn serve_wizard_local_model_path_and_port_build_approval() -> anyhow::Result<()> {
        let mut app = test_app();
        let model_path = app.paths.data_dir.join("tiny model.gguf");
        fs::create_dir_all(&app.paths.data_dir)?;
        fs::write(&model_path, "gguf")?;
        write_test_runtime_with_key(
            &app.paths,
            "release-pip-gfx120x-all-local-model",
            "therock-release:gfx120X-all",
            20,
        )?;
        assert!(app.handle_command("serve"));

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        move_serve_wizard_to_choice(&mut app, super::ServeWizardChoice::LocalPath);
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.serve_wizard_editing_text());
        app.set_input(model_path.display().to_string());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(!app.serve_wizard_editing_text());
        assert_eq!(
            app.serve_wizard
                .as_ref()
                .map(super::selected_serve_wizard_engine)
                .as_deref(),
            Some("llama.cpp")
        );

        move_serve_wizard_to_choice(&mut app, super::ServeWizardChoice::Port);
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        app.set_input("11436".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        move_serve_wizard_to_choice(&mut app, super::ServeWizardChoice::Review);
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        let actual_args = match app.pending_approval.as_ref().map(|pending| &pending.action) {
            Some(super::ApprovalAction::CliCommand { args, .. }) => args.clone(),
            other => panic!("unexpected pending approval: {other:?}"),
        };
        assert_eq!(
            actual_args,
            vec![
                "serve".to_owned(),
                model_path.display().to_string(),
                "--engine".to_owned(),
                "llama.cpp".to_owned(),
                "--device".to_owned(),
                "gpu_required".to_owned(),
                "--runtime-id".to_owned(),
                "release-pip-gfx120x-all-local-model".to_owned(),
                "--port".to_owned(),
                "11436".to_owned(),
                "--managed".to_owned(),
            ]
        );
        assert!(app.transcript.is_empty());
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("Review:"));
        assert!(rendered.contains("Start local model"));
        assert!(
            app.serve_wizard
                .as_ref()
                .and_then(|state| state.message.as_deref())
                .is_some_and(|message| message.contains(&model_path.display().to_string()))
        );
        let modal = super::render_modal_approval(&app, app.pending_approval.as_ref().unwrap());
        assert!(modal.contains("tiny model.gguf"));
        assert!(modal.contains("Address: http://127.0.0.1:11436"));
        assert!(modal.contains("Start the local model."));
        assert!(modal.contains("First start may download model files"));
        assert!(!rendered.contains("rocm serve"));
        Ok(())
    }

