    #[test]
    fn logs_screen_searches_and_clears_with_arrow_menu() -> anyhow::Result<()> {
        let mut app = test_app();
        let logs_dir = app.paths.data_dir.join("logs");
        fs::create_dir_all(&logs_dir)?;
        fs::write(
            logs_dir.join("cli-lifecycle.log"),
            "1 level=info category=test action=alpha message=alpha ready\n2 level=info category=test action=beta message=beta ready\n",
        )?;
        assert!(app.handle_command("logs"));

        for _ in 0..super::logs_view_actions().len() {
            if app.selected_logs_view_action() == super::LogsViewAction::Search {
                break;
            }
            handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }
        assert_eq!(
            app.selected_logs_view_action(),
            super::LogsViewAction::Search
        );
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        assert!(app.logs_view_editing_text());
        app.set_input("beta".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert!(!app.logs_view_editing_text());
        assert_eq!(
            app.logs_view
                .as_ref()
                .and_then(|state| state.query.as_deref()),
            Some("beta")
        );
        assert!(app.transcript.is_empty());
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("beta ready"));
        assert!(!rendered.contains("alpha ready"));

        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        assert_eq!(
            app.selected_logs_view_action(),
            super::LogsViewAction::ClearSearch
        );
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

        assert_eq!(
            app.logs_view
                .as_ref()
                .and_then(|state| state.query.as_deref()),
            None
        );
        assert!(app.transcript.is_empty());
        let rendered = render_test_terminal(&app, 120, 28);
        assert!(rendered.contains("alpha ready"));
        assert!(rendered.contains("beta ready"));
        Ok(())
    }

