    #[test]
    fn install_driver_approval_helpers_match_cli_plan_semantics() -> anyhow::Result<()> {
        assert_eq!(
            super::approved_install_args(&["driver", "--dkms"]),
            vec!["driver".to_owned(), "--dkms".to_owned(), "--yes".to_owned()]
        );
        assert_eq!(
            super::approved_install_args(&["driver", "--dkms", "--dry-run"]),
            vec![
                "driver".to_owned(),
                "--dkms".to_owned(),
                "--dry-run".to_owned()
            ]
        );
        assert_eq!(
            super::approved_install_args(&["driver", "--dkms", "--preview"]),
            vec![
                "driver".to_owned(),
                "--dkms".to_owned(),
                "--dry-run".to_owned()
            ]
        );
        assert_eq!(
            super::approved_install_args(&["driver", "--dkms", "--yes"]),
            vec!["driver".to_owned(), "--dkms".to_owned(), "--yes".to_owned()]
        );
        assert_eq!(
            super::approved_install_args(&["driver", "--reconcile"]),
            vec!["driver".to_owned(), "--reconcile".to_owned()]
        );
        assert!(!super::install_args_require_approval(&[
            "driver",
            "--dry-run"
        ])?);
        assert!(!super::install_args_require_approval(&[
            "driver",
            "--preview"
        ])?);
        assert!(!super::install_args_require_approval(&["driver"])?);
        assert!(!super::install_args_require_approval(&[
            "driver",
            "--reconcile"
        ])?);
        Ok(())
    }

