    #[test]
    fn update_completion_suggests_apply_and_runtime_keys() -> anyhow::Result<()> {
        let (root, paths) = test_paths("update-completion-runtime");
        write_test_runtime(&paths, "therock-release:gfx120X-all", 1)?;

        let top = super::slash_argument_completion_menu("/update ", &paths, 0)
            .expect("update should complete --apply");
        assert!(top.items.contains(&"--apply".to_owned()));

        let runtime =
            super::slash_argument_completion_menu("/update --apply --runtime ", &paths, 0)
                .expect("update runtime should complete runtime keys");
        assert!(
            runtime
                .items
                .contains(&"therock-release-gfx120X-all".to_owned())
        );
        let options = super::slash_argument_completion_menu(
            "/update --apply --runtime therock-release-gfx120X-all ",
            &paths,
            0,
        )
        .expect("update should complete remaining options");
        assert!(!options.items.contains(&"--apply".to_owned()));
        assert!(!options.items.contains(&"--runtime".to_owned()));
        assert!(options.items.contains(&"--preview".to_owned()));
        assert!(!options.items.contains(&"--dry-run".to_owned()));
        assert!(options.items.contains(&"--activate".to_owned()));
        fs::remove_dir_all(root).ok();
        Ok(())
    }

