    #[test]
    fn typed_approval_commands_select_open_confirmation_without_mutating() -> anyhow::Result<()> {
        for (command, selected, status) in [
            ("approve", 0, "Approve selected. Press Enter to continue."),
            ("reject", 1, "Reject selected. Press Enter to reject."),
            (
                "automations approve",
                0,
                "Approve selected. Press Enter to continue.",
            ),
            (
                "automations reject",
                1,
                "Reject selected. Press Enter to reject.",
            ),
        ] {
            let mut app = test_app();
            app.paths.ensure()?;
            append_test_proposal(&app.paths, "proposal-open-approval")?;
            assert!(app.handle_command("reviews proposal-open-approval"));
            handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));

            assert!(matches!(
                app.pending_approval.as_ref().map(|pending| &pending.action),
                Some(super::ApprovalAction::Proposal { proposal_id })
                    if proposal_id == "proposal-open-approval"
            ));

            assert!(app.handle_command(command), "{command}");

            assert_eq!(
                app.pending_approval
                    .as_ref()
                    .map(|pending| pending.selected),
                Some(selected),
                "{command}"
            );
            assert_eq!(app.status, status, "{command}");
            assert_eq!(
                find_automation_proposal(&app.paths, "proposal-open-approval")?.status,
                "pending",
                "{command}"
            );
            assert!(app.running_job.is_none(), "{command}");
            assert!(app.transcript.is_empty(), "{command}");
        }
        Ok(())
    }

