    #[test]
    fn automations_prefetch_review_fields_are_arrow_key_editable() -> anyhow::Result<()> {
        let mut app = test_app();
        app.paths.ensure()?;
        append_test_prefetch_proposal(&app.paths, "proposal-prefetch-ui")?;
        assert!(app.handle_command("automations"));

        let rendered = render_test_terminal(&app, 120, 32);
        assert!(rendered.contains("Allow download"));
        assert!(rendered.contains("Max download"));
        assert!(rendered.contains("Hugging Face"));

        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        handle_key(&mut app, key_event(KeyCode::Right, KeyModifiers::NONE));
        let proposal = find_automation_proposal(&app.paths, "proposal-prefetch-ui")?;
        assert_eq!(
            proposal
                .arguments
                .get("allow_artifact_download")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert!(app.pending_approval.is_none());

        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        handle_key(&mut app, key_event(KeyCode::Right, KeyModifiers::NONE));
        let proposal = find_automation_proposal(&app.paths, "proposal-prefetch-ui")?;
        assert_eq!(
            proposal
                .arguments
                .get("artifact_max_bytes")
                .and_then(Value::as_u64),
            Some(1_073_741_824)
        );

        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        app.set_input("2048".to_owned());
        handle_key(&mut app, key_event(KeyCode::Enter, KeyModifiers::NONE));
        let proposal = find_automation_proposal(&app.paths, "proposal-prefetch-ui")?;
        assert_eq!(
            proposal
                .arguments
                .get("artifact_max_bytes")
                .and_then(Value::as_u64),
            Some(2048)
        );

        handle_key(&mut app, key_event(KeyCode::Down, KeyModifiers::NONE));
        handle_key(&mut app, key_event(KeyCode::Right, KeyModifiers::NONE));
        let proposal = find_automation_proposal(&app.paths, "proposal-prefetch-ui")?;
        assert_eq!(
            proposal
                .arguments
                .get("allow_huggingface_download")
                .and_then(Value::as_bool),
            Some(true)
        );
        assert!(app.pending_approval.is_none());
        assert!(app.transcript.is_empty());
        Ok(())
    }

