    #[test]
    fn typed_prefetch_edit_highlights_editable_rows_without_mutating() -> anyhow::Result<()> {
        let mut app = test_app();
        app.paths.ensure()?;
        let mut proposal = test_proposal("proposal-prefetch-edit");
        proposal.watcher_id = "cache-warm".to_owned();
        proposal.action = "queue_prefetch_proposal".to_owned();
        proposal.tool = Some("prefetch_artifact".to_owned());
        proposal.service_id = None;
        proposal.arguments = serde_json::json!({
            "artifact_ref": "Qwen/Test-1B#hf-main",
        });
        rocm_core::append_automation_proposal(&app.paths, &proposal)?;

        assert!(app.handle_command("automations edit proposal-prefetch-edit allow-download yes"));
        assert!(matches!(
            app.selected_automation_prefetch_field(),
            Some((proposal, super::AutomationPrefetchField::AllowDownload))
                if proposal.proposal_id == "proposal-prefetch-edit"
        ));
        assert!(app.transcript.is_empty());
        assert!(
            app.automations_manager
                .as_ref()
                .and_then(|state| state.message.as_deref())
                .is_some_and(|message| message.contains("Nothing changed yet"))
        );

        assert!(
            app.handle_command("automations edit proposal-prefetch-edit artifact-max-bytes 1024")
        );
        assert!(matches!(
            app.selected_automation_prefetch_field(),
            Some((proposal, super::AutomationPrefetchField::MaxBytes))
                if proposal.proposal_id == "proposal-prefetch-edit"
        ));

        assert!(app.handle_command(
            "automations edit proposal-prefetch-edit allow-huggingface-download yes"
        ));
        assert!(matches!(
            app.selected_automation_prefetch_field(),
            Some((proposal, super::AutomationPrefetchField::AllowHuggingFace))
                if proposal.proposal_id == "proposal-prefetch-edit"
        ));

        let proposal = find_automation_proposal(&app.paths, "proposal-prefetch-edit")?;
        assert_eq!(
            proposal
                .arguments
                .get("artifact_ref")
                .and_then(Value::as_str),
            Some("Qwen/Test-1B#hf-main")
        );
        assert_eq!(
            proposal
                .arguments
                .get("allow_artifact_download")
                .and_then(Value::as_bool),
            None
        );
        assert_eq!(
            proposal
                .arguments
                .get("artifact_max_bytes")
                .and_then(Value::as_u64),
            None
        );
        assert_eq!(
            proposal
                .arguments
                .get("allow_huggingface_download")
                .and_then(Value::as_bool),
            None
        );
        assert!(app.pending_approval.is_none());
        assert!(app.transcript.is_empty());
        Ok(())
    }

