    fn submit_prompt_command(app: &mut App, command: &str) {
        app.input = command.to_owned();
        app.input_cursor = app.input.len();
        app.submit();
    }

    fn move_serve_wizard_to_choice(app: &mut App, choice: super::ServeWizardChoice) {
        for _ in 0..=super::serve_wizard_choices().len() {
            if app.selected_serve_wizard_choice() == choice {
                return;
            }
            handle_key(app, key_event(KeyCode::Down, KeyModifiers::NONE));
        }
        panic!("serve wizard choice {choice:?} was not reachable");
    }

    fn set_serve_wizard_engine(app: &mut App, engine: &str) {
        let engines = super::serve_wizard_engine_names();
        let index = engines
            .iter()
            .position(|candidate| candidate == engine)
            .unwrap_or_else(|| panic!("{engine} engine option"));
        app.serve_wizard
            .as_mut()
            .expect("serve wizard")
            .engine_index = index;
    }

    fn open_hidden_doctor_refresh_from_prompt(app: &mut App) {
        submit_prompt_command(app, "/doctor");
        assert!(matches!(
            app.running_job.as_ref().map(|job| &job.kind),
            Some(super::RunningJobKind::DoctorRefresh)
        ));

        handle_key(app, key_event(KeyCode::Esc, KeyModifiers::NONE));

        assert!(app.doctor_manager.is_none());
        assert!(matches!(
            app.running_job.as_ref().map(|job| &job.kind),
            Some(super::RunningJobKind::DoctorRefresh)
        ));
        assert!(app.transcript.is_empty());
    }

    fn spawn_fake_local_chat_server(
        content: &'static str,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_for_model(content, super::VALIDATED_LOCAL_ASSISTANT_MODEL)
    }

    fn spawn_fake_local_chat_server_for_model(
        content: &'static str,
        model_id: &'static str,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_repeated_for_model(content, 1, model_id)
    }

    fn spawn_fake_local_chat_server_repeated(
        content: &'static str,
        response_count: usize,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_repeated_for_model(
            content,
            response_count,
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
        )
    }

    fn spawn_fake_local_chat_server_repeated_for_model(
        content: &'static str,
        response_count: usize,
        model_id: &'static str,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_with_response_repeated(
            serde_json::json!({
                "choices": [{
                    "message": {
                        "role": "assistant",
                        "content": content
                    }
                }]
            }),
            response_count,
            model_id,
        )
    }

    fn spawn_fake_local_chat_server_with_response(
        response: Value,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_with_response_for_model(
            response,
            super::VALIDATED_LOCAL_ASSISTANT_MODEL,
        )
    }

    fn spawn_fake_local_chat_server_with_response_for_model(
        response: Value,
        model_id: &'static str,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        spawn_fake_local_chat_server_with_response_repeated(response, 1, model_id)
    }

    fn spawn_fake_local_chat_server_with_response_repeated(
        response: Value,
        response_count: usize,
        model_id: &'static str,
    ) -> anyhow::Result<(u16, mpsc::Receiver<Value>)> {
        let listener = TcpListener::bind("127.0.0.1:0")?;
        let port = listener.local_addr()?.port();
        let (sender, receiver) = mpsc::channel();
        std::thread::spawn(move || {
            let mut served_chat_responses = 0;
            while served_chat_responses < response_count.max(1) {
                let Ok((mut stream, _)) = listener.accept() else {
                    return;
                };
                let _ = stream.set_read_timeout(Some(Duration::from_secs(5)));
                let mut request = Vec::new();
                let mut buffer = [0_u8; 512];
                let header_end = loop {
                    let Ok(read) = stream.read(&mut buffer) else {
                        return;
                    };
                    if read == 0 {
                        return;
                    }
                    request.extend_from_slice(&buffer[..read]);
                    if let Some(index) = request.windows(4).position(|window| window == b"\r\n\r\n")
                    {
                        break index + 4;
                    }
                };
                let headers = String::from_utf8_lossy(&request[..header_end]);
                let request_line = headers.lines().next().unwrap_or_default();
                if request_line.starts_with("GET /v1/models ") {
                    let response = serde_json::json!({ "data": [{ "id": model_id }] }).to_string();
                    let header = format!(
                        "HTTP/1.1 200 OK\r\ncontent-type: application/json\r\ncontent-length: {}\r\n\r\n",
                        response.len()
                    );
                    let _ = stream.write_all(header.as_bytes());
                    let _ = stream.write_all(response.as_bytes());
                    continue;
                }
                let content_length = headers
                    .lines()
                    .find_map(|line| {
                        let (name, value) = line.split_once(':')?;
                        name.eq_ignore_ascii_case("content-length")
                            .then(|| value.trim().parse::<usize>().ok())
                            .flatten()
                    })
                    .unwrap_or(0);
                while request.len().saturating_sub(header_end) < content_length {
                    let Ok(read) = stream.read(&mut buffer) else {
                        return;
                    };
                    if read == 0 {
                        return;
                    }
                    request.extend_from_slice(&buffer[..read]);
                }
                let body = &request[header_end..header_end + content_length];
                let request_value = serde_json::from_slice::<Value>(body).ok();
                if let Some(value) = request_value.as_ref() {
                    let _ = sender.send(value.clone());
                };
                served_chat_responses += 1;
                if request_value
                    .as_ref()
                    .and_then(|value| value.get("stream"))
                    .and_then(Value::as_bool)
                    .unwrap_or(false)
                {
                    let content = response
                        .get("choices")
                        .and_then(Value::as_array)
                        .and_then(|choices| choices.first())
                        .and_then(|choice| choice.get("message"))
                        .and_then(|message| message.get("content"))
                        .and_then(Value::as_str)
                        .unwrap_or_default();
                    let chunk = serde_json::json!({
                        "choices": [{
                            "delta": {
                                "content": content
                            }
                        }]
                    });
                    let response_body = format!("data: {chunk}\n\ndata: [DONE]\n\n");
                    let header = format!(
                        "HTTP/1.1 200 OK\r\ncontent-type: text/event-stream\r\ncontent-length: {}\r\n\r\n",
                        response_body.len()
                    );
                    let _ = stream.write_all(header.as_bytes());
                    let _ = stream.write_all(response_body.as_bytes());
                } else {
                    let response = response.to_string();
                    let header = format!(
                        "HTTP/1.1 200 OK\r\ncontent-type: application/json\r\ncontent-length: {}\r\n\r\n",
                        response.len()
                    );
                    let _ = stream.write_all(header.as_bytes());
                    let _ = stream.write_all(response.as_bytes());
                }
            }
        });
        Ok((port, receiver))
    }

    fn poll_app_until_idle(app: &mut App) {
        for _ in 0..500 {
            app.poll_running_job();
            if app.running_job.is_none() {
                return;
            }
            std::thread::sleep(Duration::from_millis(10));
        }
        app.poll_running_job();
    }

    fn attach_running_job(
        app: &mut App,
        title: &str,
        kind: super::RunningJobKind,
    ) -> mpsc::Sender<super::RunningJobEvent> {
        let (sender, receiver) = mpsc::channel();
        app.running_job = Some(super::RunningJob {
            title: title.to_owned(),
            kind,
            receiver,
            started_at: Instant::now(),
            streamed_lines: 0,
            streamed_stdout_lines: 0,
            streamed_stderr_lines: 0,
        });
        app.running_job_log_scroll = 0;
        app.running_job_output.clear();
        sender
    }

    fn finish_running_job(
        app: &mut App,
        sender: mpsc::Sender<super::RunningJobEvent>,
        rendered: &str,
    ) {
        sender
            .send(super::RunningJobEvent::Finished(Ok(super::CommandOutput {
                ok: true,
                rendered: rendered.to_owned(),
                chat_approval: None,
            })))
            .expect("test should send running job completion");
        app.poll_running_job();
        assert!(app.running_job.is_none());
    }

    fn assert_no_background_doctor_block(app: &App, command: &str) {
        assert!(
            !app.status.contains("already running")
                && !app.status.contains("still running. Wait for it to finish"),
            "{command} should not be blocked by a hidden Doctor refresh: {}",
            app.status
        );
        assert!(
            app.running_job
                .as_ref()
                .map(|job| !matches!(job.kind, super::RunningJobKind::DoctorRefresh))
                .unwrap_or(true),
            "{command} should discard hidden Doctor refresh before continuing"
        );
        assert!(
            app.transcript.is_empty(),
            "{command} should remain a navigable screen, not a transcript dump"
        );
    }

    fn active_tui_surface_count(app: &App) -> usize {
        if app.overlay_card.is_some() {
            return 1;
        }
        [
            app.doctor_manager.is_some(),
            app.logs_view.is_some(),
            app.runtime_manager.is_some(),
            app.install_manager.is_some(),
            app.engine_manager.is_some(),
            app.model_picker.is_some(),
            app.serve_wizard.is_some(),
            app.update_manager.is_some(),
            app.automations_manager.is_some(),
            app.provider_manager.is_some(),
            app.config_manager.is_some(),
            app.services_manager.is_some(),
            app.command_screen.is_some(),
            app.onboarding_active,
            app.should_draw_home_dashboard(),
        ]
        .into_iter()
        .filter(|active| *active)
        .count()
    }

    #[derive(Debug, PartialEq, Eq)]
    struct SurfaceSelection {
        surface: &'static str,
        selected: usize,
        row_count: usize,
    }

    fn active_surface_selection(app: &App) -> Option<SurfaceSelection> {
        if let Some(pending) = app.pending_approval.as_ref() {
            return Some(SurfaceSelection {
                surface: "approval",
                selected: pending.selected,
                row_count: 2,
            });
        }
        if let Some(state) = app.overlay_card.as_ref() {
            return Some(SurfaceSelection {
                surface: "overlay",
                selected: state.selected,
                row_count: state.actions.len(),
            });
        }
        if let Some(state) = app.doctor_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "doctor",
                selected: state.selected,
                row_count: super::doctor_manager_choices().len(),
            });
        }
        if let Some(state) = app.logs_view.as_ref() {
            return Some(SurfaceSelection {
                surface: "logs",
                selected: state.selected,
                row_count: super::logs_view_actions().len(),
            });
        }
        if let Some(state) = app.runtime_manager.as_ref() {
            let (selected, row_count) = match &state.screen {
                super::RuntimeManagerScreen::List => {
                    (state.selected, super::runtime_manager_choice_count(state))
                }
                super::RuntimeManagerScreen::Advanced { selected } => {
                    (*selected, super::runtime_advanced_choices().len())
                }
                super::RuntimeManagerScreen::ImportManifest { selected, .. } => {
                    (*selected, super::runtime_import_choices().len())
                }
                super::RuntimeManagerScreen::AdoptExisting { selected, .. } => {
                    (*selected, super::runtime_adopt_choices().len())
                }
            };
            return Some(SurfaceSelection {
                surface: "runtimes",
                selected,
                row_count,
            });
        }
        if let Some(state) = app.install_manager.as_ref() {
            let (selected, row_count) = match &state.screen {
                super::InstallManagerScreen::Main => {
                    (state.selected, super::install_menu_choices().len())
                }
                super::InstallManagerScreen::Sdk { selected, .. } => {
                    (*selected, super::install_sdk_choices().len())
                }
            };
            return Some(SurfaceSelection {
                surface: "install",
                selected,
                row_count,
            });
        }
        if let Some(state) = app.engine_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "engine",
                selected: state.selected,
                row_count: super::engine_manager_choice_count(state),
            });
        }
        if let Some(state) = app.model_picker.as_ref() {
            return Some(SurfaceSelection {
                surface: "model",
                selected: state.selected,
                row_count: state.items.len(),
            });
        }
        if let Some(state) = app.serve_wizard.as_ref() {
            return Some(SurfaceSelection {
                surface: "serve",
                selected: state.selected,
                row_count: super::serve_wizard_choices().len(),
            });
        }
        if let Some(state) = app.update_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "update",
                selected: state.selected,
                row_count: super::update_menu_choices().len(),
            });
        }
        if let Some(state) = app.automations_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "automations",
                selected: state.selected,
                row_count: state.rows.len(),
            });
        }
        if let Some(state) = app.provider_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "provider",
                selected: state.selected,
                row_count: super::provider_options().len(),
            });
        }
        if let Some(state) = app.config_manager.as_ref() {
            let (selected, row_count) = match &state.screen {
                super::ConfigManagerScreen::Main => {
                    (state.selected, super::config_menu_choices().len())
                }
                super::ConfigManagerScreen::Provider {
                    selected,
                    confirming_clear,
                    ..
                } => (
                    *selected,
                    super::config_provider_choices(*confirming_clear).len(),
                ),
            };
            return Some(SurfaceSelection {
                surface: "config",
                selected,
                row_count,
            });
        }
        if let Some(state) = app.services_manager.as_ref() {
            return Some(SurfaceSelection {
                surface: "services",
                selected: state.selected,
                row_count: super::services_manager_choice_count(state),
            });
        }
        if let Some(state) = app.command_screen.as_ref() {
            return Some(SurfaceSelection {
                surface: "command",
                selected: state.selected,
                row_count: state.actions.len(),
            });
        }
        if app.onboarding_active {
            return Some(SurfaceSelection {
                surface: "setup",
                selected: app.onboarding_selection,
                row_count: app.onboarding_choice_count(),
            });
        }
        if app.should_draw_home_dashboard() {
            return Some(SurfaceSelection {
                surface: "home",
                selected: app.home_selection,
                row_count: super::home_dashboard_actions(app).len(),
            });
        }
        None
    }

